# T14: Per-token domain attribution
@dataclass
class TokenAttribution:
    """Per-token domain weight attribution for multi-domain resolution."""
    token: str
    stem: str
    domain_weights: Dict[str, float]   # domain → weight (0.0-1.0)
    source_patterns: list              # pattern_ids that contributed
    is_implementation: bool = False     # True if token signals impl domain (gui, import, class)
    is_subject: bool = False           # True if token signals subject domain (species, snake)

    @property
    def primary_domain(self) -> str:
        if not self.domain_weights:
            return 'general'
        return max(self.domain_weights, key=self.domain_weights.get)

    @property
    def ambiguous(self) -> bool:
        vals = sorted(self.domain_weights.values(), reverse=True)
        return len(vals) >= 2 and (vals[0] - vals[1]) < 0.2

# T16: Per-turn diagnostic metrics mapped to delta metric framework
@dataclass
class TurnMetrics:
    """Per-turn diagnostic metrics mapped to delta metric framework.

    Dimensions map to SR format: SR:hΔ x cΔ y rΔ z dΔ w | E a D b C c | G g
    Our system's internal values are different from the abstract metric framework
    but serve equivalent diagnostic purposes.
    """
    turn: int
    # Raw values
    entropy: float       # h — domain ambiguity (0=certain, 1=max ambiguity)
    coherence: float     # c — response token coherence with known patterns
    resonance: float     # r — alpha EMA alignment of activated patterns
    drift: float         # d — domain shift magnitude from previous turn
    evidence: float      # E — composite grade score (EBI equivalent)
    domain_risk: float   # D — gap severity weighted by ambiguity (DR equivalent)
    self_assess: float   # C — structural self-assessment (CB equivalent)
    gate: str            # G — "G", "Y", or "R"
    # Deltas from previous turn
    h_delta: float = 0.0
    c_delta: float = 0.0
    r_delta: float = 0.0
    d_delta: float = 0.0

    @property
    def sr_line(self) -> str:
        """SR format: hΔ cΔ rΔ dΔ | E D C | G"""
        return (f"SR:hΔ {self.h_delta:+.2f} cΔ {self.c_delta:+.2f} "
                f"rΔ {self.r_delta:+.2f} dΔ {self.d_delta:+.2f} | "
                f"E {self.evidence:.2f} D {self.domain_risk:.2f} "
                f"C {self.self_assess:.2f} | G={self.gate}")

    @property
    def token_line(self) -> str:
        """Orchestrator-style compact token output."""
        return (f"[COH: {self.coherence:.0%}] [RES: {self.resonance:.0%}] "
                f"[ENT: {self.entropy:.2f}] [DRF: {self.drift:.2f}] "
                f"[EVI: {self.evidence:.2f}] [GATE: {self.gate}]")

    def to_dict(self) -> dict:
        return {
            'turn': self.turn, 'entropy': self.entropy, 'coherence': self.coherence,
            'resonance': self.resonance, 'drift': self.drift, 'evidence': self.evidence,
            'domain_risk': self.domain_risk, 'self_assess': self.self_assess,
            'gate': self.gate, 'h_delta': self.h_delta, 'c_delta': self.c_delta,
            'r_delta': self.r_delta, 'd_delta': self.d_delta,
        }

# T14: Implementation vs subject domain layer separation
class DomainLayerClassifier:
    """Classify tokens into implementation vs subject domain layers.

    Implementation domain = what language/framework/tools to use (programming, gui, web).
    Subject domain = what the content is about (zoology, physics, history).
    """

    # Tokens that signal implementation context (how to build it)
    IMPL_SIGNALS = frozenset({
        'import', 'class', 'def', 'function', 'gui', 'tkinter', 'flask',
        'django', 'api', 'database', 'sql', 'build', 'compile', 'deploy',
        'test', 'debug', 'code', 'script', 'module', 'package', 'library',
        'framework', 'install', 'pip', 'npm', 'run', 'execute', 'program',
        'app', 'application', 'software', 'develop', 'implement', 'backend',
        'frontend', 'server', 'client', 'endpoint', 'route', 'template',
    })

    # Domains that are typically implementation domains
    IMPL_DOMAINS = frozenset({
        'programming', 'gui', 'web', 'database', 'network', 'devops',
        'testing', 'build', 'packaging', 'python', 'regex', 'os', 'io', 'file',
    })

    @classmethod
    def classify(cls, attributions: list) -> dict:
        """Classify token attributions into implementation and subject domain layers.

        Returns: {implementation_domain, subject_domain, impl_confidence,
                  subj_confidence, impl_scores, subj_scores}
        """
        impl_scores = {}
        subj_scores = {}
        for attr in attributions:
            for dom, weight in attr.domain_weights.items():
                if attr.is_implementation or dom in cls.IMPL_DOMAINS:
                    impl_scores[dom] = impl_scores.get(dom, 0.0) + weight
                else:
                    subj_scores[dom] = subj_scores.get(dom, 0.0) + weight
                # Dual-signal tokens contribute to both (reduced weight for subject)
                if attr.is_implementation and attr.is_subject:
                    subj_scores[dom] = subj_scores.get(dom, 0.0) + weight * 0.5

        impl_domain = max(impl_scores, key=impl_scores.get) if impl_scores else 'general'
        subj_domain = max(subj_scores, key=subj_scores.get) if subj_scores else 'general'
        impl_total = sum(impl_scores.values()) or 1.0
        subj_total = sum(subj_scores.values()) or 1.0

        return {
            'implementation_domain': impl_domain,
            'subject_domain': subj_domain,
            'impl_confidence': round(impl_scores.get(impl_domain, 0.0) / impl_total, 3),
            'subj_confidence': round(subj_scores.get(subj_domain, 0.0) / subj_total, 3),
            'impl_scores': impl_scores,
            'subj_scores': subj_scores,
        }

@dataclass
class Pattern:
    """Unique, hashable representation of a code behaviour pattern."""
    pattern_id: str                # SHA256 of content + context
    pattern_type: PatternType
    context_hash: str             # Hash of file, class, function, line range
    content_hash: str             # Hash of the code/condition itself
    outcome: str                  # 'success', 'failure', 'fix'
    metadata: Dict[str, Any] = field(default_factory=dict)
    first_seen: str = field(default_factory=lambda: datetime.datetime.now().isoformat())
    last_seen: str = field(default_factory=lambda: datetime.datetime.now().isoformat())
    occurrence_count: int = 1

    def to_dict(self):
        d = asdict(self)
        d['pattern_type'] = self.pattern_type.name
        return d

class PatternDatabase:
    """Persistent storage and retrieval of learned patterns."""
    def __init__(self, db_path: Path = Path("pymanifest_patterns.json")):
        self.db_path = db_path
        self.patterns: Dict[str, Pattern] = {}
        self.load()

    def load(self):
        if self.db_path.exists():
            try:
                with open(self.db_path, 'r') as f:
                    data = json.load(f)
                for pid, pdata in data.items():
                    pdata['pattern_type'] = PatternType[pdata['pattern_type']]
                    self.patterns[pid] = Pattern(**pdata)
                logger.info(f"Loaded {len(self.patterns)} patterns from {self.db_path}")
            except Exception as e:
                logger.warning(f"Failed to load pattern database: {e}")

    def save(self):
        try:
            with open(self.db_path, 'w') as f:
                json.dump({pid: p.to_dict() for pid, p in self.patterns.items()},
                          f, indent=2)
            logger.info(f"Saved {len(self.patterns)} patterns to {self.db_path}")
        except Exception as e:
            logger.error(f"Failed to save pattern database: {e}")

    def add_or_update(self, pattern: Pattern):
        if pattern.pattern_id in self.patterns:
            existing = self.patterns[pattern.pattern_id]
            existing.last_seen = datetime.datetime.now().isoformat()
            existing.occurrence_count += 1
            existing.metadata.update(pattern.metadata)
        else:
            self.patterns[pattern.pattern_id] = pattern

    def get_patterns_by_type(self, pattern_type: PatternType) -> List[Pattern]:
        """Return all patterns of a given type."""
        return [p for p in self.patterns.values() if p.pattern_type == pattern_type]

    def find_similar(self, context_hash: str, pattern_type: Optional[PatternType] = None) -> List[Pattern]:
        results = []
        for p in self.patterns.values():
            if p.context_hash == context_hash:
                if pattern_type is None or p.pattern_type == pattern_type:
                    results.append(p)
        # Sort by occurrence_count × tier_weight (TIER_PRECEDENCE tiebreaker)
        return sorted(results,
                      key=lambda p: p.occurrence_count * TIER_PRECEDENCE.get(
                          getattr(p, 'source_tier', 'alpha'), 1.0),
                      reverse=True)

    def compute_context_hash(self, file_path: str, class_name: Optional[str] = None,
                             function_name: Optional[str] = None, line: int = 0) -> str:
        """Hash of the static context (file + class + function)."""
        context = f"{file_path}:{class_name or ''}:{function_name or ''}:{line//10*10}"  # coarse line bucket
        return hashlib.sha256(context.encode()).hexdigest()[:16]

# Singleton pattern database (lazy init)
_pattern_db_instance = None

def get_pattern_db() -> PatternDatabase:
    global _pattern_db_instance
    if _pattern_db_instance is None:
        _pattern_db_instance = PatternDatabase()
    return _pattern_db_instance

