def _infer_module_domain(module_name: str) -> str:
    """Infer domain for a module using MODULE_DOMAIN_MAP with prefix fallback."""
    if module_name in MODULE_DOMAIN_MAP:
        return MODULE_DOMAIN_MAP[module_name]
    # Try prefix match (e.g. 'tkinter.constants' → 'tkinter' → 'gui')
    parts = module_name.split('.')
    for i in range(len(parts), 0, -1):
        prefix = '.'.join(parts[:i])
        if prefix in MODULE_DOMAIN_MAP:
            return MODULE_DOMAIN_MAP[prefix]
    return 'unknown'

