@dataclass
class RuntimeEvent:
    event_type: RuntimeEventType
    timestamp: str
    file_path: str
    line: int
    function: Optional[str] = None
    class_name: Optional[str] = None
    exception_type: Optional[str] = None
    exception_value: Optional[str] = None
    traceback: Optional[str] = None
    module: Optional[str] = None
    # GUI specific
    widget_type: Optional[str] = None
    widget_id: Optional[str] = None
    geometry: Optional[Dict] = None

    @classmethod
    def from_dict(cls, d: Dict) -> 'RuntimeEvent':
        if isinstance(d.get('event_type'), str):
            try:
                d['event_type'] = RuntimeEventType(d['event_type'])
            except ValueError:
                # Fallback if names were stored instead of values
                for et in RuntimeEventType:
                    if et.name.lower() == d['event_type'].lower():
                        d['event_type'] = et
                        break
        return cls(**d)

def reconstruct_events(event_list: List[Dict]) -> List[RuntimeEvent]:
    return [RuntimeEvent.from_dict(e) for e in event_list]

