class DictionaryPatternIngester:
    """Selective ingestion of Webster's dictionary terms relevant to code domains."""

    # Curated programming-relevant terms
    RELEVANT_TERMS = {
        'abstract', 'algorithm', 'allocate', 'array', 'assert', 'attribute',
        'binary', 'block', 'boolean', 'buffer', 'cache', 'callback', 'cascade',
        'channel', 'class', 'closure', 'cluster', 'compile', 'component',
        'compose', 'compress', 'concurrent', 'configure', 'connect', 'constant',
        'constructor', 'context', 'control', 'convert', 'coordinate', 'corrupt',
        'daemon', 'data', 'debug', 'declare', 'decode', 'default', 'delegate',
        'dependency', 'deploy', 'deprecated', 'descriptor', 'deserialize',
        'dispatch', 'domain', 'driver', 'dynamic', 'element', 'emit', 'encode',
        'encrypt', 'engine', 'entity', 'enumerate', 'environment', 'error',
        'evaluate', 'event', 'exception', 'execute', 'export', 'expression',
        'extend', 'extract', 'factory', 'filter', 'format', 'fragment',
        'framework', 'function', 'garbage', 'generate', 'generic', 'global',
        'graph', 'handle', 'hash', 'heap', 'hierarchy', 'hook', 'host',
        'identity', 'implement', 'import', 'index', 'inherit', 'initialize',
        'inject', 'input', 'instance', 'integrate', 'interface', 'internal',
        'interpolate', 'invoke', 'isolate', 'iterate', 'kernel', 'lambda',
        'layer', 'library', 'link', 'literal', 'local', 'lock', 'logic',
        'manifest', 'map', 'marshal', 'matrix', 'memory', 'merge', 'method',
        'migrate', 'module', 'monitor', 'mount', 'mutex', 'namespace', 'native',
        'navigate', 'nest', 'network', 'node', 'normalize', 'object', 'offset',
        'operator', 'optimize', 'output', 'overflow', 'override', 'package',
        'parameter', 'parse', 'partition', 'patch', 'path', 'pattern',
        'pipeline', 'platform', 'pointer', 'policy', 'poll', 'pool', 'port',
        'predicate', 'priority', 'process', 'profile', 'protocol', 'proxy',
        'publish', 'query', 'queue', 'raise', 'recursive', 'reduce', 'reference',
        'reflect', 'register', 'render', 'repository', 'request', 'resolve',
        'resource', 'response', 'restore', 'route', 'runtime', 'sandbox',
        'scaffold', 'schedule', 'schema', 'scope', 'script', 'seed',
        'serialize', 'session', 'signal', 'singleton', 'socket', 'spawn',
        'stack', 'state', 'static', 'stream', 'string', 'struct', 'subscribe',
        'symbol', 'synchronize', 'syntax', 'target', 'template', 'terminal',
        'thread', 'threshold', 'timeout', 'token', 'trace', 'transaction',
        'transform', 'traverse', 'trigger', 'tuple', 'type', 'validate',
        'variable', 'vector', 'verify', 'version', 'virtual', 'volatile',
        'widget', 'wrapper', 'yield',
    }

    def __init__(self, dict_path: Path, db: PatternDatabase):
        self.dict_path = dict_path
        self.db = db

    def ingest_filtered(self, max_terms: int = 2000, func_names: set = None) -> int:
        """Ingest programming-relevant dictionary terms. Returns count ingested."""
        if not self.dict_path.exists():
            logger.warning(f"Dictionary not found: {self.dict_path}")
            return 0
        try:
            with open(self.dict_path, 'r', encoding='utf-8') as f:
                dictionary = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load dictionary: {e}")
            return 0

        count = 0
        # Build match set: curated terms + terms that appear as function name parts
        match_terms = set(self.RELEVANT_TERMS)
        if func_names:
            # Extract word parts from function names (split on _ )
            for fn in func_names:
                for part in fn.lower().replace('_', ' ').split():
                    if len(part) >= 4:  # skip very short parts
                        match_terms.add(part)

        for term, definition in dictionary.items():
            if count >= max_terms:
                break
            term_lower = term.lower().strip()
            if term_lower not in match_terms:
                continue
            # Truncate definition to 200 chars
            defn = str(definition)[:200] if definition else ''
            content_hash = hashlib.sha256(f"{term_lower}:{defn}".encode()).hexdigest()[:16]
            context_hash = hashlib.sha256(f"dict:{term_lower}".encode()).hexdigest()[:16]
            pattern_id = hashlib.sha256(f"{context_hash}{content_hash}DICT".encode()).hexdigest()[:16]
            pattern = Pattern(
                pattern_id=pattern_id,
                pattern_type=PatternType.DICTIONARY_TERM,
                context_hash=context_hash,
                content_hash=content_hash,
                outcome="cataloged",
                metadata={'term': term_lower, 'definition': defn, 'source': 'webster',
                          'domain': 'general'}
            )
            self.db.add_or_update(pattern)
            count += 1

        logger.info(f"Ingested {count} dictionary terms (from {len(dictionary)} total)")
        return count

    def ingest_module_domains(self, pm_files: dict) -> int:
        """Scan py_manifest file imports and record MODULE_DOMAIN patterns."""
        count = 0
        seen_modules = set()
        for fpath, meta in pm_files.items():
            for imp in meta if isinstance(meta, list) else (meta.get('imports', []) if isinstance(meta, dict) else []):
                imp_dict = imp if isinstance(imp, dict) else {}
                module = imp_dict.get('module', '')
                if not module or module in seen_modules:
                    continue
                domain = _infer_module_domain(module)
                if domain == 'unknown':
                    continue
                seen_modules.add(module)
                content_hash = hashlib.sha256(f"{module}:{domain}".encode()).hexdigest()[:16]
                context_hash = hashlib.sha256(f"module_domain:{module}".encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}MOD".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.MODULE_DOMAIN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={'module': module, 'domain': domain, 'source_file': fpath}
                )
                self.db.add_or_update(pattern)
                count += 1
        logger.info(f"Ingested {count} module domain mappings")
        return count

    def ingest_full(self, max_terms: int = 0) -> int:
        """Ingest ALL dictionary terms (not filtered). For NL generation vocabulary.

        Args:
            max_terms: Limit ingestion count. 0 = no limit.
        Returns: count ingested.
        """
        if not self.dict_path.exists():
            logger.warning(f"Dictionary not found: {self.dict_path}")
            return 0
        try:
            with open(self.dict_path, 'r', encoding='utf-8') as f:
                dictionary = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load dictionary: {e}")
            return 0

        count = 0
        for term, definition in dictionary.items():
            if max_terms > 0 and count >= max_terms:
                break
            term_lower = term.lower().strip()
            if not term_lower or len(term_lower) < 2:
                continue
            defn = str(definition)[:200] if definition else ''
            if not defn:
                continue
            content_hash = hashlib.sha256(f"{term_lower}:{defn}".encode()).hexdigest()[:16]
            context_hash = hashlib.sha256(f"dict:{term_lower}".encode()).hexdigest()[:16]
            pattern_id = hashlib.sha256(f"{context_hash}{content_hash}DICT".encode()).hexdigest()[:16]
            pattern = Pattern(
                pattern_id=pattern_id,
                pattern_type=PatternType.DICTIONARY_TERM,
                context_hash=context_hash,
                content_hash=content_hash,
                outcome="cataloged",
                metadata={'term': term_lower, 'definition': defn, 'source': 'webster',
                          'domain': 'general'}
            )
            self.db.add_or_update(pattern)
            count += 1

        logger.info(f"Full dictionary ingestion: {count} terms (from {len(dictionary)} total)")
        return count


class SpeechPatternIngester:
    """Ingest speech patterns from Morph speech_pattern_store, master_regex, and domain files."""

    def __init__(self, db: PatternDatabase):
        self.db = db

    def ingest_speech_store(self, store_path: Path) -> int:
        """Ingest alpha speech patterns from speech_pattern_store.json."""
        if not store_path.exists():
            logger.warning(f"Speech pattern store not found: {store_path}")
            return 0
        try:
            with open(store_path) as f:
                data = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load speech store: {e}")
            return 0

        patterns = data.get('patterns', {})
        count = 0
        for sha, pdata in patterns.items():
            label = pdata.get('label', '')
            examples = pdata.get('example_texts', [])
            sig = pdata.get('structural_signature', {})

            # Record each example as a speech pattern
            for text in examples:
                context_hash = hashlib.sha256(f"speech:{label}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(text.encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="alpha",
                    metadata={
                        'text': text, 'label': label, 'domain': 'general',
                        'structural_signature': sig, 'source': 'speech_store',
                        'promotion_score': pdata.get('promotion_score', 0),
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        logger.info(f"Ingested {count} speech patterns from store")
        return count

    def ingest_master_regex(self, regex_path: Path) -> int:
        """Ingest master_regex.json pattern definitions as SPEECH_PATTERNs."""
        if not regex_path.exists():
            logger.warning(f"Master regex not found: {regex_path}")
            return 0
        try:
            with open(regex_path) as f:
                data = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load master regex: {e}")
            return 0

        count = 0
        for category, patterns in data.items():
            if not isinstance(patterns, dict):
                continue
            # Determine domain from category name
            if 'domain_' in category:
                domain = category.replace('domain_', '')
            elif 'level_' in category:
                domain = 'linguistic'
            elif 'entities_' in category:
                domain = 'entities'
            else:
                domain = 'general'

            for name, regex_str in patterns.items():
                if not isinstance(regex_str, str):
                    continue
                context_hash = hashlib.sha256(f"regex:{category}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(f"{name}:{regex_str}".encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={
                        'text': regex_str, 'label': name, 'domain': domain,
                        'category': category, 'source': 'master_regex',
                        'is_regex': True,
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        logger.info(f"Ingested {count} regex patterns from master_regex")
        return count

    def ingest_domain_files(self, domains_dir: Path) -> int:
        """Ingest domain-specific patterns from regex/domains/ directory."""
        if not domains_dir.exists():
            logger.warning(f"Domains directory not found: {domains_dir}")
            return 0

        count = 0
        for txt_file in sorted(domains_dir.rglob("*.txt")):
            domain = txt_file.parent.name
            # If the parent is a subdomain (e.g., biology under academic), use grandparent
            if domain in ('biology', 'chemistry', 'statistics', 'discourse',
                          'lexical', 'syntax', 'commissive', 'directive',
                          'expressive', 'informative'):
                subdomain = domain
                domain = txt_file.parent.parent.name
            else:
                subdomain = domain

            try:
                lines = txt_file.read_text(encoding='utf-8').strip().split('\n')
            except Exception:
                continue

            for line in lines:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                context_hash = hashlib.sha256(f"domain:{domain}:{subdomain}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(line.encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={
                        'text': line[:500], 'label': subdomain,
                        'domain': domain, 'source': 'domain_file',
                        'file': txt_file.name, 'is_regex': True,
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        logger.info(f"Ingested {count} domain patterns from {domains_dir}")
        return count

    def ingest_taxonomy(self, taxonomy_path: Path) -> int:
        """Ingest universal_taxonomy.json as hierarchical SPEECH_PATTERNs."""
        if not taxonomy_path.exists():
            logger.warning(f"Taxonomy not found: {taxonomy_path}")
            return 0
        try:
            with open(taxonomy_path) as f:
                data = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load taxonomy: {e}")
            return 0

        count = 0
        for section_name, section in data.items():
            if not isinstance(section, dict) or section_name in ('taxonomy_name', 'version', 'description'):
                continue
            for key, description in section.items():
                if not isinstance(description, str):
                    continue
                context_hash = hashlib.sha256(f"taxonomy:{section_name}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(f"{key}:{description}".encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={
                        'text': description[:500], 'label': key,
                        'domain': section_name, 'source': 'taxonomy',
                        'hierarchy_level': section_name, 'parent_category': 'taxonomy',
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        logger.info(f"Ingested {count} taxonomy patterns")
        return count

    def ingest_academia(self, academia_path: Path) -> int:
        """Ingest academia.json taxonomy patterns + synergetic hooks."""
        if not academia_path.exists():
            logger.warning(f"Academia not found: {academia_path}")
            return 0
        try:
            with open(academia_path) as f:
                data = json.load(f)
        except Exception as e:
            logger.error(f"Failed to load academia: {e}")
            return 0

        count = 0
        # Academic taxonomy: methodology/evidence/hypothesis/validation
        taxonomy = data.get('academic_taxonomy', {})
        for category, subcats in taxonomy.items():
            if not isinstance(subcats, dict):
                continue
            for subcat, regex_str in subcats.items():
                if not isinstance(regex_str, str):
                    continue
                context_hash = hashlib.sha256(f"academia:{category}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(f"{subcat}:{regex_str}".encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={
                        'text': regex_str[:500], 'label': subcat,
                        'domain': 'academic', 'source': 'academia',
                        'hierarchy_level': category, 'parent_category': 'academic_taxonomy',
                        'is_regex': True,
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        # Synergetic hooks (example speech patterns)
        for hook_text in data.get('synergetic_hooks', []):
            context_hash = hashlib.sha256("academia:hooks".encode()).hexdigest()[:16]
            content_hash = hashlib.sha256(hook_text.encode()).hexdigest()[:16]
            pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
            pattern = Pattern(
                pattern_id=pattern_id,
                pattern_type=PatternType.SPEECH_PATTERN,
                context_hash=context_hash,
                content_hash=content_hash,
                outcome="alpha",
                metadata={
                    'text': hook_text, 'label': 'academic_hook',
                    'domain': 'academic', 'source': 'academia',
                    'hierarchy_level': 'synergetic', 'parent_category': 'academic_taxonomy',
                }
            )
            self.db.add_or_update(pattern)
            count += 1

        logger.info(f"Ingested {count} academia patterns")
        return count

    def ingest_entity_catalogs(self, entities_dir: Path) -> int:
        """Ingest entity extraction patterns (temporal, numerical)."""
        if not entities_dir.exists():
            logger.warning(f"Entities directory not found: {entities_dir}")
            return 0

        count = 0
        for txt_file in sorted(entities_dir.rglob("*.txt")):
            entity_type = txt_file.parent.name  # temporal, numerical
            try:
                lines = txt_file.read_text(encoding='utf-8').strip().split('\n')
            except Exception:
                continue
            for line in lines:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                context_hash = hashlib.sha256(f"entity:{entity_type}".encode()).hexdigest()[:16]
                content_hash = hashlib.sha256(line.encode()).hexdigest()[:16]
                pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                pattern = Pattern(
                    pattern_id=pattern_id,
                    pattern_type=PatternType.SPEECH_PATTERN,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="cataloged",
                    metadata={
                        'text': line[:500], 'label': entity_type,
                        'domain': 'entities', 'source': 'entity_catalog',
                        'hierarchy_level': entity_type, 'parent_category': 'extraction_entities',
                        'is_regex': True,
                    }
                )
                self.db.add_or_update(pattern)
                count += 1

        logger.info(f"Ingested {count} entity patterns from {entities_dir}")
        return count

    def ingest_level_catalogs(self, regex_project_dir: Path) -> int:
        """Ingest level-based linguistic hierarchy patterns (level_1 through level_7)."""
        count = 0
        for level_dir in sorted(regex_project_dir.glob("level_*")):
            if not level_dir.is_dir():
                continue
            level_name = level_dir.name  # e.g., level_1_graphology

            for txt_file in sorted(level_dir.rglob("*.txt")):
                # Determine subcategory from file/parent
                if txt_file.parent == level_dir:
                    subdomain = level_name
                else:
                    subdomain = txt_file.parent.name

                try:
                    lines = txt_file.read_text(encoding='utf-8').strip().split('\n')
                except Exception:
                    continue

                for line in lines:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    context_hash = hashlib.sha256(f"level:{level_name}:{subdomain}".encode()).hexdigest()[:16]
                    content_hash = hashlib.sha256(line.encode()).hexdigest()[:16]
                    pattern_id = hashlib.sha256(f"{context_hash}{content_hash}SPEECH".encode()).hexdigest()[:16]
                    pattern = Pattern(
                        pattern_id=pattern_id,
                        pattern_type=PatternType.SPEECH_PATTERN,
                        context_hash=context_hash,
                        content_hash=content_hash,
                        outcome="cataloged",
                        metadata={
                            'text': line[:500], 'label': subdomain,
                            'domain': 'linguistic', 'source': 'level_catalog',
                            'hierarchy_level': level_name, 'parent_category': 'core_hierarchy',
                            'is_regex': True,
                        }
                    )
                    self.db.add_or_update(pattern)
                    count += 1

        logger.info(f"Ingested {count} level catalog patterns")
        return count

