# PART 17A-2: MARKDOWN KNOWLEDGE INGESTER (T12)
# ======================================================================

class MarkdownIngester:
    """Ingest structured knowledge from markdown files into pattern DB.

    Parses section hierarchy, code blocks, bullet explanations, and function
    signatures. Stores as KNOWLEDGE_ENTRY (sections), DICTIONARY_TERM (bullets),
    VERB_FUNCTION_MAP (signatures), and CODE_PATTERN (code blocks).

    All ingested patterns are learnable and tunable — they participate in
    generate_speech() scoring and omega grading like any other pattern.
    """

    # Regexes for markdown structure
    RE_ATX_HEADER = re.compile(r'^(#{1,4})\s+(.+)$', re.MULTILINE)
    RE_SETEXT_HEADER = re.compile(r'^(.+)\n([=-]{3,})$', re.MULTILINE)
    RE_CODE_BLOCK = re.compile(r'```(\w*)\n(.*?)```', re.DOTALL)
    RE_BULLET = re.compile(r'^\*\s+\*\*(.+?)\*\*[:\s]*(.*)$', re.MULTILINE)
    RE_HASH_BULLET = re.compile(r'^#+\s+(.+)$', re.MULTILINE)
    RE_FUNC_CALL = re.compile(r'(\w+(?:\.\w+)*)\s*\(', re.MULTILINE)
    RE_IMPORT = re.compile(r'^(?:from|import)\s+(\S+)', re.MULTILINE)
    RE_ASSIGNMENT = re.compile(r'^(\w+)\s*=\s*(\w+(?:\.\w+)*)\s*\(', re.MULTILINE)

    def __init__(self, db: PatternDatabase):
        self.db = db

    def ingest_file(self, md_path: Path, domain: str = 'python') -> dict:
        """Parse markdown file and store all extracted patterns.

        Returns dict with ingestion statistics:
        {sections, code_blocks, bullets, signatures, knowledge_entries, total}
        """
        try:
            text = md_path.read_text(encoding='utf-8')
        except Exception as e:
            logger.error(f"Failed to read markdown file {md_path}: {e}")
            return {'error': str(e), 'total': 0}

        stats = {
            'file': str(md_path.name),
            'domain': domain,
            'sections': 0,
            'code_blocks': 0,
            'bullets': 0,
            'signatures': 0,
            'knowledge_entries': 0,
            'dictionary_terms': 0,
            'verb_maps': 0,
            'total': 0,
        }

        sections = self._parse_sections(text)
        stats['sections'] = len(sections)

        for section in sections:
            # Store section as KNOWLEDGE_ENTRY
            ke_count = self._store_section_as_knowledge(section, domain)
            stats['knowledge_entries'] += ke_count

            # Extract and store code blocks
            code_blocks = self._extract_code_blocks(section.get('content', ''))
            for cb in code_blocks:
                cp_count = self._store_code_as_pattern(cb, section['title'], domain)
                stats['code_blocks'] += 1
                stats['verb_maps'] += cp_count

                # Extract signatures from code
                sigs = self._extract_signatures(cb['code'])
                for sig in sigs:
                    self._store_signature(sig, section['title'], domain)
                    stats['signatures'] += 1

            # Extract and store bullet explanations
            bullets = self._extract_bullet_knowledge(section.get('content', ''))
            for bullet in bullets:
                self._store_bullet_as_term(bullet, section['title'], domain)
                stats['bullets'] += 1
                stats['dictionary_terms'] += 1

        stats['total'] = (stats['knowledge_entries'] + stats['dictionary_terms'] +
                          stats['verb_maps'] + stats['signatures'])

        logger.info(f"Markdown ingestion from {md_path.name}: {stats['total']} patterns "
                    f"({stats['sections']} sections, {stats['code_blocks']} code blocks, "
                    f"{stats['bullets']} bullets, {stats['signatures']} signatures)")
        return stats

    def _parse_sections(self, text: str) -> list:
        """Split markdown into sections with hierarchy.

        Returns list of {level: int, title: str, content: str, parent: str}.
        """
        sections = []
        # Find all header positions
        headers = []

        # ATX headers (# Title)
        for m in self.RE_ATX_HEADER.finditer(text):
            level = len(m.group(1))
            title = m.group(2).strip().rstrip('#').strip()
            headers.append((m.start(), level, title))

        # Setext headers (Title\n=== or Title\n---)
        for m in self.RE_SETEXT_HEADER.finditer(text):
            title = m.group(1).strip()
            level = 1 if m.group(2)[0] == '=' else 2
            headers.append((m.start(), level, title))

        # Sort by position
        headers.sort(key=lambda x: x[0])

        # Extract content between headers
        parent_stack = ['']  # track parent section titles
        for i, (pos, level, title) in enumerate(headers):
            # Content runs from end of this header line to start of next header
            header_end = text.index('\n', pos) + 1 if '\n' in text[pos:] else len(text)
            if i + 1 < len(headers):
                next_start = headers[i + 1][0]
            else:
                next_start = len(text)
            content = text[header_end:next_start].strip()

            # Track parent hierarchy
            while len(parent_stack) > level:
                parent_stack.pop()
            parent = parent_stack[-1] if parent_stack else ''
            parent_stack.append(title)

            sections.append({
                'level': level,
                'title': title,
                'content': content,
                'parent': parent,
            })

        # If no headers found, treat entire text as one section
        if not sections:
            sections.append({
                'level': 1,
                'title': 'Document',
                'content': text.strip(),
                'parent': '',
            })

        return sections

    def _extract_code_blocks(self, content: str) -> list:
        """Extract ```language ... ``` code blocks.

        Returns list of {language: str, code: str}.
        """
        blocks = []
        for m in self.RE_CODE_BLOCK.finditer(content):
            lang = m.group(1) or 'python'
            code = m.group(2).strip()
            if code:
                blocks.append({'language': lang, 'code': code})
        return blocks

    def _extract_signatures(self, code: str) -> list:
        """Extract function calls and assignments from code block.

        Returns list of {name: str, type: 'call'|'import'|'assignment', full: str}.
        """
        sigs = []
        seen = set()

        # Imports
        for m in self.RE_IMPORT.finditer(code):
            name = m.group(1)
            if name not in seen:
                sigs.append({'name': name, 'type': 'import', 'full': m.group(0)})
                seen.add(name)

        # Assignments: x = func(...)
        for m in self.RE_ASSIGNMENT.finditer(code):
            var_name = m.group(1)
            func_name = m.group(2)
            key = f"{var_name}={func_name}"
            if key not in seen:
                sigs.append({'name': func_name, 'type': 'assignment',
                             'full': m.group(0), 'var': var_name})
                seen.add(key)

        # Function calls: func(...) — skip common builtins already captured
        for m in self.RE_FUNC_CALL.finditer(code):
            name = m.group(1)
            if name not in seen and name not in ('if', 'for', 'while', 'with',
                                                   'return', 'yield', 'print',
                                                   'True', 'False', 'None'):
                sigs.append({'name': name, 'type': 'call', 'full': m.group(0)})
                seen.add(name)

        return sigs

    def _extract_bullet_knowledge(self, content: str) -> list:
        """Extract * **term** explanation bullets.

        Returns list of {term: str, explanation: str}.
        """
        bullets = []
        for m in self.RE_BULLET.finditer(content):
            term = m.group(1).strip()
            explanation = m.group(2).strip().rstrip('.')
            if term and len(term) < 200:
                bullets.append({'term': term, 'explanation': explanation})
        return bullets

    def _store_section_as_knowledge(self, section: dict, domain: str) -> int:
        """Store a markdown section as KNOWLEDGE_ENTRY pattern.

        Returns count of patterns stored (1 for section, possibly more for
        subsections with code examples).
        """
        title = section['title']
        content = section['content']
        if not content or len(content) < 10:
            return 0

        context_hash = hashlib.sha256(
            f"knowledge:{domain}:{section.get('parent', '')}".encode()
        ).hexdigest()[:16]
        content_hash = hashlib.sha256(
            f"{title}:{content[:500]}".encode()
        ).hexdigest()[:16]
        pattern_id = hashlib.sha256(
            f"{context_hash}{content_hash}KNOWLEDGE".encode()
        ).hexdigest()[:16]

        # Extract a code example if present
        code_blocks = self._extract_code_blocks(content)
        code_example = code_blocks[0]['code'][:300] if code_blocks else ''

        # Build a concise summary from first non-empty line
        summary_lines = [l.strip() for l in content.split('\n')
                         if l.strip() and not l.strip().startswith('```')]
        summary = summary_lines[0][:200] if summary_lines else title

        pattern = Pattern(
            pattern_id=pattern_id,
            pattern_type=PatternType.KNOWLEDGE_ENTRY,
            context_hash=context_hash,
            content_hash=content_hash,
            outcome="cataloged",
            metadata={
                'title': title,
                'section': section.get('parent', '') or title,
                'domain': domain,
                'summary': summary,
                'code_example': code_example,
                'level': section.get('level', 1),
                'content_length': len(content),
                'has_code': bool(code_blocks),
                'source': 'markdown',
            }
        )
        self.db.add_or_update(pattern)
        return 1

    def _store_code_as_pattern(self, code_block: dict, section_title: str,
                                domain: str) -> int:
        """Store code block. Extract function signatures as VERB_FUNCTION_MAP.

        Returns count of verb maps stored.
        """
        code = code_block['code']
        lang = code_block['language']

        # Store signatures found in this code block as VERB_FUNCTION_MAP
        sigs = self._extract_signatures(code)
        count = 0
        for sig in sigs:
            if sig['type'] in ('call', 'assignment'):
                self._store_signature(sig, section_title, domain)
                count += 1

        return count

    def _store_signature(self, sig: dict, section_title: str, domain: str):
        """Store a function signature as VERB_FUNCTION_MAP pattern."""
        name = sig['name']
        context_hash = hashlib.sha256(
            f"mdsig:{domain}:{section_title}".encode()
        ).hexdigest()[:16]
        content_hash = hashlib.sha256(
            f"{name}:{sig.get('full', '')}".encode()
        ).hexdigest()[:16]
        pattern_id = hashlib.sha256(
            f"{context_hash}{content_hash}VERB".encode()
        ).hexdigest()[:16]

        # Infer verb category from function name
        verb_category = 'action'
        name_lower = name.split('.')[-1].lower()
        if name_lower.startswith(('get', 'read', 'load', 'fetch', 'find')):
            verb_category = 'retrieve'
        elif name_lower.startswith(('set', 'write', 'save', 'store', 'put')):
            verb_category = 'store'
        elif name_lower.startswith(('create', 'make', 'new', 'build', 'init')):
            verb_category = 'create'
        elif name_lower.startswith(('delete', 'remove', 'drop', 'clear')):
            verb_category = 'destroy'
        elif name_lower.startswith(('update', 'modify', 'change', 'edit')):
            verb_category = 'modify'
        elif name_lower.startswith(('check', 'is_', 'has_', 'test', 'verify')):
            verb_category = 'check'
        elif name_lower.startswith(('convert', 'transform', 'to_', 'parse')):
            verb_category = 'transform'

        pattern = Pattern(
            pattern_id=pattern_id,
            pattern_type=PatternType.VERB_FUNCTION_MAP,
            context_hash=context_hash,
            content_hash=content_hash,
            outcome="cataloged",
            metadata={
                'name': name,
                'qualname': name,
                'args': sig.get('full', ''),
                'returns': sig.get('var', ''),
                'verb_category': verb_category,
                'section': section_title,
                'domain': domain,
                'source': 'markdown',
                'sig_type': sig.get('type', 'call'),
            }
        )
        self.db.add_or_update(pattern)

    def _store_bullet_as_term(self, bullet: dict, section_title: str,
                               domain: str):
        """Store bullet explanation as DICTIONARY_TERM with source='markdown'."""
        term = bullet['term']
        explanation = bullet['explanation']

        context_hash = hashlib.sha256(
            f"mdterm:{domain}:{section_title}".encode()
        ).hexdigest()[:16]
        content_hash = hashlib.sha256(
            f"{term}:{explanation[:200]}".encode()
        ).hexdigest()[:16]
        pattern_id = hashlib.sha256(
            f"{context_hash}{content_hash}DICT".encode()
        ).hexdigest()[:16]

        pattern = Pattern(
            pattern_id=pattern_id,
            pattern_type=PatternType.DICTIONARY_TERM,
            context_hash=context_hash,
            content_hash=content_hash,
            outcome="cataloged",
            metadata={
                'term': term.lower(),
                'definition': explanation or f"Python concept from {section_title}",
                'source': 'markdown',
                'section': section_title,
                'domain': domain,
            }
        )
        self.db.add_or_update(pattern)

    def ingest_txt(self, filepath: str, domain: str = "general",
                   chunk_size: int = 500) -> dict:
        """Ingest a plain-text file into pattern DB as KNOWLEDGE_ENTRY patterns.

        Splits by paragraph (double-newline), then by chunk_size characters.
        Returns {chunks, ingested}.
        """
        text = Path(filepath).read_text(encoding="utf-8", errors="replace")
        paragraphs = [p.strip() for p in text.split("\n\n") if p.strip()]
        ingested = 0
        for para in paragraphs:
            for i in range(0, len(para), chunk_size):
                chunk = para[i:i + chunk_size].strip()
                if len(chunk) < 20:
                    continue
                content_hash = hashlib.sha256(chunk.encode()).hexdigest()[:16]
                context = f"txt:{Path(filepath).stem}:{domain}"
                context_hash = hashlib.sha256(context.encode()).hexdigest()[:16]
                pid = hashlib.sha256(
                    (context_hash + content_hash + "KNOWLEDGE_ENTRY").encode()
                ).hexdigest()[:16]
                pat = Pattern(
                    pattern_id=pid,
                    pattern_type=PatternType.KNOWLEDGE_ENTRY,
                    context_hash=context_hash,
                    content_hash=content_hash,
                    outcome="ingested",
                    metadata={"source": str(filepath), "domain": domain,
                              "chunk_idx": i // chunk_size, "kind": "txt"}
                )
                self.db.add_or_update(pat)
                ingested += 1
        return {"chunks": len(paragraphs), "ingested": ingested}

    def ingest_stl(self, filepath: str) -> dict:
        """Ingest STL file geometry metadata as MEASUREMENT_PATTERN.

        Parses binary STL (80-byte header + uint32 count + 50 bytes/triangle).
        Falls back to ASCII STL line counting.
        Returns {triangles, surface_area_est, ingested}.
        """
        import struct
        path = Path(filepath)
        triangles = 0
        bbox = {"x": [0, 0], "y": [0, 0], "z": [0, 0]}
        raw = path.read_bytes()

        if raw[:5] != b"solid" or len(raw) > 80:
            # Binary STL
            try:
                triangles = struct.unpack_from("<I", raw, 80)[0]
                verts = []
                for i in range(min(triangles, 500)):
                    off = 84 + i * 50 + 12  # skip normal (12 bytes)
                    for v in range(3):
                        x, y, z = struct.unpack_from("<fff", raw, off + v * 12)
                        verts.append((x, y, z))
                if verts:
                    bbox = {
                        "x": [min(v[0] for v in verts), max(v[0] for v in verts)],
                        "y": [min(v[1] for v in verts), max(v[1] for v in verts)],
                        "z": [min(v[2] for v in verts), max(v[2] for v in verts)],
                    }
            except Exception:
                pass
        else:
            # ASCII STL — count "facet" occurrences
            triangles = raw.decode("utf-8", errors="replace").count("facet normal")

        surface_area_est = triangles * 0.5
        stem = path.stem
        content = f"stl:{stem}:tris={triangles}:bbox={bbox}"
        content_hash = hashlib.sha256(content.encode()).hexdigest()[:16]
        context = f"geometry:{stem}"
        context_hash = hashlib.sha256(context.encode()).hexdigest()[:16]
        pid = hashlib.sha256(
            (context_hash + content_hash + "MEASUREMENT_PATTERN").encode()
        ).hexdigest()[:16]
        pat = Pattern(
            pattern_id=pid,
            pattern_type=PatternType.MEASUREMENT_PATTERN,
            context_hash=context_hash,
            content_hash=content_hash,
            outcome="ingested",
            metadata={"subtype": "stl_geometry", "file": str(path),
                      "triangles": triangles, "bbox": bbox,
                      "surface_area_est": surface_area_est}
        )
        self.db.add_or_update(pat)
        return {"triangles": triangles, "surface_area_est": surface_area_est, "ingested": 1}

    def ingest_plan_docs(self, directory: str) -> dict:
        """Recursively ingest all .md files in directory via ingest_file()."""
        root = Path(directory)
        stats = {"files": 0, "total_ingested": 0}
        for md_path in sorted(root.rglob("*.md")):
            try:
                result = self.ingest_file(md_path, domain='planning')
                stats["files"] += 1
                stats["total_ingested"] += result.get("total", 0)
            except Exception as e:
                print(f"[ingest_plan_docs] skip {md_path.name}: {e}")
        return stats

    def ingest_sha_context(self, filepath: str) -> dict:
        """Ingest SHA→name index as SCRIPT_INGEST patterns (variant genealogy context).

        Works with variant_sha_index.json or any {sha: name} dict.
        """
        data = json.loads(Path(filepath).read_text())
        ingested = 0
        for sha, name in data.items():
            content = f"sha:{sha}:variant:{name}"
            content_hash = hashlib.sha256(content.encode()).hexdigest()[:16]
            context_hash = hashlib.sha256(
                f"sha_context:{name}".encode()
            ).hexdigest()[:16]
            pid = hashlib.sha256(
                (context_hash + content_hash + "SCRIPT_INGEST").encode()
            ).hexdigest()[:16]
            pat = Pattern(
                pattern_id=pid,
                pattern_type=PatternType.SCRIPT_INGEST,
                context_hash=context_hash, content_hash=content_hash,
                outcome="cataloged",
                metadata={"sha": sha, "variant_name": name,
                          "kind": "sha_context", "source": str(filepath)}
            )
            self.db.add_or_update(pat)
            ingested += 1
        return {"ingested": ingested}


# ======================================================================
# PART 17B: DOMAIN RESOLVER
# ======================================================================

class DomainResolver:
    """Resolve domain classification for files and functions from stored patterns."""

    def __init__(self, db: PatternDatabase):
        self.db = db
        self._module_domain_cache = {}  # module → domain
        self._build_module_cache()

    def _build_module_cache(self):
        """Pre-build module→domain lookup from MODULE_DOMAIN patterns."""
        for p in self.db.patterns.values():
            if p.pattern_type == PatternType.MODULE_DOMAIN:
                mod = p.metadata.get('module', '')
                dom = p.metadata.get('domain', 'unknown')
                if mod:
                    self._module_domain_cache[mod] = dom

    def resolve_file_domain(self, file_path: str, imports: list = None) -> str:
        """Determine primary domain of a file from its import patterns."""
        if not imports:
            return 'unknown'
        domain_votes = {}
        for imp in imports:
            mod = imp if isinstance(imp, str) else imp.get('module', '')
            domain = self._module_domain_cache.get(mod)
            if not domain:
                domain = _infer_module_domain(mod)
            if domain and domain != 'unknown':
                domain_votes[domain] = domain_votes.get(domain, 0) + 1
        if not domain_votes:
            return 'unknown'
        return max(domain_votes, key=domain_votes.get)

    def resolve_function_domain(self, func_name: str, file_domain: str = 'unknown') -> str:
        """Determine domain from VERB_FUNCTION_MAP patterns or file domain fallback."""
        # Search for matching verb patterns
        for p in self.db.patterns.values():
            if p.pattern_type == PatternType.VERB_FUNCTION_MAP:
                if p.metadata.get('name') == func_name:
                    # Found exact match — infer from file domain of the pattern
                    return file_domain if file_domain != 'unknown' else 'unknown'
        return file_domain

# ======================================================================
# PART 17: LOGICAL ITERATION ENGINE
# ======================================================================

class LogicalIterationEngine:
    """
    Implements variable workflows: try fixes in order of confidence/pattern match,
    revert if unsuccessful, and retry with alternative fixes.
    """
    def __init__(self, static: Manifest, runtime: RuntimeManifest, pattern_db: PatternDatabase):
        self.static = static
        self.runtime = runtime
        self.pattern_db = pattern_db
        self.iteration_log = []

    def iterate_fixes(self, fixes: List[Dict], max_attempts: int = 5) -> Dict[str, Any]:
        """
        Attempt fixes in priority order; if a fix fails (causes new error),
        revert and try next.
        """
        # Sort fixes by confidence descending, then by pattern match score
        fixes = sorted(fixes, key=lambda f: f.get('confidence', 0), reverse=True)

        applied = []
        for fix in fixes[:max_attempts]:
            # Check if similar fix succeeded before in this context
            pattern_hint = self._match_pattern(fix)
            if pattern_hint:
                logger.info(f"Pattern suggests fix: {fix['suggestion']} (confidence boosted)")
                fix['confidence'] = min(1.0, fix.get('confidence', 0) + 0.2)

            logger.info(f"Attempting fix: {fix['suggestion']}")
            # Simulate fix application (in real implementation, would actually modify code)
            # Here we record the attempt.
            attempt = {
                'fix': fix,
                'timestamp': datetime.datetime.now().isoformat(),
                'status': 'attempted'
            }
            # For demonstration, we assume success if confidence > 0.7
            success = fix.get('confidence', 0) > 0.7
            if success:
                attempt['status'] = 'success'
                applied.append(fix)
            else:
                attempt['status'] = 'failed'
                # Revert would happen here
            self.iteration_log.append(attempt)
            if success:
                # Record successful pattern
                self._record_successful_fix(fix)
                break

        return {
            'applied_fixes': applied,
            'iteration_log': self.iteration_log,
            'total_attempts': len(self.iteration_log),
            'success': len(applied) > 0
        }

    def _match_pattern(self, fix: Dict) -> bool:
        """Check if a similar fix succeeded before in similar context."""
        # Simplified: return True if there's a pattern with same fix type and outcome success
        context_hash = self.pattern_db.compute_context_hash(fix.get('file', ''), line=fix.get('line', 0))
        for pat in self.pattern_db.find_similar(context_hash):
            if pat.pattern_type == PatternType.FIX_APPLIED and pat.outcome == 'success':
                if pat.metadata.get('fix', {}).get('type') == fix.get('type'):
                    return True
        return False

    def _record_successful_fix(self, fix: Dict):
        """Store successful fix in pattern DB."""
        engine = PatternLearningEngine(self.static, self.runtime)
        engine.record_fix_applied(fix, success=True)
        engine.save()

# ======================================================================
# PART 17.5: NEURAL PATTERN ENGINE (Neural Debugger)
# ======================================================================

# Matrix-based weight attribution constants
FEATURE_NAMES = ['total_events', 'exceptions', 'calls', 'imports',
                  'covered_lines', 'suspicious_paths', 'crash_points', 'static_complexity']
OUTCOME_NAMES = ['success', 'error_rate', 'coverage_rate']
N_FEATURES = 8
N_OUTCOMES = 3

# Semantic feature constants (parallel to runtime features, same outcome space)
SEMANTIC_FEATURE_NAMES = [
    'domain_technical', 'domain_academic', 'domain_informal',
    'understanding_pct', 'priority_pct', 'gap_severity_numeric',
    'recognized_ratio', 'pattern_match_count'
]
N_SEMANTIC_FEATURES = 8

class NeuralPatternEngine:
    """
    Learns complexity weights from execution history using BPNN logic.
    Serializes weights per epoch and logs SHA256 of training data subsets.
    """
    def __init__(self, weights_path: Path = Path("pymanifest_weights.json")):
        self.weights_path = weights_path
        self.weights = {}  # version -> {weights, data_sha, timestamp}
        self.current_weights = None
        self.semantic_weights = None  # 8×3 semantic feature matrix (parallel to runtime)
        self.load_weights()

    def load_weights(self):
        if self.weights_path.exists():
            try:
                with open(self.weights_path, 'r') as f:
                    self.weights = json.load(f)
                if self.weights:
                    latest_v = sorted(self.weights.keys())[-1]
                    data = self.weights[latest_v]['data']
                    # Backward compatibility: if flat list (len 10 or 12), reinit as matrix
                    if isinstance(data, list) and len(data) > 0 and not isinstance(data[0], list):
                        logger.warning(f"Detected old flat-vector format (len={len(data)}). Reinitializing as matrix.")
                        self.current_weights = None
                    else:
                        self.current_weights = data
                logger.info(f"Loaded {len(self.weights)} weight versions from {self.weights_path}")
                # Load latest semantic weights if present
                semantic_versions = sorted([k for k in self.weights if k.startswith('semantic_')])
                if semantic_versions:
                    self.semantic_weights = self.weights[semantic_versions[-1]].get('data')
            except Exception as e:
                logger.warning(f"Failed to load weights: {e}")

    def save_weights(self, data_sha: str):
        version = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        self.weights[version] = {
            "timestamp": datetime.datetime.now().isoformat(),
            "data_sha": data_sha,
            "shape": [N_FEATURES, N_OUTCOMES],
            "feature_names": FEATURE_NAMES,
            "outcome_names": OUTCOME_NAMES,
            "data": self.current_weights
        }
        try:
            with open(self.weights_path, 'w') as f:
                json.dump(self.weights, f, indent=2)
            logger.info(f"Serialized weight version {version} (Data SHA: {data_sha[:8]}), shape={[N_FEATURES, N_OUTCOMES]}")
        except Exception as e:
            logger.error(f"Failed to save weights: {e}")

    def runtime_to_vector(self, runtime: RuntimeManifest, graph_data: Optional[Dict] = None,
                          static_manifest: Optional[Any] = None) -> Tuple[List[float], List[float]]:
        """
        Convert runtime manifest + graph topology + static manifest into feature and outcome vectors.
        Returns: (features, outcomes) where:
          - features: 8-element vector [total_events, exceptions, calls, imports, covered_lines, suspicious_paths, crash_points, static_complexity]
          - outcomes: 3-element vector [success, error_rate, coverage_rate]
        """
        if not runtime:
            return [0.0] * N_FEATURES, [0.0] * N_OUTCOMES

        # Base features from runtime
        total_events = runtime.summary.get('total_events', 1)
        exceptions = runtime.summary.get('exceptions', 0)
        calls = runtime.summary.get('calls', 0)
        imports = runtime.summary.get('imports', 0)
        covered_lines = runtime.summary.get('covered_lines', 0)

        # Graph features (Architecture Scrutiny)
        nodes_count = len(graph_data.get('suspicious_paths', {})) if graph_data else 0
        crash_points = len(graph_data.get('crash_points', [])) if graph_data else 0

        # Static complexity feature
        static_complexity = 0.5
        if static_manifest and hasattr(static_manifest, 'summary'):
            total_funcs = static_manifest.summary.get('total_functions', 1)
            total_complexity = 0
            for fm in static_manifest.files.values():
                total_complexity += sum(f.complexity for f in fm.functions)
            # Normalize: avg complexity per function, scaled to [0,1]
            static_complexity = min(1.0, (total_complexity / max(total_funcs, 1)) / 20.0)

        # Build 8-element feature vector
        features = [
            min(1.0, total_events / 1000.0),          # total_events
            min(1.0, exceptions / 10.0),               # exceptions
            min(1.0, calls / 500.0),                   # calls
            min(1.0, imports / 100.0),                 # imports
            min(1.0, covered_lines / 1000.0),          # covered_lines
            min(1.0, nodes_count / 100.0),             # suspicious_paths
            min(1.0, crash_points / 5.0),              # crash_points
            static_complexity                          # static_complexity
        ]

        # Build 3-element outcome vector
        success = 1.0 if runtime.exit_code == 0 else 0.0
        error_rate = min(1.0, exceptions / max(total_events, 1))
        coverage_rate = min(1.0, covered_lines / max(total_events, 1))
        outcomes = [success, error_rate, coverage_rate]

        return features, outcomes

    def train_step(self, runtime: RuntimeManifest, graph_data: Optional[Dict] = None,
                   static_manifest: Optional[Any] = None):
        """
        Perform a single 'epoch' of matrix-based learning from the current run.
        Updates W[feature_idx][outcome_idx] matrix using delta rule.
        """
        features, outcomes = self.runtime_to_vector(runtime, graph_data, static_manifest)

        # Create SHA from both features and outcomes
        data_dict = {'features': features, 'outcomes': outcomes}
        data_json = json.dumps(data_dict, sort_keys=True)
        data_sha = hashlib.sha256(data_json.encode()).hexdigest()

        # Include Graph SHA in versioning if available
        if graph_data and 'graph_sha' in graph_data:
            data_sha = f"{data_sha[:32]}{graph_data['graph_sha'][:32]}"

        # Initialize matrix: [N_FEATURES][N_OUTCOMES]
        if self.current_weights is None:
            self.current_weights = [[0.1] * N_OUTCOMES for _ in range(N_FEATURES)]

        # Matrix-based weight update: delta rule for each cell
        lr = 0.05
        for i in range(N_FEATURES):
            for j in range(N_OUTCOMES):
                pred = features[i] * self.current_weights[i][j]
                error = outcomes[j] - pred
                self.current_weights[i][j] += lr * error * features[i]

        self.save_weights(data_sha)

    def get_overall_pattern_sha(self, runtime: RuntimeManifest) -> str:
        """Create a single SHA representing 'everything we saw' in this run."""
        summary_str = json.dumps(runtime.summary, sort_keys=True)
        coverage_str = json.dumps(runtime.coverage, sort_keys=True)
        # Combine with exit code and script path
        combined = f"{runtime.script_path}:{runtime.exit_code}:{summary_str}:{coverage_str}"
        return hashlib.sha256(combined.encode()).hexdigest()

    def train_from_associations(self, associations: Dict[str, float],
                                outcomes: List[float]) -> Dict[str, Any]:
        """Train semantic weights from domain classification scores.

        Args:
            associations: Dict with keys from SEMANTIC_FEATURE_NAMES → float values
            outcomes: 3-element [success, error_rate, coverage_rate]

        Returns: dict with data_sha, deltas, new weights summary
        """
        # Build 8-element semantic feature vector from associations
        features = []
        for fname in SEMANTIC_FEATURE_NAMES:
            features.append(float(associations.get(fname, 0.0)))

        # SHA from features+outcomes
        data_dict = {'semantic_features': features, 'outcomes': outcomes}
        data_sha = hashlib.sha256(json.dumps(data_dict, sort_keys=True).encode()).hexdigest()

        # Initialize semantic matrix if needed
        if self.semantic_weights is None:
            self.semantic_weights = [[0.1] * N_OUTCOMES for _ in range(N_SEMANTIC_FEATURES)]

        # Delta rule (same lr as runtime)
        lr = 0.05
        deltas = []
        for i in range(N_SEMANTIC_FEATURES):
            row_deltas = []
            for j in range(N_OUTCOMES):
                pred = features[i] * self.semantic_weights[i][j]
                error = outcomes[j] - pred
                delta = lr * error * features[i]
                self.semantic_weights[i][j] += delta
                row_deltas.append(round(delta, 6))
            deltas.append(row_deltas)

        self.save_semantic_weights(data_sha)

        return {
            'data_sha': data_sha[:16],
            'features': [round(f, 4) for f in features],
            'outcomes': [round(o, 4) for o in outcomes],
            'deltas': deltas
        }

    def save_semantic_weights(self, data_sha: str):
        """Save semantic weights alongside runtime weights."""
        version = f"semantic_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}"
        self.weights[version] = {
            "timestamp": datetime.datetime.now().isoformat(),
            "data_sha": data_sha,
            "shape": [N_SEMANTIC_FEATURES, N_OUTCOMES],
            "feature_names": SEMANTIC_FEATURE_NAMES,
            "outcome_names": OUTCOME_NAMES,
            "data": self.semantic_weights
        }
        try:
            with open(self.weights_path, 'w') as f:
                json.dump(self.weights, f, indent=2)
            logger.info(f"Saved semantic weights version {version}")
        except Exception as e:
            logger.error(f"Failed to save semantic weights: {e}")

# ======================================================================
# PART 17.7: QUERY ENGINE (6W1H Query & Chain Delta Analysis)
# ======================================================================

class QueryEngine:
    """
    6W1H query interface for manifest exploration and chain delta analysis.
    Supports bidirectional call-chain traversal and static-vs-runtime gap (delta) reporting.
    """
    def __init__(self, manifest: Manifest, runtime: Optional[RuntimeManifest] = None):
        self.manifest = manifest
        self.runtime = runtime
        self._reverse_calls: Dict[str, List[Dict]] = {}
        self._function_map: Dict[str, Dict] = {}
        self._class_map: Dict[str, Dict] = {}
        self._build_reverse_index()
        self._build_element_maps()

    def _build_reverse_index(self):
        """Build backward call graph from static FunctionInfo.calls lists."""
        for file_meta in self.manifest.files.values():
            for func in file_meta.functions:
                for callee, line in func.calls:
                    key = callee.split('.')[-1]  # last component of qualified name
                    self._reverse_calls.setdefault(key, []).append({
                        'caller': func.qualname,
                        'caller_name': func.name,
                        'file': func.file_path,
                        'line': line
                    })

    def _build_element_maps(self):
        """Build lookup maps for functions and classes by name/qualname."""
        for file_meta in self.manifest.files.values():
            for func in file_meta.functions:
                # Index by both name and qualname
                self._function_map[func.name] = {'type': 'function', 'data': func, 'file': file_meta}
                self._function_map[func.qualname] = {'type': 'function', 'data': func, 'file': file_meta}
            for cls in file_meta.classes:
                self._class_map[cls.name] = {'type': 'class', 'data': cls, 'file': file_meta}
                self._class_map[cls.qualname] = {'type': 'class', 'data': cls, 'file': file_meta}

    def _find_target(self, name: str) -> Optional[Dict]:
        """Find a function or class by name or qualname."""
        if name in self._function_map:
            return self._function_map[name]
        if name in self._class_map:
            return self._class_map[name]
        return None

    def query_6w1h(self, dimension: str, value: str) -> List[Dict]:
        """
        Filter manifest elements by a 6W1H dimension.
        Returns: list of {type, name, file, line, dimension_value, runtime_state}
        """
        results = []

        for file_path, file_meta in self.manifest.files.items():
            # WHERE: file path or line range
            if dimension == 'where':
                if value.lower() in file_path.lower():
                    results.append({
                        'type': 'file',
                        'name': file_path,
                        'dimension': 'where',
                        'value': file_path
                    })

            # WHAT: verb category or function/class name
            elif dimension == 'what':
                for func in file_meta.functions:
                    match = False
                    if value.lower() in func.name.lower():
                        match = True
                    elif hasattr(func.verb_category, 'value') and value.upper() == func.verb_category.value.upper():
                        match = True
                    if match:
                        state = 'executed' if func.runtime_executed else 'unexecuted'
                        results.append({
                            'type': 'function',
                            'name': func.qualname,
                            'file': func.file_path,
                            'line': func.line,
                            'dimension': 'what',
                            'value': func.verb_category.value if hasattr(func.verb_category, 'value') else func.name,
                            'state': state
                        })
                for cls in file_meta.classes:
                    if value.lower() in cls.name.lower():
                        state = 'instantiated' if cls.runtime_instantiated else 'uninstantiated'
                        results.append({
                            'type': 'class',
                            'name': cls.qualname,
                            'file': cls.file_path,
                            'line': cls.line,
                            'dimension': 'what',
                            'value': cls.name,
                            'state': state
                        })

            # STATE: execution state
            elif dimension == 'state':
                for func in file_meta.functions:
                    if value == 'all':
                        state = 'executed' if func.runtime_executed else 'unexecuted'
                    elif value == 'executed' and func.runtime_executed:
                        state = 'executed'
                    elif value == 'unexecuted' and not func.runtime_executed:
                        state = 'unexecuted'
                    elif value == 'failed' and func.runtime_exceptions:
                        state = 'failed'
                    else:
                        continue

                    results.append({
                        'type': 'function',
                        'name': func.qualname,
                        'file': func.file_path,
                        'line': func.line,
                        'dimension': 'state',
                        'value': state,
                        'exceptions': func.runtime_exceptions
                    })
                for cls in file_meta.classes:
                    if value == 'all':
                        state = 'instantiated' if cls.runtime_instantiated else 'uninstantiated'
                    elif value == 'instantiated' and cls.runtime_instantiated:
                        state = 'instantiated'
                    elif value == 'uninstantiated' and not cls.runtime_instantiated:
                        state = 'uninstantiated'
                    else:
                        continue

                    results.append({
                        'type': 'class',
                        'name': cls.qualname,
                        'file': cls.file_path,
                        'line': cls.line,
                        'dimension': 'state',
                        'value': state
                    })

            # HOW: call relationships (find callers of target)
            elif dimension == 'how':
                for caller_dict in self._reverse_calls.get(value, []):
                    results.append({
                        'type': 'call_relation',
                        'caller': caller_dict['caller'],
                        'callee': value,
                        'file': caller_dict['file'],
                        'line': caller_dict['line'],
                        'dimension': 'how'
                    })

            # WHY: docstring search
            elif dimension == 'why':
                for func in file_meta.functions:
                    if func.docstring and value.lower() in func.docstring.lower():
                        results.append({
                            'type': 'function',
                            'name': func.qualname,
                            'file': func.file_path,
                            'line': func.line,
                            'dimension': 'why',
                            'value': func.docstring[:100]
                        })
                for cls in file_meta.classes:
                    if cls.docstring and value.lower() in cls.docstring.lower():
                        results.append({
                            'type': 'class',
                            'name': cls.qualname,
                            'file': cls.file_path,
                            'line': cls.line,
                            'dimension': 'why',
                            'value': cls.docstring[:100]
                        })

        return results

    def chain_delta(self, target: str, include_delta: bool = False) -> Dict:
        """
        For a given function/class/import name, show:
        - forward_chain: what it calls/depends on
        - backward_chain: what calls/imports it
        - delta: what SHOULD trigger but DIDN'T (only if include_delta=True and runtime available)

        Returns comprehensive chain and delta info.
        """
        target_entry = self._find_target(target)
        if not target_entry:
            return {
                'target': target,
                'found': False,
                'forward_chain': [],
                'backward_chain': [],
                'prerequisite_chain': [],
                'delta': [],
                'coverage_score': 0.0
            }

        target_type = target_entry['type']
        target_data = target_entry['data']
        file_meta = target_entry['file']

        # Forward: what does target call?
        forward_chain = []
        if target_type == 'function':
            for callee, line in target_data.calls:
                forward_chain.append({
                    'target': callee,
                    'line': line,
                    'direction': 'forward'
                })

        # Backward: what calls target?
        backward_chain = []
        target_short_name = target.split('.')[-1]
        for caller_dict in self._reverse_calls.get(target_short_name, []):
            backward_chain.append({
                'caller': caller_dict['caller'],
                'file': caller_dict['file'],
                'line': caller_dict['line'],
                'direction': 'backward'
            })

        # Prerequisites from manifest
        prerequisite_chain = []
        if hasattr(self.manifest, 'prerequisites') and self.manifest.prerequisites:
            for prereq in self.manifest.prerequisites:
                if target in prereq.get('target', ''):
                    prerequisite_chain.append(asdict(prereq) if is_dataclass(prereq) else prereq)

        # Delta analysis (requires runtime)
        delta = []
        coverage_score = 0.0
        if include_delta and self.runtime:
            if target_type == 'function' and not target_data.runtime_executed:
                delta.append({
                    'issue': 'function_not_executed',
                    'target': target,
                    'reason': 'Function declared but never called at runtime'
                })

            # Check if forward callees were executed
            for callee, _ in target_data.calls:
                callee_entry = self._find_target(callee)
                if callee_entry and callee_entry['type'] == 'function':
                    if not callee_entry['data'].runtime_executed:
                        delta.append({
                            'issue': 'forward_not_executed',
                            'target': callee,
                            'reason': f'Called by {target} but not executed'
                        })

            # Check if backward callers were executed
            for caller_dict in backward_chain:
                caller_entry = self._find_target(caller_dict['caller'])
                if caller_entry and caller_entry['type'] == 'function':
                    if not caller_entry['data'].runtime_executed:
                        delta.append({
                            'issue': 'backward_not_executed',
                            'target': caller_dict['caller'],
                            'reason': f'Calls {target} but was not executed'
                        })

            # Coverage score: ratio of executed elements in chain to total
            executed_count = 0
            if target_type == 'function' and target_data.runtime_executed:
                executed_count += 1
            for callee, _ in target_data.calls:
                callee_entry = self._find_target(callee)
                if callee_entry and callee_entry['type'] == 'function' and callee_entry['data'].runtime_executed:
                    executed_count += 1
            for caller_dict in backward_chain:
                caller_entry = self._find_target(caller_dict['caller'])
                if caller_entry and caller_entry['type'] == 'function' and caller_entry['data'].runtime_executed:
                    executed_count += 1

            total_elements = 1 + len(forward_chain) + len(backward_chain)
            coverage_score = executed_count / max(total_elements, 1)

        return {
            'target': target,
            'target_type': target_type,
            'found': True,
            'forward_chain': forward_chain,
            'backward_chain': backward_chain,
            'prerequisite_chain': prerequisite_chain,
            'delta': delta,
            'coverage_score': coverage_score
        }

    def query_pattern_chain(self, sha_id: str, patterns_file: Optional[str] = None) -> Dict:
        """
        Full chain traversal for a pattern in pymanifest_patterns.json.

        sha_id → metadata.domain → metadata.6w1h → domain_index → slot_range → tensor_row_range

        The chain lives entirely in the JSON — one dict lookup, no GGUF binary access needed.
        To fix routing: set pattern['metadata']['domain'] and re-spawn (Pass 1 reads it directly).

        Args:
            sha_id:        16-char hex key from pymanifest_patterns.json (prefix search supported)
            patterns_file: path to patterns JSON (default: sibling pymanifest_patterns.json)

        Returns dict with keys:
            sha_id, found, pattern_type, domain, 6w1h, domain_index,
            slot_range, tensor_row_range, occurrence_count, outcome, metadata, note
        """
        DOMAIN_ORDER = [
            "Physics", "Chemistry", "Biology", "Mathematics", "Computer Science",
            "Astronomy", "Literature", "Philosophy", "History", "Economics"
        ]
        VOCAB_SIZE = 60000
        SLOT_SIZE = VOCAB_SIZE // len(DOMAIN_ORDER)  # 6000 rows per domain

        _patterns_file = patterns_file or str(
            Path(__file__).parent / "pymanifest_patterns.json"
        )

        try:
            with open(_patterns_file) as f:
                patterns = json.load(f)
        except Exception as e:
            return {'sha_id': sha_id, 'found': False, 'error': str(e)}

        entry = patterns.get(sha_id)
        if not entry:
            # Prefix search — allow partial sha_id
            matches = [k for k in patterns if k.startswith(sha_id)]
            if len(matches) == 1:
                sha_id = matches[0]
                entry = patterns[sha_id]
            elif len(matches) > 1:
                return {
                    'sha_id': sha_id, 'found': False,
                    'error': f'Ambiguous prefix: {len(matches)} matches',
                    'candidates': matches[:5]
                }
            else:
                return {'sha_id': sha_id, 'found': False, 'error': 'Pattern not found'}

        meta = entry.get('metadata', {})
        domain = meta.get('domain', '?')
        w6h1 = meta.get('6w1h', {})

        # Compute domain index and token_embd slot range
        domain_index = None
        slot_range = None
        tensor_row_range = None
        domain_lower = domain.lower()
        for i, d in enumerate(DOMAIN_ORDER):
            if d.lower() == domain_lower or d.lower() in domain_lower:
                domain_index = i
                slot_start = i * SLOT_SIZE
                slot_range = [slot_start, slot_start + SLOT_SIZE - 1]
                tensor_row_range = slot_range  # token_embd rows == slot positions
                break

        return {
            'sha_id': sha_id,
            'found': True,
            'pattern_type': entry.get('pattern_type'),
            'domain': domain,
            '6w1h': w6h1,
            'domain_index': domain_index,
            'slot_range': slot_range,
            'tensor_row_range': tensor_row_range,
            'occurrence_count': entry.get('occurrence_count', 0),
            'outcome': entry.get('outcome'),
            'metadata': meta,
            'note': (
                'slot_range covers all rows for this domain in token_embd.weight. '
                'Exact row within that range is determined by spawn bucket ordering '
                '(spawn_v51_gguf._build_domain_buckets). '
                'To fix routing: edit metadata.domain in pymanifest_patterns.json then re-spawn.'
            )
        }

# ======================================================================
# PART 17.3: T23 ANCESTRAL MEMORY + MORPHOLOGICAL ARCHIVE
# ======================================================================

class AncestralMemoryEngine:
    """Weights pattern retrieval by recency + exhaustion + novelty.
    Surfaces old/ancestral patterns (CDALS lineage, early orchestrator) ONLY
    when the current context is sufficiently novel.
    Prevents stale patterns from dominating while making ancestral wisdom
    available for edge cases."""

    NOVELTY_THRESHOLD = 0.70
    RECENCY_HALFLIFE_DAYS = 90
    CONTEXT_BUFFER_SIZE = 200

    def __init__(self, db):
        self.db = db
        self._context_buffer = []  # circular list of token-sets
        self._buffer_path = None

    def _load_buffer(self, variants_dir: Path):
        """Load persisted context buffer if available."""
        if self._buffer_path:
            return
        self._buffer_path = variants_dir / 'ancestral_context_buffer.json'
        if self._buffer_path.exists():
            try:
                data = json.loads(self._buffer_path.read_text())
                self._context_buffer = [set(row) for row in data[-self.CONTEXT_BUFFER_SIZE:]]
            except Exception:
                self._context_buffer = []

    def register_context(self, context_tokens: list, variants_dir: Path = None):
        """Append token set to rolling buffer and persist."""
        token_set = set(t.lower() for t in context_tokens if t)
        if token_set:
            self._context_buffer.append(token_set)
            if len(self._context_buffer) > self.CONTEXT_BUFFER_SIZE:
                self._context_buffer = self._context_buffer[-self.CONTEXT_BUFFER_SIZE:]
        if variants_dir and self._buffer_path is None:
            self._buffer_path = variants_dir / 'ancestral_context_buffer.json'
        if self._buffer_path:
            try:
                self._buffer_path.write_text(
                    json.dumps([list(s) for s in self._context_buffer[-self.CONTEXT_BUFFER_SIZE:]])
                )
            except Exception:
                pass

    def compute_novelty_score(self, context_tokens: list) -> float:
        """1.0 - max_jaccard vs seen contexts. High = never seen this before."""
        if not context_tokens or not self._context_buffer:
            return 1.0
        token_set = set(t.lower() for t in context_tokens if t)
        if not token_set:
            return 1.0
        best = 0.0
        for seen in self._context_buffer[-50:]:  # last 50 for speed
            if not seen:
                continue
            inter = len(token_set & seen)
            union = len(token_set | seen)
            if union:
                j = inter / union
                if j > best:
                    best = j
        return max(0.0, 1.0 - best)

    def compute_age_weight(self, pattern: dict) -> float:
        """Exponential decay: halves every RECENCY_HALFLIFE_DAYS."""
        import math
        meta = pattern.get('metadata', {})
        first_seen = meta.get('first_seen', pattern.get('first_seen', ''))
        if not first_seen:
            return 0.5
        try:
            ts = datetime.datetime.fromisoformat(str(first_seen)[:19])
            age_days = (datetime.datetime.now() - ts).days
            return math.exp(-age_days * math.log(2) / self.RECENCY_HALFLIFE_DAYS)
        except Exception:
            return 0.5

    def compute_exhaustion_weight(self, pattern: dict) -> float:
        """Higher occurrence count → lower weight (freshness penalty)."""
        import math
        count = pattern.get('occurrence_count', 1)
        return 1.0 / math.sqrt(max(1, count - 1))

    def surface_ancestral(self, context_tokens: list, n: int = 5) -> list:
        """Return top-N ancestral/old patterns if novelty > NOVELTY_THRESHOLD."""
        novelty = self.compute_novelty_score(context_tokens)
        if novelty < self.NOVELTY_THRESHOLD:
            return []
        candidates = []
        for pid, p_obj in self.db.patterns.items():
            p = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
            p_type = str(p.get('pattern_type', ''))
            # ANCESTRAL_MEMORY patterns or old SCRIPT_INGEST with domain='ancestor'
            if 'ANCESTRAL_MEMORY' in p_type:
                is_ancestral = True
            elif 'SCRIPT_INGEST' in p_type and p.get('metadata', {}).get('domain') == 'ancestor':
                is_ancestral = True
            else:
                continue
            age_w = self.compute_age_weight(p)
            exhaust_w = self.compute_exhaustion_weight(p)
            novelty_boost = novelty * 0.5 if novelty > self.NOVELTY_THRESHOLD else 0
            score = age_w * exhaust_w * (1 + novelty_boost)
            candidates.append((score, pid, p))
        candidates.sort(key=lambda x: x[0], reverse=True)
        return [{'score': s, 'pid': pid, 'pattern': p} for s, pid, p in candidates[:n]]

    def promote_to_ancestral(self, pattern_id: str, reason: str = '') -> bool:
        """Tag a SCRIPT_INGEST/KNOWLEDGE pattern as ANCESTRAL_MEMORY."""
        if pattern_id not in self.db.patterns:
            return False
        p_obj = self.db.patterns[pattern_id]
        p = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
        meta = p.get('metadata', {})
        meta['ancestral_reason'] = reason
        meta['promoted_at'] = datetime.datetime.now().isoformat()
        # Update pattern_type in DB
        if hasattr(p_obj, 'pattern_type'):
            try:
                p_obj.pattern_type = PatternType.ANCESTRAL_MEMORY
            except Exception:
                pass
        return True


class MorphologicalVariantArchive:
    """Captures capability-delta snapshots at each spawn.
    Enables temporal comparison: what did this variant gain vs parent?
    What measurement coverage expanded? What gaps closed?"""

    def capture_snapshot(self, name: str, domain: str, tier: str,
                         build_data: dict, db, parent_name: str = None) -> dict:
        """Build snapshot dict from build_data + pattern DB state."""
        patterns = db.patterns if hasattr(db, 'patterns') else {}
        # Count by type
        type_dist = {}
        for p_obj in patterns.values():
            p = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
            pt = str(p.get('pattern_type', 'UNKNOWN')).split('.')[-1]
            type_dist[pt] = type_dist.get(pt, 0) + 1

        # Native function count
        native_count = type_dist.get('NATIVE_FUNCTION', 0)

        # Parent gap resolutions — PARENT_GAP patterns present
        gap_count = type_dist.get('PARENT_GAP', 0)

        # Measurement coverage estimate
        meas_count = type_dist.get('MEASUREMENT_DESIGNATION', 0) + type_dist.get('MEASUREMENT_PATTERN', 0)
        total = max(1, len(patterns))
        meas_coverage = round(meas_count / total * 100, 1)

        # Top domains from metadata
        domain_counts = {}
        for p_obj in patterns.values():
            p = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
            d = p.get('metadata', {}).get('domain', p.get('metadata', {}).get('primary_domain', ''))
            if d:
                domain_counts[d] = domain_counts.get(d, 0) + 1
        top_domains = sorted(domain_counts, key=domain_counts.get, reverse=True)[:5]

        spawn_meta = build_data.get('spawn_meta', {})
        return {
            'name': name,
            'domain': domain,
            'tier': tier,
            'ts': datetime.datetime.now().isoformat(),
            'generation': spawn_meta.get('generation', 2),
            'pattern_count': len(patterns),
            'native_count': native_count,
            'gap_count': gap_count,
            'measurement_coverage_pct': meas_coverage,
            'pattern_type_distribution': type_dist,
            'top_domains': top_domains,
            'domain_pattern_counts': domain_counts,
            'parent_name': parent_name or spawn_meta.get('parent', None),
            'lineage_path': spawn_meta.get('lineage_path', []),
            'gap_resolutions': build_data.get('parent_gap_map', {}),
            'absorbed_scripts': build_data.get('absorbed_scripts', []),
        }

    def write_archive(self, snapshot: dict, variants_dir: Path) -> Path:
        """Write morph_archive JSON and append summary to morph_index.jsonl."""
        variants_dir.mkdir(parents=True, exist_ok=True)
        domain = snapshot.get('domain', 'general') or 'general'
        ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        archive_path = variants_dir / f"morph_archive_{domain}_{ts}.json"
        archive_path.write_text(json.dumps(snapshot, indent=2, default=str))
        index_path = variants_dir / 'morph_index.jsonl'
        summary = {
            'ts': snapshot['ts'],
            'name': snapshot['name'],
            'domain': domain,
            'tier': snapshot.get('tier', '?'),
            'generation': snapshot.get('generation', '?'),
            'pattern_count': snapshot.get('pattern_count', 0),
            'native_count': snapshot.get('native_count', 0),
            'measurement_coverage_pct': snapshot.get('measurement_coverage_pct', 0),
            'archive_file': archive_path.name,
        }
        with open(index_path, 'a') as f:
            f.write(json.dumps(summary) + '\n')
        return archive_path

    def load_archive(self, archive_path: Path) -> dict:
        try:
            return json.loads(archive_path.read_text())
        except Exception:
            return {}

    def compare(self, a1: dict, a2: dict) -> dict:
        """Return delta between two snapshots."""
        return {
            'pattern_delta': a2.get('pattern_count', 0) - a1.get('pattern_count', 0),
            'native_delta': a2.get('native_count', 0) - a1.get('native_count', 0),
            'gap_delta': a2.get('gap_count', 0) - a1.get('gap_count', 0),
            'measurement_coverage_delta': round(
                a2.get('measurement_coverage_pct', 0) - a1.get('measurement_coverage_pct', 0), 1),
            'top_domains_a1': a1.get('top_domains', []),
            'top_domains_a2': a2.get('top_domains', []),
        }

    def temporal_curve(self, domain: str, variants_dir: Path, n: int = 5) -> list:
        """Load last N morph_archive_{domain}_*.json sorted by timestamp."""
        if not variants_dir.exists():
            return []
        files = sorted(variants_dir.glob(f"morph_archive_{domain}_*.json"))
        results = []
        for f in files[-n:]:
            snap = self.load_archive(f)
            if snap:
                results.append(snap)
        return results



