class OmegaBacktester:
    """Verifies each spawned omega against a capability checklist to identify
    design gaps — 'Design is calculation'. Tests by source-text scan only (no exec).
    Also tests the reverse chain: alpha token output → spawn eligibility."""

    CAPABILITY_CHECKS = [
        ('can_spawn_alpha',        'has _cmd_spawn_alpha in source'),
        ('can_token_generate',     'has TokenWeightMatrix in source'),
        ('has_parent_state',       'has parent-state command in source'),
        ('has_native_funcs',       'NATIVE_FUNCTION patterns in DB'),
        ('has_measurement_domain', 'semantic_systems OR neural_network OR ml_pipeline in DOMAIN_TOOL_SETS'),
        ('has_thought_chains',     'THOUGHT_CHAIN patterns in DB'),
        ('has_lineage',            'spawn_meta generation in DB patterns'),
        ('can_backtest',           'backtest command in source'),
        ('has_scratch_pad',        'MorphScratchPad in source'),
        ('has_attribution',        'DomainAttributionMatrix in source'),
        ('has_morph_catalog',      'MorphCatalogEngine in source'),
    ]

    def __init__(self, db=None):
        self.db = db

    def _load_source(self, omega_path):
        try:
            return open(omega_path, 'r', errors='ignore').read()
        except Exception:
            return ''

    def test_omega(self, omega_path) -> dict:
        """Source-text scan for each capability. Returns {name, passed, failed, score}."""
        src = self._load_source(omega_path)
        name = omega_path.name if hasattr(omega_path, 'name') else str(omega_path)
        passed = []
        failed = []
        for check_id, description in self.CAPABILITY_CHECKS:
            ok = False
            if check_id == 'can_spawn_alpha':
                ok = '_cmd_spawn_alpha' in src
            elif check_id == 'can_token_generate':
                ok = 'TokenWeightMatrix' in src
            elif check_id == 'has_parent_state':
                ok = 'parent-state' in src
            elif check_id == 'has_native_funcs':
                ok = 'NATIVE_FUNCTION' in src
            elif check_id == 'has_measurement_domain':
                ok = ('semantic_systems' in src or 'neural_network' in src or 'ml_pipeline' in src)
            elif check_id == 'has_thought_chains':
                ok = 'THOUGHT_CHAIN' in src
            elif check_id == 'has_lineage':
                ok = ('generation' in src and 'lineage_path' in src)
            elif check_id == 'can_backtest':
                ok = 'backtest' in src
            if ok:
                passed.append(check_id)
            else:
                failed.append(check_id)
        return {
            'name': name,
            'passed': passed,
            'failed': failed,
            'score': f"{len(passed)}/{len(self.CAPABILITY_CHECKS)}",
        }

    def identify_design_gaps(self, result: dict) -> list:
        """Maps failed checks to known design decision locations."""
        GAP_MAP = {
            'can_spawn_alpha':        'spawn_omega() → _cmd_spawn_alpha template not included',
            'can_token_generate':     'spawn_omega() → TokenWeightMatrix template missing',
            'has_parent_state':       'full-build template → parent-state command not wired (T23)',
            'has_native_funcs':       'spawn_omega() → NATIVE_FUNCTION patterns not created',
            'has_measurement_domain': 'T24 domain_keywords / DOMAIN_TOOL_SETS not in omega source',
            'has_thought_chains':     'grade_response() → ThoughtMatrixStore not wired (T24)',
            'has_lineage':            'spawn_omega() → LineageGraph not called (T23)',
            'can_backtest':           'omega_dispatcher_patch → backtest command not added (T24)',
        }
        gaps = []
        for check_id in result.get('failed', []):
            gaps.append({'check': check_id, 'gap': GAP_MAP.get(check_id, 'unknown')})
        return gaps

    def backtest_all(self, variants_dir) -> dict:
        """Scan all omega_*.py in variants_dir and return {name: result}."""
        from pathlib import Path as _Path
        vdir = _Path(variants_dir)
        results = {}
        for omf in sorted(vdir.glob('omega_*.py')):
            results[omf.name] = self.test_omega(omf)
        return results

    def backtest_token_chain(self, alpha_path) -> dict:
        """Verify alpha has spawn-relevant token patterns from parent blend.
        Returns {alpha_name, spawn_eligible, findings}."""
        src = self._load_source(alpha_path)
        name = alpha_path.name if hasattr(alpha_path, 'name') else str(alpha_path)
        findings = []
        if 'chain_policy' in src:
            findings.append('has chain_policy tier patterns from FunctionalWeightProfiler')
        if 'THOUGHT_CHAIN' in src:
            findings.append('has THOUGHT_CHAIN records — executable chain patterns present')
        if 'parent_script' in src and 'blend_ratio' in src:
            findings.append('is mutant alpha with parent blend metadata')
        spawn_eligible = 'chain_policy' in src or 'THOUGHT_CHAIN' in src
        return {'alpha_name': name, 'spawn_eligible': spawn_eligible, 'findings': findings}

    def format_report(self, backtest_results: dict) -> str:
        lines = ['  Back-test results:']
        for name, r in backtest_results.items():
            status = 'PASS' if not r['failed'] else f"WARN ({len(r['failed'])} gaps)"
            lines.append(f"  {name}: {r['score']} {status}")
            for f in r['failed']:
                gaps = self.identify_design_gaps(r)
                for g in gaps:
                    if g['check'] == f:
                        lines.append(f"    ✗ {f}: {g['gap']}")
        return '\n'.join(lines)


