class LineageGraph:
    """Reads spawn_log.jsonl → builds directed acyclic graph of all spawn events
    → assigns generation depth to each node.
    Pre-cursor scripts are registered as generation 0 roots."""

    ANCESTRAL_ROOTS = {
        'CDALS_v2':            {'gen': 0, 'role': 'cross_domain_learning', 'tier': 'ancestor'},
        'CDALS_v3':            {'gen': 0, 'role': 'cross_domain_learning', 'tier': 'ancestor'},
        'orchestrator':        {'gen': 0, 'role': 'linguistic_hierarchy',  'tier': 'ancestor'},
        'Os_Toolkit':          {'gen': 0, 'role': 'forensic_toolkit',      'tier': 'ancestor'},
        'onboarder':           {'gen': 0, 'role': 'tool_discovery',        'tier': 'ancestor'},
        'Filesync':            {'gen': 0, 'role': 'file_organization',     'tier': 'ancestor'},
        'py_manifest_augmented': {'gen': 1, 'role': 'pattern_engine',     'tier': 'generator'},
    }

    def __init__(self):
        self._graph = {}  # name → {parent, generation, ts, event, domain, tier}

    def build_from_log(self, spawn_log_path: Path) -> dict:
        """Read spawn_log.jsonl and build the generation graph."""
        # Seed with ancestral roots
        for name, info in self.ANCESTRAL_ROOTS.items():
            self._graph[name] = {
                'parent': None,
                'generation': info['gen'],
                'ts': None,
                'event': 'root',
                'domain': info.get('role', ''),
                'tier': info.get('tier', 'ancestor'),
            }

        if not spawn_log_path.exists():
            return dict(self._graph)

        try:
            lines = spawn_log_path.read_text().splitlines()
        except Exception:
            return dict(self._graph)

        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                record = json.loads(line)
            except Exception:
                continue

            event = record.get('event', '')
            name = record.get('name', '')
            if not name:
                continue

            parent = record.get('parent') or 'py_manifest_augmented'
            domain = record.get('domain', None)
            ts = record.get('ts', '')

            # Determine generation from parent
            parent_gen = self._graph.get(parent, {}).get('generation', 1)

            if event == 'omega_spawn':
                gen = parent_gen + 1  # omega = py_manifest(gen=1) + 1 = 2
                tier = 'omega'
            elif event == 'alpha_spawn':
                gen = parent_gen + 1  # alpha = omega(gen=2) + 1 = 3
                tier = 'alpha'
            elif event == 'fix_spawn':
                # Lateral — same gen as parent omega
                gen = parent_gen
                tier = 'fix'
            else:
                gen = parent_gen + 1
                tier = 'unknown'

            self._graph[name] = {
                'parent': parent,
                'generation': gen,
                'ts': ts,
                'event': event,
                'domain': domain,
                'tier': tier,
            }

        return dict(self._graph)

    def get_generation(self, name: str) -> int:
        info = self._graph.get(name)
        if info:
            return info.get('generation', 2)
        # Default: if name looks like omega_vN, gen=2; specialist_*, gen=3
        if name and name.startswith('specialist_'):
            return 3
        return 2

    def get_lineage_path(self, name: str) -> list:
        """Build lineage path from CDALS ancestors to current."""
        path = []
        current = name
        visited = set()
        while current and current not in visited:
            visited.add(current)
            path.insert(0, current)
            info = self._graph.get(current, {})
            parent = info.get('parent')
            if not parent or parent == current:
                break
            current = parent
        # Ensure CDALS roots appear at front if not already
        ancestral = [n for n in ['CDALS_v2', 'orchestrator', 'py_manifest_augmented']
                     if n not in path]
        return ancestral + path

    def get_siblings(self, name: str) -> list:
        """Return nodes with same parent and same domain."""
        info = self._graph.get(name, {})
        parent = info.get('parent')
        domain = info.get('domain')
        return [
            n for n, d in self._graph.items()
            if d.get('parent') == parent and d.get('domain') == domain and n != name
        ]

    def get_capability_evolution(self, domain: str) -> list:
        """Return nodes for a domain sorted by generation."""
        nodes = [
            {'name': n, **d}
            for n, d in self._graph.items()
            if d.get('domain') == domain
        ]
        return sorted(nodes, key=lambda x: x.get('generation', 0))

    def save_graph(self, variants_dir: Path):
        """Write lineage_graph.json to variants/."""
        variants_dir.mkdir(parents=True, exist_ok=True)
        out = variants_dir / 'lineage_graph.json'
        out.write_text(json.dumps(self._graph, indent=2, default=str))
        return out

    def format_tree(self) -> str:
        """Format tree for display in lineage command."""
        lines = [f"  Lineage graph ({len(self._graph)} nodes):"]
        by_gen = {}
        for name, info in self._graph.items():
            g = info.get('generation', 0)
            by_gen.setdefault(g, []).append((name, info))
        for g in sorted(by_gen):
            nodes = by_gen[g]
            for name, info in sorted(nodes, key=lambda x: x[0]):
                tier = info.get('tier', '?')
                domain = f" domain={info['domain']}" if info.get('domain') else ''
                parent = f" ← {info['parent']}" if info.get('parent') else ''
                lines.append(f"  [gen {g}] {name} ({tier}){domain}{parent}")
        return '\n'.join(lines)


