# T14: Simplified ProbePatternEngine for standalone
class ProbePatternEngine:
    SEED_PROBES = [
        {{"label": "disambiguate_python", "trigger_tokens": ["python"],
          "probe_text": "Are you referring to Python the programming language or python snakes?",
          "probe_type": "disambiguation", "target_domains": ["programming", "zoology"]}},
        {{"label": "specificity_species", "trigger_tokens": ["species", "animal", "snake"],
          "probe_text": "Which species are you interested in, or all of them?",
          "probe_type": "specificity", "target_domains": ["zoology"]}},
        {{"label": "specificity_framework", "trigger_tokens": ["gui", "web", "app"],
          "probe_text": "Do you have a preferred framework or library for this?",
          "probe_type": "specificity", "target_domains": ["programming", "gui"]}},
        {{"label": "confirmation_project", "trigger_tokens": ["build", "create", "plan"],
          "probe_text": "Should I create a project plan with code structure and tasks?",
          "probe_type": "confirmation", "target_domains": ["programming", "operational"]}},
    ]

    def __init__(self, db):
        self.db = db
        self._seed_probes()
        self._probe_index = self._build_probe_index()

    def _seed_probes(self):
        existing = [p for p in self.db.get_patterns_by_type(PatternType.PROBE_PATTERN)
                    if p.metadata.get("label") == "disambiguate_python"]
        if existing:
            return
        for probe in self.SEED_PROBES:
            content = f"probe:{{probe['label']}}"
            context = f"trigger:{{','.join(probe['trigger_tokens'])}}"
            pat = Pattern(
                pattern_id="", content_hash=hashlib.sha256(content.encode()).hexdigest()[:16],
                context_hash=hashlib.sha256(context.encode()).hexdigest()[:16],
                pattern_hash="" if not hasattr(Pattern, "pattern_hash") else hashlib.sha256(f"{{content}}:{{context}}".encode()).hexdigest()[:16],
                pattern_type=PatternType.PROBE_PATTERN, outcome="learned",
                metadata={{**probe, "occurrence_count": 0}})
            self.db.add_or_update(pat)

    def _build_probe_index(self):
        index = {{}}
        for p in self.db.get_patterns_by_type(PatternType.PROBE_PATTERN):
            for tok in p.metadata.get("trigger_tokens", []):
                index.setdefault(tok.lower(), []).append(p)
        return index

    def evaluate(self, tokens, domain_vector, matched, alpha_mem=None):
        result = {{"should_probe": False, "probe_text": "", "probe_type": "",
                  "probe_pid": "", "target_domains": []}}
        impl_conf = domain_vector.get("impl_confidence", 1.0)
        subj_conf = domain_vector.get("subj_confidence", 1.0)
        impl_dom = domain_vector.get("implementation_domain", "general")
        subj_dom = domain_vector.get("subject_domain", "general")
        ambiguous = (impl_dom != subj_dom and impl_conf < 0.7 and subj_conf < 0.7)
        if not ambiguous:
            overall_conf = max(impl_conf, subj_conf)
            has_trigger = any(t.lower() in self._probe_index for t in tokens)
            if not (has_trigger and overall_conf < 0.6):
                return result
        candidates = []
        token_set = set(t.lower() for t in tokens)
        seen = set()
        for tok in tokens:
            for probe in self._probe_index.get(tok.lower(), []):
                if probe.pattern_id in seen:
                    continue
                seen.add(probe.pattern_id)
                trigger_tokens = set(probe.metadata.get("trigger_tokens", []))
                score = 1.0 + len(trigger_tokens & token_set) * 0.3
                probe_targets = set(probe.metadata.get("target_domains", []))
                if probe_targets & ({{impl_dom, subj_dom}} - {{"general"}}):
                    score *= 1.5
                candidates.append((score, probe))
        if not candidates:
            return result
        candidates.sort(key=lambda x: x[0], reverse=True)
        best_score, best_probe = candidates[0]
        if best_score < 0.5:
            return result
        result["should_probe"] = True
        result["probe_text"] = best_probe.metadata.get("probe_text", "")
        result["probe_type"] = best_probe.metadata.get("probe_type", "")
        result["probe_pid"] = best_probe.pattern_id
        result["target_domains"] = best_probe.metadata.get("target_domains", [])
        return result

class AlphaPatternMemory:
    EMA_ALPHA = 0.3
    def __init__(self):
        self.performance = {{}}
    def record_outcome(self, pattern_id, grade):
        entry = self.performance.setdefault(pattern_id, {{"proven": 0, "biased": 0, "ema": 0.5}})
        if grade in ("A", "B"):
            entry["proven"] += 1
            entry["ema"] = entry["ema"] * 0.7 + 0.3
        elif grade in ("D", "F"):
            entry["biased"] += 1
            entry["ema"] = entry["ema"] * 0.7
        else:
            entry["ema"] = entry["ema"] * 0.7 + 0.15
    def get_weight(self, pid):
        return self.performance.get(pid, {{}}).get("ema", 0.5)
    def to_dict(self):
        return {{"performance": self.performance}}
    @classmethod
    def from_dict(cls, data):
        m = cls()
        m.performance = data.get("performance", {{}})
        return m

class PatternBrainChat:
    PRESETS = {{
        "SHORT": {{"max_tokens": 20}},
        "MEDIUM_Q": {{"max_tokens": 40}},
        "MEDIUM_STMT": {{"max_tokens": 60}},
        "LONG_EXPLAIN": {{"max_tokens": 120}},
        "STORY": {{"max_tokens": 200}},
    }}

    def __init__(self, db: PatternDatabase):
        self.db = db
        self.turn_history = []
        self.active_domain = "general"
        self.confidence = 0.5
        self._build_indices()
        self._compartment_weights = dict(DEFAULT_COMPARTMENT_WEIGHTS)
        self.probe_engine = ProbePatternEngine(db)
        self._last_domain_vector = {{}}
        # T15: Alpha memory + session persistence
        self.alpha_mem = AlphaPatternMemory()
        self._last_activated_pids = []
        self._last_candidates = []      # T16
        self._prev_metrics = None       # T16
        self._session_path = Path(__file__).parent / "session_state.json"
        self._load_session()

    def _load_session(self):
        try:
            if self._session_path.exists():
                data = json.loads(self._session_path.read_text())
                self.turn_history = data.get("turn_history", [])
                self.confidence = data.get("confidence", 0.5)
                if "alpha_mem" in data:
                    self.alpha_mem = AlphaPatternMemory.from_dict(data["alpha_mem"])
        except (json.JSONDecodeError, OSError):
            pass

    def save_session(self):
        data = {{"turn_history": self.turn_history[-50:], "confidence": self.confidence,
                "alpha_mem": self.alpha_mem.to_dict(),
                "saved_at": datetime.datetime.now().isoformat()}}
        self._session_path.write_text(json.dumps(data, indent=2))

    def _build_indices(self):
        self.dict_terms = {{}}
        self.verb_funcs = {{}}
        self.class_tax = {{}}
        self.speech_pats = {{}}
        self.knowledge_sections = {{}}
        for p in self.db.patterns.values():
            if p.pattern_type == PatternType.DICTIONARY_TERM:
                term = p.metadata.get("term", "")
                if term:
                    self.dict_terms[term.lower()] = p
            elif p.pattern_type == PatternType.VERB_FUNCTION_MAP:
                func_name = p.metadata.get("name", "")
                if func_name:
                    for part in func_name.lower().split("_"):
                        if len(part) >= 3:
                            self.verb_funcs.setdefault(part, []).append(p)
            elif p.pattern_type == PatternType.CLASS_TAXONOMY:
                cls = p.metadata.get("name", "")
                if cls:
                    self.class_tax[cls.lower()] = p
                    for cp in re.findall(r"[A-Z][a-z]+|[a-z]+", cls):
                        if len(cp) >= 3:
                            self.class_tax.setdefault(cp.lower(), p)
            elif p.pattern_type == PatternType.SPEECH_PATTERN:
                dom = p.metadata.get("domain", "general")
                self.speech_pats.setdefault(dom, []).append(p)
            elif p.pattern_type == PatternType.KNOWLEDGE_ENTRY:
                title = p.metadata.get("title", "").lower()
                if title:
                    self.knowledge_sections.setdefault(title, []).append(p)
                    for word in title.split():
                        if len(word) >= 3:
                            self.knowledge_sections.setdefault(word, []).append(p)

    @staticmethod
    def _stem(token):
        if len(token) < 4: return ""
        if token.endswith("ies") and len(token) > 4: return token[:-3] + "y"
        if token.endswith("ing") and len(token) > 5: return token[:-3]
        if token.endswith("ed") and len(token) > 4: return token[:-2]
        if token.endswith("s") and not token.endswith("ss") and len(token) > 3: return token[:-1]
        return ""

    def _tokenize(self, text):
        raw = re.findall(r"\\b\\w+\\b", text)
        tokens = []
        for w in raw:
            parts = re.findall(r"[A-Z]+(?=[A-Z][a-z])|[A-Z][a-z]+|[a-z]+|[A-Z]+$", w)
            if len(parts) > 1:
                tokens.extend(p.lower() for p in parts if len(p) >= 2)
            elif "_" in w:
                tokens.extend(p.lower() for p in w.split("_") if len(p) >= 2)
            elif len(w) >= 2:
                tokens.append(w.lower())
        stems, seen = [], set(tokens)
        for t in tokens:
            s = PatternBrainChat._stem(t)
            if s and s not in seen:
                stems.append(s)
                seen.add(s)
        tokens.extend(stems)
        return tokens

    def _detect_intent(self, tokens, user_text=""):
        best_label, best_score = "", 0.0
        token_set = set(tokens)
        user_lower = user_text.lower()
        for p in self.db.patterns.values():
            if p.pattern_type != PatternType.SPEECH_PATTERN: continue
            label = p.metadata.get("label", "")
            if not label.startswith("intent_"): continue
            intent_tokens = set(p.metadata.get("intent_tokens", []))
            if not intent_tokens: continue
            intersection = len(token_set & intent_tokens)
            union = len(token_set | intent_tokens)
            score = intersection / max(union, 1)
            for t in intent_tokens:
                if len(t) > 3 and t in user_lower:
                    score += 0.3
                    break
            if score > best_score and score >= 0.15:
                best_score = score
                best_label = label.replace("intent_", "")
        return best_label

    def _attribute_tokens(self, tokens, matched):
        attributions = []
        for tok in tokens:
            weights = {{}}
            tok_lower = tok.lower()
            is_impl = tok_lower in DomainLayerClassifier.IMPL_SIGNALS
            is_subj = False
            if tok_lower in self.dict_terms:
                dom = self.dict_terms[tok_lower].metadata.get("domain", "general")
                weights[dom] = weights.get(dom, 0.0) + 1.0
                if dom not in DomainLayerClassifier.IMPL_DOMAINS and dom != "general":
                    is_subj = True
            for vp in self.verb_funcs.get(tok_lower, []):
                dom = vp.metadata.get("domain", "programming")
                weights[dom] = weights.get(dom, 0.0) + 0.8
                is_impl = True
            if tok_lower in self.class_tax:
                dom = self.class_tax[tok_lower].metadata.get("domain", "programming")
                weights[dom] = weights.get(dom, 0.0) + 0.7
            if tok_lower in self.knowledge_sections:
                for kp in self.knowledge_sections[tok_lower]:
                    dom = kp.metadata.get("domain", "programming")
                    weights[dom] = weights.get(dom, 0.0) + 0.9
                    if dom not in DomainLayerClassifier.IMPL_DOMAINS and dom != "general":
                        is_subj = True
            if not weights:
                weights["general"] = 0.1
            attributions.append(TokenAttribution(
                token=tok, stem=self._stem(tok), domain_weights=weights,
                source_patterns=[], is_implementation=is_impl, is_subject=is_subj))
        return attributions

    def _compute_multi_domain_weights(self, attributions):
        layers = DomainLayerClassifier.classify(attributions)
        # Turn history recency decay
        decay = [0.3, 0.2, 0.1]
        for i, turn in enumerate(reversed(self.turn_history[-3:])):
            td = turn.get("domain", "")
            if td and td != "general" and i < len(decay):
                if td in DomainLayerClassifier.IMPL_DOMAINS:
                    layers["impl_scores"][td] = layers["impl_scores"].get(td, 0.0) + decay[i]
                else:
                    layers["subj_scores"][td] = layers["subj_scores"].get(td, 0.0) + decay[i]
            impl_d = turn.get("impl_domain", "")
            subj_d = turn.get("subj_domain", "")
            if impl_d and i < len(decay):
                layers["impl_scores"][impl_d] = layers["impl_scores"].get(impl_d, 0.0) + decay[i] * 0.5
            if subj_d and i < len(decay):
                layers["subj_scores"][subj_d] = layers["subj_scores"].get(subj_d, 0.0) + decay[i] * 0.5
        # Re-pick winners
        if layers["impl_scores"]:
            layers["implementation_domain"] = max(layers["impl_scores"], key=layers["impl_scores"].get)
            total = sum(layers["impl_scores"].values()) or 1.0
            layers["impl_confidence"] = round(layers["impl_scores"][layers["implementation_domain"]] / total, 3)
        if layers["subj_scores"]:
            layers["subject_domain"] = max(layers["subj_scores"], key=layers["subj_scores"].get)
            total = sum(layers["subj_scores"].values()) or 1.0
            layers["subj_confidence"] = round(layers["subj_scores"][layers["subject_domain"]] / total, 3)
        all_scores = {{}}
        for scores in [layers.get("impl_scores", {{}}), layers.get("subj_scores", {{}})]:
            for dom, score in scores.items():
                all_scores[dom] = all_scores.get(dom, 0.0) + score
        ambiguous = (layers["implementation_domain"] != layers["subject_domain"]
                     and layers.get("impl_confidence", 1.0) < 0.7
                     and layers.get("subj_confidence", 1.0) < 0.7)
        layers["domain_vector"] = all_scores
        layers["ambiguous"] = ambiguous
        layers["primary"] = (layers["implementation_domain"]
                             if layers.get("impl_confidence", 0) >= 0.5
                             else layers["subject_domain"])
        return layers

    def _compute_temporal_domain(self, tokens, matched):
        domain_scores = {{}}
        for m in matched.get("dict", []):
            dom = m.metadata.get("domain", "general")
            domain_scores[dom] = domain_scores.get(dom, 0.0) + 1.0
        for m in matched.get("verbs", []):
            dom = m.metadata.get("domain", "general")
            domain_scores[dom] = domain_scores.get(dom, 0.0) + 1.0
        for m in matched.get("knowledge", []):
            dom = m.metadata.get("domain", "")
            if dom:
                domain_scores[dom] = domain_scores.get(dom, 0.0) + 1.5
        decay = [0.6, 0.4, 0.2]
        for i, turn in enumerate(reversed(self.turn_history[-3:])):
            td = turn.get("domain", "general")
            if td and td != "general":
                w = decay[i] if i < len(decay) else 0.1
                domain_scores[td] = domain_scores.get(td, 0.0) + w
        specific = {{k: v for k, v in domain_scores.items() if k != "general"}}
        if specific: domain_scores = specific
        if not domain_scores: return ("general", 0.0, True)
        best = max(domain_scores, key=domain_scores.get)
        conf = domain_scores[best] / max(sum(domain_scores.values()), 0.001)
        ambiguous = domain_scores[best] < 0.3
        return (best, round(conf, 3), ambiguous)

    def _resolve_compartment(self, intent, domain, matched):
        if intent in ("greeting", "farewell", "acknowledgment"):
            return SemanticCompartment.CONVERSATIONAL
        if intent == "narrative":
            tech = len(matched.get("verbs", [])) + len(matched.get("knowledge", []))
            if tech > 2: return SemanticCompartment.TECHNICAL
            return SemanticCompartment.CONVERSATIONAL
        if domain in TECHNICAL_DOMAINS: return SemanticCompartment.TECHNICAL
        tech = len(matched.get("verbs", [])) + len(matched.get("classes", [])) + len(matched.get("knowledge", []))
        if tech > len(matched.get("speech", [])) and tech > 2: return SemanticCompartment.TECHNICAL
        return SemanticCompartment.CONVERSATIONAL

    def respond(self, user_text):
        tokens = self._tokenize(user_text)
        matched = {{"dict": [], "verbs": [], "classes": [], "knowledge": []}}
        for token in tokens:
            if token in self.dict_terms:
                matched["dict"].append(self.dict_terms[token])
            if token in self.verb_funcs:
                matched["verbs"].extend(self.verb_funcs[token][:3])
            if token in self.class_tax:
                matched["classes"].append(self.class_tax[token])
            if token in self.knowledge_sections:
                matched["knowledge"].extend(self.knowledge_sections[token][:3])

        intent = self._detect_intent(tokens, user_text)

        # T14: Multi-domain token attribution
        attributions = self._attribute_tokens(tokens, matched)
        domain_vector = self._compute_multi_domain_weights(attributions)
        domain = domain_vector.get("primary", "general")
        domain_conf = max(domain_vector.get("impl_confidence", 0.5),
                          domain_vector.get("subj_confidence", 0.5))
        domain_ambiguous = domain_vector.get("ambiguous", False)
        self.active_domain = domain
        self._last_domain_vector = domain_vector

        # T14: Probe check
        probe_result = self.probe_engine.evaluate(tokens, domain_vector, matched)

        compartment = self._resolve_compartment(intent, domain, matched)

        matched_tokens = set()
        for p in matched["dict"]:
            matched_tokens.add(p.metadata.get("term", "").lower())
        for t in tokens:
            if t in self.verb_funcs or t in self.class_tax or t in self.knowledge_sections:
                matched_tokens.add(t)
        gap = max(0.0, 1.0 - len(matched_tokens) / max(len(tokens), 1))
        self.confidence = min(1.0, self.confidence * 0.7 + (1.0 - gap) * 0.3 + 0.1)

        # Intent-aware preset
        if intent in ("greeting", "farewell", "acknowledgment"): preset = "SHORT"
        elif intent == "narrative": preset = "STORY"
        elif intent == "help": preset = "LONG_EXPLAIN"
        elif gap > 0.8: preset = "MEDIUM_Q"
        elif gap > 0.5: preset = "MEDIUM_STMT"
        else: preset = "LONG_EXPLAIN"

        # Conversational intent → direct response
        if intent in ("greeting", "farewell", "acknowledgment"):
            fallback = {{"greeting": "Hello. How can I help?",
                        "farewell": "Goodbye. Session recorded.",
                        "acknowledgment": "Understood."}}
            for p in self.db.patterns.values():
                if (p.pattern_type == PatternType.SPEECH_PATTERN and
                        p.metadata.get("response_type", "") == intent):
                    response = p.metadata.get("text", fallback.get(intent, ""))
                    break
            else:
                response = fallback.get(intent, "")
            self.turn_history.append({{"user": user_text, "response": response, "domain": domain,
                                      "impl_domain": domain_vector.get("implementation_domain", domain),
                                      "subj_domain": domain_vector.get("subject_domain", domain)}})
            return {{"response": response, "gap": round(gap, 3), "domain": domain,
                    "preset": preset, "confidence": round(self.confidence, 3),
                    "intent": intent, "compartment": compartment,
                    "domain_confidence": domain_conf, "domain_ambiguous": domain_ambiguous,
                    "implementation_domain": domain_vector.get("implementation_domain", domain),
                    "subject_domain": domain_vector.get("subject_domain", domain),
                    "probe": probe_result if probe_result.get("should_probe") else None,
                    "tokens": len(tokens), "matched": len(matched_tokens)}}

        parts = []
        activated = []  # T15: [(pid, ftype)]
        # Knowledge entries (prioritized in TECHNICAL compartment)
        if matched["knowledge"]:
            seen_k = set()
            for p in matched["knowledge"][:3]:
                title = p.metadata.get("title", "")
                if not title or title in seen_k: continue
                seen_k.add(title)
                summary = p.metadata.get("summary", "")
                code_ex = p.metadata.get("code_example", "")
                if code_ex and preset in ("LONG_EXPLAIN", "STORY"):
                    parts.append(f"{{title}}: {{code_ex[:100]}}")
                elif summary:
                    parts.append(f"{{title}}: {{summary[:120]}}")
                else:
                    parts.append(title)
                activated.append((p.pattern_id, "knowledge"))

        # Dictionary defs — suppress general domain in TECHNICAL compartment if knowledge matched
        dict_matches = matched["dict"]
        if compartment == SemanticCompartment.TECHNICAL and matched["knowledge"]:
            dict_matches = [p for p in dict_matches if p.metadata.get("domain", "general") != "general"]

        skip = {{"the", "an", "is", "are", "do", "does", "tell", "me", "about", "how", "what", "why", "and", "or", "of"}}
        content_defs = [p for p in dict_matches if p.metadata.get("term", "").lower() not in skip]
        if not content_defs:
            content_defs = dict_matches[:2]

        if content_defs and preset in ("LONG_EXPLAIN", "MEDIUM_STMT", "STORY"):
            key_defs = []
            for p in content_defs[:4]:
                term = p.metadata.get("term", "")
                defn = p.metadata.get("definition", "")
                if term and defn:
                    defn = re.sub(r"^\\d+\\.\\s*", "", defn).strip()
                    sents = defn.split(". ")
                    defn = sents[0].strip()
                    if len(defn) < 10 and len(sents) > 1:
                        defn = ". ".join(sents[:2]).strip()
                    key_defs.append(f"{{term.capitalize()}}: {{defn}}")
                    activated.append((p.pattern_id, "definition"))
            if key_defs:
                parts.append(". ".join(key_defs) + ".")

        if matched["verbs"]:
            actions = set()
            for p in matched["verbs"][:5]:
                func = p.metadata.get("name", "")
                if func:
                    actions.add(func.replace("_", " ").strip())
                    activated.append((p.pattern_id, "action"))
            if actions:
                parts.append(f"Related: {{', '.join(sorted(actions)[:5])}}.")

        if matched["classes"]:
            seen = set()
            for p in matched["classes"][:3]:
                cls = p.metadata.get("name", "")
                if cls in seen: continue
                seen.add(cls)
                methods = p.metadata.get("methods", [])
                bases = p.metadata.get("bases", [])
                if cls and bases:
                    parts.append(f"{{cls}} extends {{', '.join(bases[:2])}}.")
                elif cls and methods:
                    parts.append(f"{{cls}}: [{{', '.join(methods[:5])}}].")
                activated.append((p.pattern_id, "structure"))

        if not parts:
            parts.append(f"No strong match in {{domain}} domain. Gap: {{gap:.0%}}")

        self._last_activated_pids = activated
        # T16: Stash candidates for session log
        self._last_candidates = [(parts[i][:60] if i < len(parts) else "", 1.0,
                                   activated[i][0][:12] if i < len(activated) else "",
                                   activated[i][1] if i < len(activated) else "")
                                  for i in range(min(len(parts), len(activated), 10))]

        response = " ".join(parts)
        max_words = self.PRESETS.get(preset, {{}}).get("max_tokens", 60)
        words = response.split()
        if len(words) > max_words:
            response = " ".join(words[:max_words]) + "..."

        # T14: Prepend probe text if probe fired
        if probe_result.get("should_probe"):
            response = probe_result["probe_text"] + " " + response

        self.turn_history.append({{"user": user_text, "response": response, "domain": domain,
                                  "impl_domain": domain_vector.get("implementation_domain", domain),
                                  "subj_domain": domain_vector.get("subject_domain", domain)}})

        # T15: Auto-grade + alpha feedback
        grade_result = self.grade_response(user_text, response)
        grade = grade_result.get("grade", "C")
        for pid, ftype in self._last_activated_pids:
            self.alpha_mem.record_outcome(pid, grade)

        # T16: Compute turn metrics
        turn_metrics = self._compute_turn_metrics(grade_result, domain_vector,
                                                   self._last_activated_pids, gap, domain_ambiguous)
        # T16: Log session
        result = {{"response": response, "gap": round(gap, 3), "domain": domain,
                "preset": preset, "confidence": round(self.confidence, 3),
                "intent": intent, "compartment": compartment,
                "domain_confidence": domain_conf, "domain_ambiguous": domain_ambiguous,
                "implementation_domain": domain_vector.get("implementation_domain", domain),
                "subject_domain": domain_vector.get("subject_domain", domain),
                "domain_vector": domain_vector,
                "probe": probe_result if probe_result.get("should_probe") else None,
                "tokens": len(tokens), "matched": len(matched_tokens),
                "grade": grade, "grade_score": grade_result.get("score", 0.0),
                "grade_metrics": grade_result.get("metrics", {{}}),
                "activated_patterns": len(self._last_activated_pids),
                "alpha_entries": len(self.alpha_mem.performance),
                "sr_line": turn_metrics.sr_line,
                "token_line": turn_metrics.token_line,
                "gate": turn_metrics.gate,
                "turn_metrics": turn_metrics.to_dict(),
                "thought_strategy": "",
                "gap_ratio": round(gap, 3),
                "instance_swapped": False}}
        if getattr(self, "_last_thought_log", None):
            best = max(self._last_thought_log, key=lambda t: t.get("score", 0))
            result["thought_strategy"] = best.get("strategy", "")
        self._log_session(user_text, response, result, turn_metrics, grade_result)
        self.save_session()
        return result

    def grade_response(self, user_text, response):
        inp = set(self._tokenize(user_text))
        resp = set(self._tokenize(response))
        coverage = len(inp & resp) / max(len(inp), 1) if inp else 0.0
        known = sum(1 for t in resp if t in self.dict_terms or t in self.verb_funcs or t in self.class_tax)
        coherence = known / max(len(resp), 1)
        relevance = min(1.0, coherence + coverage) / 2.0
        score = coverage * 0.25 + coherence * 0.35 + relevance * 0.15 + self.confidence * 0.25
        if score >= 0.8: grade = "A"
        elif score >= 0.65: grade = "B"
        elif score >= 0.45: grade = "C"
        elif score >= 0.3: grade = "D"
        else: grade = "F"
        return {{"grade": grade, "score": round(score, 3), "metrics": {{
            "coverage": round(coverage, 3), "coherence": round(coherence, 3)}}}}

    def _compute_turn_metrics(self, grade_result, domain_vector, activated_pids,
                               gap_ratio, domain_ambiguous):
        turn_num = len(self.turn_history)
        metrics = grade_result.get("metrics", {{}})
        impl_conf = domain_vector.get("impl_confidence", 0.5)
        subj_conf = domain_vector.get("subj_confidence", 0.5)
        entropy = 1.0 - max(impl_conf, subj_conf)
        coherence = metrics.get("coherence", 0.0)
        ema_vals = [self.alpha_mem.performance.get(p[0] if isinstance(p, (list, tuple)) else p, {{}}).get("ema", 0.5)
                    for p in activated_pids]
        resonance = sum(ema_vals) / max(len(ema_vals), 1)
        drift = 0.0
        if hasattr(self, "_prev_metrics") and self._prev_metrics is not None:
            prev_impl = getattr(self, "_prev_impl_domain", "general")
            if domain_vector.get("implementation_domain", "general") != prev_impl:
                drift += 0.5
            prev_subj = getattr(self, "_prev_subj_domain", "general")
            if domain_vector.get("subject_domain", "general") != prev_subj:
                drift += 0.5
        evidence = grade_result.get("score", 0.0)
        domain_risk = min(1.0, gap_ratio * (1.5 if domain_ambiguous else 1.0))
        self_assess = coherence
        if evidence >= 0.65 and domain_risk <= 0.35 and drift <= 0.15:
            gate = "G"
        elif evidence >= 0.45 and domain_risk <= 0.55 and drift <= 0.35:
            gate = "Y"
        else:
            gate = "R"
        h_delta = c_delta = r_delta = d_delta = 0.0
        if hasattr(self, "_prev_metrics") and self._prev_metrics is not None:
            prev = self._prev_metrics
            h_delta = entropy - prev.entropy
            c_delta = coherence - prev.coherence
            r_delta = resonance - prev.resonance
            d_delta = drift - prev.drift
        tm = TurnMetrics(turn_num, round(entropy, 3), round(coherence, 3),
                         round(resonance, 3), round(drift, 3), round(evidence, 3),
                         round(domain_risk, 3), round(self_assess, 3), gate,
                         round(h_delta, 3), round(c_delta, 3), round(r_delta, 3), round(d_delta, 3))
        self._prev_metrics = tm
        self._prev_impl_domain = domain_vector.get("implementation_domain", "general")
        self._prev_subj_domain = domain_vector.get("subject_domain", "general")
        return tm

    def _log_session(self, user_text, response_text, result, metrics, grade_result, instance=None):
        ts = datetime.datetime.now().strftime("%Y-%m-%dT%H:%M:%S")
        lines = [
            "=" * 60,
            f"=== Turn {{metrics.turn}} | {{ts}} ===",
            f'Input: "{{user_text[:120]}}"',
            metrics.sr_line,
            metrics.token_line,
            f"Grade: {{grade_result.get('grade', '?')}} ({{grade_result.get('score', 0):.3f}}) | "
            f"Activated: {{len(self._last_activated_pids)}} | Alpha: {{len(self.alpha_mem.performance)}}",
        ]
        if hasattr(self, "_last_thought_log") and self._last_thought_log:
            lines.append("Thought String:")
            for entry in self._last_thought_log:
                name = entry.get("strategy", "?")
                sc = entry.get("score", 0.0)
                np_ = entry.get("parts", 0)
                marker = " <- selected" if name == result.get("thought_strategy", "") else ""
                lines.append(f"  {{name:18s}} {{sc:.3f}} ({{np_}} parts){{marker}}")
        if hasattr(self, "_last_candidates") and self._last_candidates:
            lines.append("Top Candidates:")
            for text, sc, pid, ftype in self._last_candidates[:8]:
                ema = self.alpha_mem.performance.get(pid, {{}}).get("ema", 0.5)
                lines.append(f"  {{pid[:12]:12s}} [{{ftype:10s}}] s={{sc:.2f}} a={{ema:.2f}}")
        lines.append("")
        session_txt = self._session_path.parent / "session.txt"
        try:
            with open(session_txt, "a") as f:
                f.write("\\n".join(lines) + "\\n")
        except OSError:
            pass
        # T21: Write to per-variant session directory
        _sm21 = getattr(self, '_session_mgr', None)
        if _sm21:
            try:
                _grade21 = grade_result.get('grade', '?')
                _sm21.write_chat_turn(user_text, response_text, ts, grade=_grade21)
                _sm21.write_metrics(metrics.to_dict() if hasattr(metrics, 'to_dict') else {{}})
            except Exception:
                pass

    def run_interactive(self):
        stats = f"{{len(self.db.patterns)}} patterns | {{len(self.dict_terms)}} terms | {{len(self.verb_funcs)}} verbs"
        print(f"\\nPattern Brain Chat ({{stats}})")
        print("Type 'quit' to exit, '/stats' for stats")
        print("-" * 60)
        while True:
            try:
                user = input("\\nYou: ").strip()
            except (EOFError, KeyboardInterrupt):
                print("\\nBye.")
                break
            if not user: continue
            if user.lower() == "quit":
                print(f"{{len(self.turn_history)}} turns. Bye.")
                break
            if user == "/stats":
                print(f"  Patterns: {{len(self.db.patterns)}} | Terms: {{len(self.dict_terms)}} | "
                      f"Verbs: {{len(self.verb_funcs)}} | Classes: {{len(self.class_tax)}} | "
                      f"Knowledge: {{len(self.knowledge_sections)}} | "
                      f"Confidence: {{self.confidence:.2f}}")
                continue
            r = self.respond(user)
            print(f"  {{r.get('sr_line', '')}}")
            print(f"  {{r.get('token_line', '')}}")
            print(f"  [grade: {{r.get('grade','?')}} ({{r.get('grade_score',0):.3f}}) | "
                  f"impl: {{r.get('implementation_domain','?')}} | subj: {{r.get('subject_domain','?')}} | "
                  f"activated: {{r.get('activated_patterns',0)}} | alpha: {{r.get('alpha_entries',0)}}]")
            print(f"Brain: {{r['response']}}")


