# T21: Session + Prior-Gen Bridge (spawn template)
class SessionManager:
    def __init__(self, script_path, session_name=None):
        self.script_path = Path(script_path)
        self.variant_stem = self.script_path.stem
        self.session_root = self.script_path.parent / 'session'
        self.session_root.mkdir(exist_ok=True)
        _name = session_name or self.variant_stem
        self.session_dir = self.session_root / _name
        self.session_dir.mkdir(exist_ok=True)
        _ts = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        self._chat_path = self.session_dir / f'chat_{{_ts}}.txt'
        self._debug_path = self.session_dir / f'debug_{{_ts}}.txt'
        self._chat_f = None
        self._debug_f = None
    def write_chat_turn(self, user, response, ts, grade='?'):
        try:
            if not self._chat_f:
                self._chat_f = open(self._chat_path, 'a', encoding='utf-8')
            self._chat_f.write(f"--- {{ts}} ---\\nIN: {{user}}\\nOUT: {{response}}\\nGRADE: {{grade}}\\n\\n")
            self._chat_f.flush()
        except OSError: pass
    def write_metrics(self, metrics_dict): pass
    def write_debug_event(self, event_type, detail):
        try:
            if not self._debug_f:
                self._debug_f = open(self._debug_path, 'a', encoding='utf-8')
            self._debug_f.write(f"[{{datetime.datetime.now().isoformat()}}] {{event_type}}: {{detail}}\\n")
            self._debug_f.flush()
        except OSError: pass
    def save_instance(self, state_dict): pass
    def read_prior_session(self, n): return None
    def list_sessions(self): return []
    def close(self):
        for _f in [self._chat_f, self._debug_f]:
            try:
                if _f: _f.close()
            except Exception: pass

class PriorGenBridge:
    def __init__(self, script_path):
        self.script_path = Path(script_path)
        self.variants_dir = self.script_path.parent
    def find_prior_gen(self, domain='debug'):
        import re as _re
        candidates = sorted(self.variants_dir.glob(f'specialist_{{domain}}_*.py'))
        _ts_pat = _re.compile(r'_(\d{{8}}_\d{{6}})\.py$')
        def _ts(p):
            m = _ts_pat.search(p.name); return m.group(1) if m else p.name
        current_ts = _ts(self.script_path)
        older = [p for p in candidates if _ts(p) < current_ts and p != self.script_path]
        return older[-1] if older else None
    def analyze(self, variant_path, traceback_str):
        return {{'issues': [], 'summary': 'Prior-gen bridge (spawn variant).'}}
    def format_display(self, analysis):
        return f"  Summary: {{analysis.get('summary','(none)')}}"
    def mark_broken(self, variant_path, reason, n=1):
        p = Path(variant_path)
        lines = [l for l in p.read_text().splitlines(keepends=True) if not l.startswith('# BROKEN[')]
        lines.insert(1, f'# BROKEN[{{n}}]: {{str(reason)[:80]}}\\n')
        p.write_text(''.join(lines))
    def get_broken_version(self, variant_path):
        for line in Path(variant_path).read_text().splitlines()[:5]:
            if line.startswith('# BROKEN['):
                try: return int(line.split('[')[1].split(']')[0])
                except Exception: return 1
        return 0
    def propose_spawn(self, variant_path, analysis): pass


def main():
    parser = argparse.ArgumentParser(description="Pattern Brain Chat — Standalone Variant: {name}")
    parser.add_argument("query", nargs="?", default=None, help="Single query (omit for interactive)")
    parser.add_argument("--pattern-file", default=None, help="External pattern JSON to load")
    parser.add_argument("--session", default=None, metavar="NAME",
                        help="Named session for isolated chat/metrics/debug logs")
    parser.add_argument("--analyze-tb", default=None, metavar="TB_FILE",
                        help="Run prior-gen traceback analysis (headless)")
    parser.add_argument("--target", default=None, metavar="VARIANT_PATH",
                        help="Target variant to analyze (with --analyze-tb)")
    parser.add_argument("--output-json", default=None, metavar="OUT_FILE",
                        help="Write analysis JSON (with --analyze-tb)")
    args = parser.parse_args()

    if args.pattern_file:
        db = PatternDatabase()
        with open(args.pattern_file) as f:
            db.load_embedded(json.load(f))
    else:
        db = _load_patterns()

    # T21: --analyze-tb headless mode
    if args.analyze_tb:
        _tb_text = Path(args.analyze_tb).read_text()
        _issues = []
        _sum = f"analyze-tb: {{len(_tb_text.splitlines())}} traceback lines"
        _result = {{'issues': _issues, 'summary': _sum, 'call_graph': {{}}}}
        _out = args.output_json
        if _out:
            Path(_out).write_text(json.dumps(_result, indent=2))
        else:
            print(json.dumps(_result, indent=2))
        sys.exit(0)

    # T21: Session directory manager
    _session_mgr = SessionManager(__file__, args.session)
    _session_mgr.write_debug_event('INIT', f"variant={{Path(__file__).stem}} patterns={{len(db.patterns)}}")

    chat = PatternBrainChat(db)
    chat._session_mgr = _session_mgr
    if args.query:
        r = chat.respond(args.query)
        print(f"  [gap: {{r['gap']:.2f}} | preset: {{r['preset']}} | conf: {{r['confidence']:.2f}}]")
        print(f"  {{r['response']}}")
    else:
        chat.run_interactive()
    _session_mgr.close()

