@dataclass
class TokenAttribution:
    token: str
    stem: str
    domain_weights: Dict[str, float]
    source_patterns: list
    is_implementation: bool = False
    is_subject: bool = False
    @property
    def primary_domain(self):
        return max(self.domain_weights, key=self.domain_weights.get) if self.domain_weights else "general"
    @property
    def ambiguous(self):
        vals = sorted(self.domain_weights.values(), reverse=True)
        return len(vals) >= 2 and (vals[0] - vals[1]) < 0.2

# T16: Per-turn diagnostic metrics
class TurnMetrics:
    def __init__(self, turn, entropy, coherence, resonance, drift,
                 evidence, domain_risk, self_assess, gate,
                 h_delta=0.0, c_delta=0.0, r_delta=0.0, d_delta=0.0):
        self.turn = turn
        self.entropy = entropy
        self.coherence = coherence
        self.resonance = resonance
        self.drift = drift
        self.evidence = evidence
        self.domain_risk = domain_risk
        self.self_assess = self_assess
        self.gate = gate
        self.h_delta = h_delta
        self.c_delta = c_delta
        self.r_delta = r_delta
        self.d_delta = d_delta

    @property
    def sr_line(self):
        return (f"SR:hΔ {{self.h_delta:+.2f}} cΔ {{self.c_delta:+.2f}} "
                f"rΔ {{self.r_delta:+.2f}} dΔ {{self.d_delta:+.2f}} | "
                f"E {{self.evidence:.2f}} D {{self.domain_risk:.2f}} "
                f"C {{self.self_assess:.2f}} | G={{self.gate}}")

    @property
    def token_line(self):
        return (f"[COH: {{self.coherence:.0%}}] [RES: {{self.resonance:.0%}}] "
                f"[ENT: {{self.entropy:.2f}}] [DRF: {{self.drift:.2f}}] "
                f"[EVI: {{self.evidence:.2f}}] [GATE: {{self.gate}}]")

    def to_dict(self):
        return {{
            "turn": self.turn, "entropy": self.entropy, "coherence": self.coherence,
            "resonance": self.resonance, "drift": self.drift, "evidence": self.evidence,
            "domain_risk": self.domain_risk, "self_assess": self.self_assess,
            "gate": self.gate, "h_delta": self.h_delta, "c_delta": self.c_delta,
            "r_delta": self.r_delta, "d_delta": self.d_delta,
        }}

class DomainLayerClassifier:
    IMPL_SIGNALS = frozenset({{
        "import", "class", "def", "function", "gui", "tkinter", "flask",
        "django", "api", "database", "sql", "build", "compile", "deploy",
        "test", "debug", "code", "script", "module", "package", "library",
        "framework", "install", "pip", "run", "execute", "program", "app",
        "application", "software", "develop", "implement",
    }})
    IMPL_DOMAINS = frozenset({{
        "programming", "gui", "web", "database", "network", "devops",
        "testing", "build", "packaging", "python", "regex", "os", "io", "file",
    }})
    @classmethod
    def classify(cls, attributions):
        impl_scores = {{}}
        subj_scores = {{}}
        for attr in attributions:
            for dom, weight in attr.domain_weights.items():
                if attr.is_implementation or dom in cls.IMPL_DOMAINS:
                    impl_scores[dom] = impl_scores.get(dom, 0.0) + weight
                else:
                    subj_scores[dom] = subj_scores.get(dom, 0.0) + weight
                if attr.is_implementation and attr.is_subject:
                    subj_scores[dom] = subj_scores.get(dom, 0.0) + weight * 0.5
        impl_domain = max(impl_scores, key=impl_scores.get) if impl_scores else "general"
        subj_domain = max(subj_scores, key=subj_scores.get) if subj_scores else "general"
        impl_total = sum(impl_scores.values()) or 1.0
        subj_total = sum(subj_scores.values()) or 1.0
        return {{
            "implementation_domain": impl_domain, "subject_domain": subj_domain,
            "impl_confidence": round(impl_scores.get(impl_domain, 0.0) / impl_total, 3),
            "subj_confidence": round(subj_scores.get(subj_domain, 0.0) / subj_total, 3),
            "impl_scores": impl_scores, "subj_scores": subj_scores,
        }}

@dataclass
class Pattern:
    pattern_id: str
    pattern_type: PatternType
    context_hash: str
    content_hash: str
    outcome: str
    metadata: Dict[str, Any] = field(default_factory=dict)
    first_seen: str = ""
    last_seen: str = ""
    occurrence_count: int = 1
    def to_dict(self):
        d = asdict(self)
        d["pattern_type"] = self.pattern_type.name
        return d

class PatternDatabase:
    def __init__(self):
        self.patterns: Dict[str, Pattern] = {{}}
    def load_from_file(self, path: Path):
        with open(path) as f:
            data = json.load(f)
        for pid, pdata in data.items():
            pdata["pattern_type"] = PatternType[pdata["pattern_type"]]
            self.patterns[pid] = Pattern(**pdata)
    def add_or_update(self, pattern: Pattern):
        if pattern.pattern_id in self.patterns:
            existing = self.patterns[pattern.pattern_id]
            existing.occurrence_count += 1
            existing.last_seen = datetime.datetime.now().isoformat()
        else:
            self.patterns[pattern.pattern_id] = pattern
    def get_patterns_by_type(self, ptype):
        return [p for p in self.patterns.values() if p.pattern_type == ptype]
    def save(self, path: Path):
        data = {{pid: p.to_dict() for pid, p in self.patterns.items()}}
        with open(path, "w") as f:
            json.dump(data, f)

