class OmegaState:
    def __init__(self, build_data: dict):
        self.signal_map = build_data.get("signal_map", [])
        self.presets = build_data.get("presets", {{}})
        self.confidence = 0.5
        self.active_domain = "general"
        self.active_preset = "MEDIUM_STMT"
        self.understanding = 0.5
        self.gap_severity = "medium"

    def select_preset(self, gap: float, understanding: float = 0.5,
                      interaction_type: str = "") -> str:
        self.understanding = understanding
        if gap > 0.8:
            self.gap_severity = "critical"
        elif gap > 0.5:
            self.gap_severity = "high"
        elif gap > 0.2:
            self.gap_severity = "medium"
        else:
            self.gap_severity = "low"
        for rule in self.signal_map:
            cond = rule.get("condition", "")
            if cond == "default":
                self.active_preset = rule.get("preset", "MEDIUM_STMT")
                break
            if f"gap_severity={{self.gap_severity}}" in cond:
                if "understanding_pct<0.2" in cond and understanding < 0.2:
                    self.active_preset = rule.get("preset", "MEDIUM_Q")
                    return self.active_preset
                elif "understanding_pct>=0.2" in cond and understanding >= 0.2:
                    self.active_preset = rule.get("preset", "LONG_EXPLAIN")
                    return self.active_preset
        return self.active_preset

    def get_epistemic(self, gap: float, matched: float) -> dict:
        return {{"gap_severity": self.gap_severity, "understanding_pct": self.understanding,
                "confidence": self.confidence, "active_domain": self.active_domain,
                "active_preset": self.active_preset, "matched_ratio": round(matched, 3)}}

    def update_confidence(self, gap: float):
        self.confidence = min(1.0, self.confidence * 0.7 + (1.0 - gap) * 0.3 + 0.1)

