class InstanceVariantState:
    def __init__(self, domain: str = "general"):
        self.domain_bias: dict = {{}}
        self.activated_patterns: dict = {{}}
        self.turn_count: int = 0
        self.variant_sha: str = ""
        self.primary_domain: str = domain
        self.structural_profile: dict = {{
            "avg_word_count": 0.0, "question_ratio": 0.0,
            "assert_weight": 0.5, "explain_weight": 0.3, "probe_weight": 0.2,
        }}
        # T13: Compartment + temporal tracking
        self.compartment_history: list = []
        self.compartment_bias: dict = {{}}
        self.domain_resolution_confidence: float = 0.5
        # T14: Multi-domain tracking
        self.domain_vector_history: list = []
        self.implementation_domain: str = "general"
        self.subject_domain: str = "general"
        # T15: Grade tracking for instance swap
        self.grade_history: list = []
        self.swap_count: int = 0
        self.swap_threshold: int = 3
        # T18: Action-state tracking
        self.action_history: list = []
        self.action_success_rate: dict = {{}}
        self.action_bias: dict = {{}}
        self._recompute_sha()

    def record_action_outcome(self, action, outcome, domain="general"):
        import datetime as _dt
        self.action_history.append({{"action": action, "outcome": outcome,
            "domain": domain, "timestamp": _dt.datetime.now().isoformat()}})
        if len(self.action_history) > 50:
            self.action_history = self.action_history[-50:]
        bucket = self.action_success_rate.setdefault(domain, {{"success": 0, "fail": 0}})
        if outcome in ("ok", "success", "0"):
            bucket["success"] += 1
        else:
            bucket["fail"] += 1
        a = 0.3
        old = self.action_bias.get(action, 0.5)
        sig = 1.0 if outcome in ("ok", "success", "0") else 0.0
        self.action_bias[action] = (1 - a) * old + a * sig
        self._recompute_sha()

    def get_action_profile(self):
        preferred = sorted(self.action_bias.items(), key=lambda x: x[1], reverse=True)[:5]
        rates = {{}}
        for domain, bucket in self.action_success_rate.items():
            total = bucket["success"] + bucket["fail"]
            rates[domain] = round(bucket["success"] / total, 3) if total else 0.0
        return {{"preferred_actions": [{{"action": a, "bias": round(b, 3)}} for a, b in preferred],
                "success_rate_by_domain": rates, "total_actions": len(self.action_history)}}

    def should_prefer_action(self, action_type, domain="general"):
        bias = self.action_bias.get(action_type, 0.5)
        bucket = self.action_success_rate.get(domain, {{}})
        total = bucket.get("success", 0) + bucket.get("fail", 0)
        if total == 0:
            return bias
        return round((bias + bucket["success"] / total) / 2.0, 3)

    def record_grade(self, grade, score=0.0):
        self.grade_history.append(grade)
        if len(self.grade_history) > 10:
            self.grade_history = self.grade_history[-10:]

    @property
    def should_swap(self):
        if len(self.grade_history) < self.swap_threshold:
            return False
        return all(g in ("D", "F") for g in self.grade_history[-self.swap_threshold:])

    def reset_for_swap(self):
        pre = {{"swap_number": self.swap_count, "variant_sha": self.variant_sha,
               "grade_history": list(self.grade_history), "turn_count": self.turn_count}}
        self.activated_patterns.clear()
        self.structural_profile = {{"avg_word_count": 0.0, "question_ratio": 0.0,
            "assert_weight": 0.5, "explain_weight": 0.3, "probe_weight": 0.2}}
        self.swap_count += 1
        self.grade_history.clear()
        self._recompute_sha()
        return pre

    def activate_pattern(self, pattern_id: str, domain: str, weight: float = 1.0):
        self.activated_patterns[pattern_id] = self.activated_patterns.get(pattern_id, 0.0) + weight
        self.domain_bias[domain] = self.domain_bias.get(domain, 0.0) + weight
        if self.domain_bias:
            self.primary_domain = max(self.domain_bias, key=self.domain_bias.get)
        self._recompute_sha()

    def record_compartment(self, compartment, weight=1.0):
        comp_val = compartment if isinstance(compartment, str) else str(compartment)
        self.compartment_history.append(comp_val)
        if len(self.compartment_history) > 10:
            self.compartment_history = self.compartment_history[-10:]
        a = 0.3
        old = self.compartment_bias.get(comp_val, 0.0)
        self.compartment_bias[comp_val] = (1 - a) * old + a * weight
        self._recompute_sha()

    def record_domain_resolution(self, domain, confidence):
        a = 0.3
        self.domain_resolution_confidence = (1 - a) * self.domain_resolution_confidence + a * confidence

    def record_domain_vector(self, domain_vector):
        self.implementation_domain = domain_vector.get("implementation_domain", "general")
        self.subject_domain = domain_vector.get("subject_domain", "general")
        self.domain_vector_history.append({{
            "impl": self.implementation_domain, "subj": self.subject_domain,
            "impl_conf": domain_vector.get("impl_confidence", 0.5),
            "subj_conf": domain_vector.get("subj_confidence", 0.5),
        }})
        if len(self.domain_vector_history) > 10:
            self.domain_vector_history = self.domain_vector_history[-10:]

    def update_structural_profile(self, response_text: str):
        wc = len(response_text.split())
        is_q = 1.0 if "?" in response_text else 0.0
        self.turn_count += 1
        a = 0.3
        self.structural_profile["avg_word_count"] = (1 - a) * self.structural_profile["avg_word_count"] + a * wc
        self.structural_profile["question_ratio"] = (1 - a) * self.structural_profile["question_ratio"] + a * is_q
        self._recompute_sha()

    def _recompute_sha(self):
        state_str = json.dumps({{"domain_bias": self.domain_bias, "turn_count": self.turn_count,
                                "profile": self.structural_profile}}, sort_keys=True)
        self.variant_sha = hashlib.sha256(state_str.encode()).hexdigest()[:16]

    def to_dict(self) -> dict:
        top = dict(sorted(self.activated_patterns.items(), key=lambda x: x[1], reverse=True)[:50])
        return {{"domain_bias": self.domain_bias, "activated_patterns": top,
                "turn_count": self.turn_count, "variant_sha": self.variant_sha,
                "primary_domain": self.primary_domain, "structural_profile": self.structural_profile,
                "compartment_history": self.compartment_history, "compartment_bias": self.compartment_bias,
                "domain_resolution_confidence": self.domain_resolution_confidence,
                "domain_vector_history": self.domain_vector_history,
                "implementation_domain": self.implementation_domain,
                "subject_domain": self.subject_domain,
                "grade_history": self.grade_history, "swap_count": self.swap_count,
                "action_history": self.action_history[-50:],
                "action_success_rate": self.action_success_rate,
                "action_bias": self.action_bias}}

