# T21: SESSION MANAGER + PRIOR-GEN BRIDGE (full-build template)
# ═══════════════════════════════════════════════════════════

class SessionManager:
    """Per-variant session directory with timestamped chat/metrics/debug logs."""
    def __init__(self, script_path, session_name=None):
        self.script_path = Path(script_path)
        self.variant_stem = self.script_path.stem
        self.session_root = self.script_path.parent / 'session'
        self.session_root.mkdir(exist_ok=True)
        _name = session_name or self.variant_stem
        self.session_dir = self.session_root / _name
        self.session_dir.mkdir(exist_ok=True)
        _ts = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        self._ts = _ts
        self._chat_path = self.session_dir / f'chat_{{_ts}}.txt'
        self._metrics_path = self.session_dir / f'metrics_{{_ts}}.jsonl'
        self._debug_path = self.session_dir / f'debug_{{_ts}}.txt'
        self._instance_path = self.session_dir / f'instance_{{_ts}}.json'
        self._chat_f = None
        self._metrics_f = None
        self._debug_f = None
    def _chat_fh(self):
        if not self._chat_f: self._chat_f = open(self._chat_path, 'a', encoding='utf-8')
        return self._chat_f
    def _metrics_fh(self):
        if not self._metrics_f: self._metrics_f = open(self._metrics_path, 'a', encoding='utf-8')
        return self._metrics_f
    def _debug_fh(self):
        if not self._debug_f: self._debug_f = open(self._debug_path, 'a', encoding='utf-8')
        return self._debug_f
    def write_chat_turn(self, user, response, ts, grade='?'):
        try:
            self._chat_fh().write(f"--- {{ts}} ---\\nIN: {{user}}\\nOUT: {{response}}\\nGRADE: {{grade}}\\n\\n")
            self._chat_fh().flush()
        except OSError: pass
    def write_metrics(self, metrics_dict):
        try:
            self._metrics_fh().write(json.dumps(metrics_dict) + '\\n')
            self._metrics_fh().flush()
        except OSError: pass
    def write_debug_event(self, event_type, detail):
        try:
            _ts = datetime.datetime.now().isoformat()
            self._debug_fh().write(f"[{{_ts}}] {{event_type}}: {{detail}}\\n")
            self._debug_fh().flush()
        except OSError: pass
    def save_instance(self, state_dict):
        try: self._instance_path.write_text(json.dumps(state_dict, indent=2))
        except OSError: pass
    def read_prior_session(self, session_name):
        _d = self.session_root / session_name
        if not _d.exists(): return None
        _files = sorted(_d.glob('instance_*.json'))
        if not _files: return None
        try: return json.loads(_files[-1].read_text())
        except Exception: return None
    def list_sessions(self):
        result = []
        for _d in sorted(self.session_root.iterdir()):
            if not _d.is_dir(): continue
            _mf = sorted(_d.glob('metrics_*.jsonl'))
            _tc = 0
            for _f in _mf:
                try: _tc += len(_f.read_text().splitlines())
                except Exception: pass
            result.append((_d.name, _tc, 0.0, _mf[-1].name if _mf else 'none'))
        return result
    def close(self):
        for _f in [self._chat_f, self._metrics_f, self._debug_f]:
            try:
                if _f: _f.close()
            except Exception: pass


class PriorGenBridge:
    """Discovers prior-gen debug specialist and routes tracebacks for analysis."""
    def __init__(self, script_path):
        self.script_path = Path(script_path)
        self.variants_dir = self.script_path.parent
    def find_prior_gen(self, domain='debug'):
        import re as _re
        candidates = sorted(self.variants_dir.glob(f'specialist_{{domain}}_*.py'))
        _ts_pat = _re.compile(r'_(\d{{8}}_\d{{6}})\.py$')
        def _ts(p):
            m = _ts_pat.search(p.name); return m.group(1) if m else p.name
        current_ts = _ts(self.script_path)
        older = [p for p in candidates if _ts(p) < current_ts and p != self.script_path]
        return older[-1] if older else None
    def analyze(self, variant_path, traceback_str):
        import subprocess as _sp, tempfile as _tf
        prior = self.find_prior_gen('debug')
        if not prior: return {{'issues': [], 'summary': 'No prior-gen debug specialist found.'}}
        with _tf.NamedTemporaryFile(mode='w', suffix='.tb', delete=False) as _tbf:
            _tbf.write(traceback_str); _tb_path = _tbf.name
        with _tf.NamedTemporaryFile(mode='w', suffix='.json', delete=False) as _of:
            _out_path = _of.name
        try:
            _r = _sp.run(['python3', str(prior), '--analyze-tb', _tb_path,
                          '--target', str(variant_path), '--output-json', _out_path],
                         capture_output=True, text=True, timeout=90)
            if Path(_out_path).stat().st_size > 2:
                return json.loads(Path(_out_path).read_text())
            return {{'issues': [], 'summary': _r.stdout[-300:] or 'No output'}}
        except Exception as _e:
            return {{'issues': [], 'summary': f'Bridge error: {{_e}}'}}
        finally:
            for _p in [_tb_path, _out_path]:
                try: Path(_p).unlink()
                except Exception: pass
    def format_display(self, analysis):
        lines = ['', 'PRIOR-GEN ANALYSIS:']
        for issue in analysis.get('issues', [])[:8]:
            lines.append(f"  [{{issue.get('type','?')}}] {{issue.get('file','?')}}:{{issue.get('line','?')}} conf={{issue.get('confidence',0):.2f}}")
            lines.append(f"    Problem: {{issue.get('desc','')}}")
            if issue.get('suggestion'): lines.append(f"    Fix:     {{issue['suggestion']}}")
        lines.append(f"  Summary: {{analysis.get('summary','(none)')}}")
        return '\\n'.join(lines)
    def mark_broken(self, variant_path, reason, n=1):
        p = Path(variant_path); src = p.read_text()
        tag = f'# BROKEN[{{n}}]: {{str(reason)[:80]}}\\n'
        lines = [l for l in src.splitlines(keepends=True) if not l.startswith('# BROKEN[')]
        lines.insert(1, tag); p.write_text(''.join(lines))
    def get_broken_version(self, variant_path):
        for line in Path(variant_path).read_text().splitlines()[:5]:
            if line.startswith('# BROKEN['):
                try: return int(line.split('[')[1].split(']')[0])
                except Exception: return 1
        return 0
    def propose_spawn(self, variant_path, analysis):
        import subprocess as _sp
        import json as _jfix
        _n = self.get_broken_version(variant_path)
        _mf = self.variants_dir.parent / 'py_manifest_augmented.py'
        if _mf.exists():
            print(f'  [BRIDGE] Requesting corrected spawn (fix{{_n}})...')
            _r = _sp.run(['python3', str(_mf), 'variant', '--omega', '--name', f'omega_fix{{_n}}'],
                         capture_output=True, text=True, timeout=120)
            print(_r.stdout[-400:] if _r.stdout else '  (no output)')
            _log_path_fix = self.variants_dir / 'spawn_log.jsonl'
            with open(_log_path_fix, 'a') as _lf_fix:
                _lf_fix.write(_jfix.dumps({{
                    'ts': datetime.datetime.now().isoformat(),
                    'event': 'fix_spawn',
                    'name': f'omega_fix{{_n}}',
                    'domain': None,
                    'pattern_count': None,
                    'script': None,
                    'duration_s': None,
                    'outcome': 'ok' if _r.returncode == 0 else 'error',
                    'error': _r.stderr[-200:] if _r.returncode != 0 and _r.stderr else None,
                    'broken_from': str(variant_path),
                    'parent': None,
                }}) + '\\n')
        else:
            print('  [BRIDGE] Cannot find py_manifest_augmented.py to respawn.')


# ═══════════════════════════════════════════════════════════
# TOOLKIT DISPATCHER (Command Registry + Handlers)
# ═══════════════════════════════════════════════════════════

class ToolkitDispatcher:
    def __init__(self, db: PatternDatabase, omega: OmegaState,
                 chat: PatternBrainChat, trainer: TrainingEngine,
                 plan: PlanViewer, build_data: dict):
        self.db = db
        self.omega = omega
        self.chat = chat
        self.trainer = trainer
        self.plan = plan
        self.tool_registry = build_data.get("tool_registry", [])
        self.build_data = build_data

    def dispatch(self, cmd_str: str) -> bool:
        parts = cmd_str.strip().split(None, 1)
        if not parts:
            return True
        cmd = parts[0].lower()
        arg = parts[1] if len(parts) > 1 else ""

        if cmd in ("quit", "exit", "q"):
            return False
        elif cmd == "chat":
            self._cmd_chat(arg)
        elif cmd == "explain":
            self._cmd_explain(arg)
        elif cmd == "plan":
            self._cmd_plan(arg)
        elif cmd == "train":
            self._cmd_train(arg)
        elif cmd == "tools":
            self._cmd_tools(arg)
        elif cmd == "assess":
            self._cmd_assess(arg)
        elif cmd == "weights":
            self.trainer.show_weights()
        elif cmd == "stats":
            self._cmd_stats()
        elif cmd == "instance":
            self._cmd_instance()
        elif cmd == "action":
            self._cmd_action(arg)
        elif cmd == "suggest":
            self._cmd_suggest(arg)
        elif cmd == "generate":
            self._cmd_generate(arg)
        elif cmd == "ingest":
            self._cmd_ingest(arg)
        elif cmd == "intent":
            self._cmd_intent(arg)
        elif cmd == "gaps":
            self._cmd_gaps(arg)
        elif cmd == "measure":
            self._cmd_measure(arg)
        elif cmd == "act":
            self._cmd_act(arg)
        elif cmd == "read":
            self._cmd_read(arg)
        elif cmd == "search":
            self._cmd_search(arg)
        elif cmd == "morph":
            self._cmd_morph(arg)
        elif cmd == "sessions":
            self._cmd_sessions(arg)
        elif cmd in ("parent-state", "parent_state"):
            self._cmd_parent_state(arg)
        elif cmd == "native":
            self._cmd_native(arg)
        elif cmd in ("ancestors", "ancestral"):
            self._cmd_ancestors(arg)
        elif cmd == "help":
            self._cmd_help()
        else:
            # Default: treat as chat
            self._cmd_chat(cmd_str)
        return True

    def _cmd_chat(self, text: str):
        if not text:
            print("  Usage: chat <text>")
            return
        r = self.chat.respond(text)
        print(f"  {{r.get('sr_line', '')}}")
        print(f"  {{r.get('token_line', '')}}")
        print(f"  [domain: {{r['domain']}} | impl: {{r.get('implementation_domain', '?')}} | "
              f"subj: {{r.get('subject_domain', '?')}} | {{r.get('compartment', '?')}} | "
              f"gap: {{r['gap']:.2f}} | sha: {{r.get('variant_sha', '')[:8]}}]")
        print(f"  [grade: {{r.get('grade', '?')}} ({{r.get('grade_score', 0):.3f}}) | "
              f"activated: {{r.get('activated_patterns', 0)}} | "
              f"alpha: {{len(self.chat.alpha_mem.performance)}} | "
              f"swapped: {{r.get('instance_swapped', False)}} | gate: {{r.get('gate', '?')}}]")
        if r.get("probe"):
            print(f"  [PROBE: {{r['probe'].get('probe_type', '?')}} → {{r['probe'].get('probe_text', '')}}]")
        print(f"  {{r['response']}}")

