    def _cmd_plan(self, arg: str):
        if arg.startswith("--diffs"):
            fn = arg.replace("--diffs", "").strip()
            self.plan.show_diffs(fn)
        elif arg.startswith("--assess"):
            fn = arg.replace("--assess", "").strip()
            self.plan.show_assess(fn)
        else:
            try:
                top = int(arg) if arg.isdigit() else 0
            except ValueError:
                top = 0
            self.plan.show_roadmap(top)

    def _cmd_train(self, arg: str):
        if arg == "--grade" or arg.startswith("--grade "):
            text = arg.replace("--grade", "").strip()
            if not text:
                print("  Usage: train --grade <text>")
                return
            for attempt in range(1, 4):
                r = self.chat.respond(text)
                g = self.chat.grade_response(text, r["response"])
                corrections = self.chat.omega_correct(text, r["response"], g)
                matched_ratio = r["matched"] / max(r["tokens"], 1)
                tr = self.trainer.train_from_response(r["gap"], matched_ratio, g["score"], corrections)
                m = g.get("metrics", {{}})
                print(f"  Attempt {{attempt}}: Grade {{g['grade']}} ({{g['score']}}) sha={{tr['sha']}}")
                if m:
                    print(f"    domain_coherence={{m.get('domain_coherence', 0):.2f}} "
                          f"structural={{m.get('structural_grade', 0):.2f}} "
                          f"instance_sha={{r.get('variant_sha', '')[:8]}}")
                if corrections["correction_count"] > 0:
                    for sig in corrections["signals"]:
                        print(f"    Omega: [{{sig['type']}}] {{sig['message']}}")
                if tr.get("correction_applied"):
                    print(f"    +{{tr.get('correction_signals', 0)}} weight corrections applied")
                if g["grade"] in ("A", "B"):
                    print(f"  Grade {{g['grade']}} achieved.")
                    break
            print()
        elif arg == "--show-weights":
            self.trainer.show_weights()
        elif arg:
            r = self.chat.respond(arg)
            matched_ratio = r["matched"] / max(r["tokens"], 1)
            associations = {{
                "domain_technical": 0.0, "domain_academic": 0.0, "domain_informal": 1.0,
                "understanding_pct": matched_ratio, "priority_pct": 0.5,
                "gap_severity_numeric": r["gap"], "recognized_ratio": matched_ratio,
                "pattern_match_count": min(1.0, matched_ratio * 2)
            }}
            tr = self.trainer.train_step(associations, [1.0, 0.0, matched_ratio])
            print(f"  Domain: {{r['domain']}} | Gap: {{r['gap']:.2f}} | "
                  f"Recognized: {{matched_ratio:.1%}} | SHA: {{tr['sha']}}")
        else:
            print("  Usage: train <text> | train --grade <text> | train --show-weights")

    def _cmd_tools(self, arg: str):
        tools = self.tool_registry
        if arg:
            tools = [t for t in tools if arg.lower() in t.get("name", "").lower()
                     or arg.lower() in t.get("category", "").lower()]
        if not tools:
            print("\\n  No tools found.\\n")
            return
        cats = {{}}
        for t in tools:
            c = t.get("category", "other")
            cats.setdefault(c, []).append(t)
        print(f"\\n  === TOOL REGISTRY ({{len(tools)}} tools) ===")
        for cat, cat_tools in sorted(cats.items()):
            print(f"\\n  [{{cat}}]")
            for t in cat_tools[:10]:
                args_str = " ".join(t.get("args", [])[:3])
                print(f"    {{t.get('icon', '')}} {{t.get('name', '?')}} — {{t.get('command', '?')}} {{args_str}}")
        print()

