    def _cmd_read(self, arg):
        """read <path> — Read a file and inject structured summary as chat context."""
        import ast as _ast, json as _json
        if not arg:
            print("  Usage: read <file_path>")
            return
        fpath = Path(arg.strip())
        if not fpath.exists():
            print(f"  File not found: {{fpath}}")
            return
        suffix = fpath.suffix.lower()
        try:
            if suffix == '.py':
                source = fpath.read_text(errors='replace')
                try:
                    tree = _ast.parse(source)
                    classes = [n.name for n in _ast.walk(tree) if isinstance(n, _ast.ClassDef)]
                    funcs = [n.name for n in _ast.walk(tree)
                             if isinstance(n, (_ast.FunctionDef, _ast.AsyncFunctionDef))
                             and not n.name.startswith('_')][:20]
                    imports = []
                    for n in _ast.walk(tree):
                        if isinstance(n, _ast.Import):
                            imports += [a.name.split('.')[0] for a in n.names]
                        elif isinstance(n, _ast.ImportFrom) and n.module:
                            imports.append(n.module.split('.')[0])
                    imports = list(dict.fromkeys(imports))[:15]
                    summary = (f"[Python: {{fpath.name}}]\\nClasses ({{len(classes)}}): "
                               + ', '.join(classes[:10]) + f"\\nFunctions ({{len(funcs)}}): "
                               + ', '.join(funcs[:15]) + "\\nImports: " + ', '.join(imports[:12]))
                except SyntaxError as e:
                    summary = f"[Python: {{fpath.name}}] SyntaxError: {{e}}"
            elif suffix in ('.md', '.markdown'):
                lines = fpath.read_text(errors='replace').split('\\n')
                sections = [l.strip() for l in lines if l.startswith('#')][:15]
                summary = f"[Markdown: {{fpath.name}}]\\nSections: " + '\\n'.join(sections[:12])
            elif suffix == '.json':
                data = _json.loads(fpath.read_text(errors='replace'))
                if isinstance(data, dict):
                    keys = list(data.keys())[:20]
                    summary = f"[JSON: {{fpath.name}}]\\nKeys ({{len(keys)}}): " + ', '.join(str(k) for k in keys)
                elif isinstance(data, list):
                    summary = f"[JSON: {{fpath.name}}]\\nList with {{len(data)}} items"
                else:
                    summary = f"[JSON: {{fpath.name}}]\\nValue: " + str(data)[:100]
            else:
                lines = fpath.read_text(errors='replace').split('\\n')[:50]
                summary = f"[Text: {{fpath.name}}]\\n" + '\\n'.join(lines)
        except Exception as e:
            print(f"  Read error: {{e}}")
            return
        # Store as IO_OBSERVATION pattern for generate_speech() context
        ctx_h = hashlib.sha256(f"read:{{fpath.name}}".encode()).hexdigest()[:16]
        cnt_h = hashlib.sha256(summary.encode()).hexdigest()[:16]
        pid = hashlib.sha256(f"{{ctx_h}}{{cnt_h}}READ".encode()).hexdigest()[:16]
        p = Pattern(pattern_id=pid, pattern_type=PatternType.IO_OBSERVATION,
                    context_hash=ctx_h, content_hash=cnt_h, outcome='file_read',
                    metadata={{'text': summary[:600], 'file': str(fpath),
                               'source': 'read_command', 'expires_after_turns': 3,
                               'turn_created': len(self.chat.turn_history), 'domain': 'general'}})
        self.db.add_or_update(p)
        print(summary[:400])
        print(f"  Context loaded from {{fpath.name}}. Use 'chat' to query it.")

    def _cmd_search(self, arg):
        """search <query> — Token-overlap search of pattern DB. Returns top-5 matches."""
        if not arg:
            print("  Usage: search <query>")
            return
        query_toks = set(arg.lower().split())
        scored = []
        for pid, p_obj in self.db.patterns.items():
            meta = p_obj.metadata if hasattr(p_obj, 'metadata') else {{}}
            p_type = p_obj.pattern_type.name if hasattr(p_obj, 'pattern_type') else ''
            text_parts = [meta.get('text',''), meta.get('term',''), meta.get('section',''),
                          meta.get('function',''), meta.get('name',''), meta.get('subcommand',''),
                          meta.get('trigger',''), meta.get('content','')[:100]]
            text = ' '.join(str(t) for t in text_parts if t)
            if not text.strip():
                continue
            tok_set = set(text.lower().split())
            overlap = len(query_toks & tok_set)
            if overlap >= 1:
                score = 0.3 + (overlap * 0.12)
                snippet = next((str(t) for t in text_parts if t), '')[:80]
                scored.append((score, pid, p_type, snippet))
        scored.sort(key=lambda x: -x[0])
        print(f"  Search: '{{arg}}' → {{len(scored)}} matches (showing top 5)")
        for rank, (score, pid, ptype, snippet) in enumerate(scored[:5], 1):
            print(f"  [{{rank}}] score={{score:.2f}} type={{ptype}} | {{snippet}}")
        if not scored:
            print("  No patterns matched. Try broader terms.")

    def _cmd_morph(self, arg=None):
        """morph — Show current morphological intersection state."""
        _chat = getattr(self, 'chat', self)
        sw = getattr(_chat, '_strategy_weights',
                     {{'deterministic': 0.5, 'probabilistic': 0.3, 'morphological': 0.2}})
        det_w = sw.get('deterministic', 0.5)
        prob_w = sw.get('probabilistic', 0.3)
        morph_w = sw.get('morphological', 0.2)
        last_ms = getattr(_chat, '_last_morph_state', None)
        prev_metrics = getattr(_chat, '_prev_metrics', None)
        last_gate = getattr(prev_metrics, 'gate', 'none') if prev_metrics else 'none'
        turn_n = len(getattr(_chat, 'turn_history', []))
        print(f"  Morphological Intersection State (turn {{turn_n}})")
        print("  " + "-" * 54)
        if last_ms:
            det_scores = last_ms.get('det_scores', {{}})
            prob_scores = last_ms.get('prob_scores', {{}})
            morph_scores = last_ms.get('morph_scores', {{}})
            det_top = next(iter(det_scores), '?')
            det_c = det_scores.get(det_top, 0.0)
            prob_top = next(iter(prob_scores), '?')
            prob_c = prob_scores.get(prob_top, 0.0)
            morph_top = next(iter(morph_scores), '?')
            morph_c = morph_scores.get(morph_top, 0.0)
            resolved = last_ms.get('resolved_domain', '?')
            conf = last_ms.get('confidence', 0.0)
            gap_th = last_ms.get('gap_threshold', 0.7)
            print(f"  Deterministic  : {{det_top:<14s}} conf={{det_c:.2f}}  w={{det_w:.2f}}")
            print(f"  Probabilistic  : {{prob_top:<14s}} conf={{prob_c:.2f}}  w={{prob_w:.2f}}")
            print(f"  Morphological  : {{morph_top:<14s}} conf={{morph_c:.2f}}  w={{morph_w:.2f}}")
            print("  " + "-" * 54)
            print(f"  Resolved       : {{resolved:<22s}} conf={{conf:.2f}}")
            print(f"  Gap threshold  : {{gap_th:.2f}} (domain-aware)")
        else:
            print("  No morph state yet. Run a chat turn first.")
        print(f"  Last Gate      : {{last_gate}}")
        print(f"  Next weights   : det={{det_w:.2f}} prob={{prob_w:.2f}} morph={{morph_w:.2f}}")

    def _cmd_sessions(self, arg=''):
        """sessions — list session dirs. sessions load <name> — load prior session."""
        _chat = getattr(self, 'chat', self)
        _sm = getattr(_chat, '_session_mgr', None)
        if not _sm:
            print('  No session manager active. Use --session <name> on startup.')
            return
        arg = (arg or '').strip()
        if arg.startswith('load '):
            _sess = arg[5:].strip()
            _prior = _sm.read_prior_session(_sess)
            if _prior:
                _th = _prior.get('grade_history', [])
                print(f"  Session {{_sess!r}}: domain={{_prior.get('primary_domain','?')}} turns={{_prior.get('turn_count',len(_th))}}")
            else:
                print(f"  Session {{_sess!r}} not found.")
            return
        _sessions = _sm.list_sessions()
        if not _sessions:
            print(f"  No sessions in {{_sm.session_root}} yet.")
            return
        print(f"  Sessions in {{_sm.session_root}}:")
        for _name, _tc, _ga, _last in _sessions:
            _marker = ' *' if _name == _sm.session_dir.name else ''
            print(f"    {{_name:<40}} turns={{_tc:>4}}  last={{_last}}{{_marker}}")

    def run_interactive(self):
        meta = self.build_data.get("spawn_meta", {{}})
        print(f"\\nFull Build Alpha: {{meta.get('name', 'unknown')}}")
        print(f"Patterns: {{len(self.db.patterns):,}} | "
              f"Tools: {{len(self.tool_registry)}} | "
              f"Roadmap: {{len(self.plan.items)}} items | "
              f"Diffs: {{len(self.plan.diffs)}}")
        print("Type 'help' for commands, 'quit' to exit")
        print("-" * 60)
        while True:
            try:
                cmd = input("\\nalpha> ").strip()
            except (EOFError, KeyboardInterrupt):
                print("\\nBye.")
                break
            if not cmd:
                continue
            if not self.dispatch(cmd):
                print(f"{{len(self.chat.turn_history)}} turns. Bye.")
                break

