class SessionManager:
    """Per-variant session directory with timestamped chat/metrics/debug logs."""
    def __init__(self, script_path, session_name=None):
        self.script_path = Path(script_path)
        self.variant_stem = self.script_path.stem
        self.session_root = self.script_path.parent / 'session'
        self.session_root.mkdir(exist_ok=True)
        _name = session_name or self.variant_stem
        self.session_dir = self.session_root / _name
        self.session_dir.mkdir(exist_ok=True)
        _ts = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        self._ts = _ts
        self._chat_path = self.session_dir / f'chat_{_ts}.txt'
        self._metrics_path = self.session_dir / f'metrics_{_ts}.jsonl'
        self._debug_path = self.session_dir / f'debug_{_ts}.txt'
        self._instance_path = self.session_dir / f'instance_{_ts}.json'
        self._chat_f = None
        self._metrics_f = None
        self._debug_f = None

    def _chat(self):
        if not self._chat_f:
            self._chat_f = open(self._chat_path, 'a', encoding='utf-8')
        return self._chat_f

    def _metrics(self):
        if not self._metrics_f:
            self._metrics_f = open(self._metrics_path, 'a', encoding='utf-8')
        return self._metrics_f

    def _debug(self):
        if not self._debug_f:
            self._debug_f = open(self._debug_path, 'a', encoding='utf-8')
        return self._debug_f

    def write_chat_turn(self, user, response, ts, grade='?'):
        try:
            self._chat().write(f"--- {ts} ---\\nIN: {user}\\nOUT: {response}\\nGRADE: {grade}\\n\\n")
            self._chat().flush()
        except OSError:
            pass

    def write_metrics(self, metrics_dict):
        try:
            self._metrics().write(json.dumps(metrics_dict) + '\\n')
            self._metrics().flush()
        except OSError:
            pass

    def write_debug_event(self, event_type, detail):
        try:
            _ts = datetime.datetime.now().isoformat()
            self._debug().write(f"[{_ts}] {event_type}: {detail}\\n")
            self._debug().flush()
        except OSError:
            pass

    def save_instance(self, state_dict):
        try:
            self._instance_path.write_text(json.dumps(state_dict, indent=2))
        except OSError:
            pass

    def read_prior_session(self, session_name):
        _d = self.session_root / session_name
        if not _d.exists():
            return None
        _files = sorted(_d.glob('instance_*.json'))
        if not _files:
            return None
        try:
            return json.loads(_files[-1].read_text())
        except Exception:
            return None

    def list_sessions(self):
        result = []
        for _d in sorted(self.session_root.iterdir()):
            if not _d.is_dir():
                continue
            _mf = sorted(_d.glob('metrics_*.jsonl'))
            _tc, _grades = 0, []
            for _f in _mf:
                try:
                    for _line in _f.read_text().splitlines():
                        try:
                            _m = json.loads(_line)
                            _tc += 1
                            if 'grade' in _m and isinstance(_m['grade'], (int, float)):
                                _grades.append(_m['grade'])
                        except Exception:
                            pass
                except Exception:
                    pass
            _ga = sum(_grades) / max(len(_grades), 1) if _grades else 0.0
            _last = _mf[-1].name if _mf else 'none'
            result.append((_d.name, _tc, round(_ga, 2), _last))
        return result

    def close(self):
        for _f in [self._chat_f, self._metrics_f, self._debug_f]:
            try:
                if _f:
                    _f.close()
            except Exception:
                pass


class PriorGenBridge:
    """Discovers prior-gen debug specialist and routes tracebacks for analysis."""
    def __init__(self, script_path):
        self.script_path = Path(script_path)
        self.variants_dir = self.script_path.parent

    def find_prior_gen(self, domain='debug'):
        """Find most recent specialist_{domain}_*.py older than current script."""
        import re as _re
        candidates = sorted(self.variants_dir.glob(f'specialist_{domain}_*.py'))
        _ts_pat = _re.compile(r'_(\d{8}_\d{6})\.py$')
        def _ts(p):
            m = _ts_pat.search(p.name); return m.group(1) if m else p.name
        current_ts = _ts(self.script_path)
        older = [p for p in candidates if _ts(p) < current_ts and p != self.script_path]
        return older[-1] if older else None

    def analyze(self, variant_path, traceback_str):
        """Run prior-gen specialist in --analyze-tb mode. Returns analysis dict."""
        import subprocess as _sp
        import tempfile as _tf
        import re as _re_ana
        # Inline regex parse — works even without a prior-gen debug specialist
        _TB_FRAME = _re_ana.compile(r'File "([^"]+)", line (\d+), in (\S+)')
        _TB_EXC = _re_ana.compile(r'^(\w[\w.]*(?:Error|Exception|Warning|Interrupt|Exit)[^:]*): (.+)$')
        _inline = []
        for _fp, _fl, _fn in _TB_FRAME.findall(traceback_str):
            _inline.append({'type': 'frame', 'file': _fp, 'line': int(_fl), 'func': _fn,
                            'confidence': 0.7, 'desc': f'in {_fn}()',
                            'suggestion': 'Inspect call at this frame'})
        _last_ln = traceback_str.strip().splitlines()[-1] if traceback_str.strip() else ''
        _exc_m = _TB_EXC.search(_last_ln)
        if _exc_m:
            _inline.append({'type': _exc_m.group(1), 'file': '?', 'line': 0,
                            'confidence': 1.0, 'desc': _exc_m.group(2),
                            'suggestion': f'Fix {_exc_m.group(1)}'})
        prior = self.find_prior_gen('debug')
        if not prior:
            return {'issues': _inline, 'summary': f'{len(_inline)} issues (inline regex; no debug specialist found)'}
        with _tf.NamedTemporaryFile(mode='w', suffix='.tb', delete=False) as _tbf:
            _tbf.write(traceback_str)
            _tb_path = _tbf.name
        with _tf.NamedTemporaryFile(mode='w', suffix='.json', delete=False) as _outf:
            _out_path = _outf.name
        try:
            _r = _sp.run(
                ['python3', str(prior),
                 '--analyze-tb', _tb_path,
                 '--target', str(variant_path),
                 '--output-json', _out_path],
                capture_output=True, text=True, timeout=90)
            if Path(_out_path).stat().st_size > 2:
                _sub = json.loads(Path(_out_path).read_text())
                # If subprocess found real issues, use those; else prefer inline regex frames
                if _sub.get('issues'):
                    # Merge: prepend inline frames so caller gets both TB context + AST findings
                    _sub['issues'] = _inline + _sub['issues']
                    return _sub
            return {'issues': _inline, 'summary': f'{len(_inline)} issues (inline regex + prior-gen)'}
        except Exception as _e:
            return {'issues': _inline, 'summary': f'Bridge error: {_e}'}
        finally:
            for _p in [_tb_path, _out_path]:
                try:
                    Path(_p).unlink()
                except Exception:
                    pass

    def format_display(self, analysis):
        lines = ['', '╔══════════════════ PRIOR-GEN ANALYSIS ══════════════════╗']
        for issue in analysis.get('issues', [])[:12]:
            _t = issue.get('type', '?')
            _f = issue.get('file', '?')
            _l = issue.get('line', '?')
            _d = issue.get('desc', '')
            _s = issue.get('suggestion', '')
            _c = issue.get('confidence', 0.0)
            lines.append(f'  [{_t}] {_f}:{_l} (conf={_c:.2f})')
            lines.append(f'    Problem:    {_d}')
            if _s:
                lines.append(f'    Suggestion: {_s}')
        cg = analysis.get('call_graph', {})
        if cg.get('crash_nodes'):
            lines.append(f"  Crash nodes: {', '.join(str(n) for n in cg['crash_nodes'][:5])}")
        lines.append(f"  Summary: {analysis.get('summary', '(none)')}")
        lines.append('╚══════════════════════════════════════════════════════════╝')
        return '\\n'.join(lines)

    def mark_broken(self, variant_path, reason, n=1):
        """Insert BROKEN[N] header comment into variant file."""
        p = Path(variant_path)
        src = p.read_text()
        tag = f'# BROKEN[{n}]: {str(reason)[:80]}\\n'
        src_lines = src.splitlines(keepends=True)
        src_lines = [l for l in src_lines if not l.startswith('# BROKEN[')]
        src_lines.insert(1, tag)
        p.write_text(''.join(src_lines))

    def get_broken_version(self, variant_path):
        for line in Path(variant_path).read_text().splitlines()[:5]:
            if line.startswith('# BROKEN['):
                try:
                    return int(line.split('[')[1].split(']')[0])
                except Exception:
                    return 1
        return 0

    def propose_spawn(self, variant_path, analysis):
        """Invoke py_manifest_augmented.py to spawn a corrected variant."""
        import subprocess as _sp
        import json as _jfix
        _n = self.get_broken_version(variant_path)
        _mf = self.variants_dir.parent / 'py_manifest_augmented.py'
        if _mf.exists():
            print(f'  [BRIDGE] Requesting corrected spawn (fix{_n}) from py_manifest_augmented...')
            _r = _sp.run(['python3', str(_mf), 'variant', '--omega',
                          '--name', f'omega_fix{_n}'],
                         capture_output=True, text=True, timeout=120)
            print(_r.stdout[-400:] if _r.stdout else '  (no output)')
            # Spawn log
            _log_path_fix = self.variants_dir / 'spawn_log.jsonl'
            with open(_log_path_fix, 'a') as _lf_fix:
                _lf_fix.write(_jfix.dumps({
                    'ts': datetime.datetime.now().isoformat(),
                    'event': 'fix_spawn',
                    'name': f'omega_fix{_n}',
                    'domain': None,
                    'pattern_count': None,
                    'script': None,
                    'duration_s': None,
                    'outcome': 'ok' if _r.returncode == 0 else 'error',
                    'error': _r.stderr[-200:] if _r.returncode != 0 and _r.stderr else None,
                    'broken_from': str(variant_path),
                    'parent': None,
                }) + '\\n')
        else:
            print(f'  [BRIDGE] Cannot find py_manifest_augmented.py to respawn.')

