    def _cmd_observe(self, arg):
        """Record an I/O observation for a command."""
        if not arg:
            print("  Usage: observe <command> | <input_desc> | <output_desc>")
            print("  Example: observe python3 Os_Toolkit.py suggest | none | task suggestions")
            return
        parts = [p.strip() for p in arg.split("|")]
        if len(parts) < 3:
            print("  Need: command | input | output  (pipe-separated)")
            return
        pid = self.io_registry.record_observation(parts[0], parts[1], parts[2])
        print(f"  Recorded IO_OBSERVATION: {pid}")
        effects = self.io_registry.get_command_effects(parts[0].split()[0])
        print(f"  Total observations for this command: {len(effects)}")
        self.db.save(Path(__file__).parent / _PATTERN_FILE)

