        _spawn_profile_obj = SpawnProfile(domain, _profile_name)
        if _spawn_profile_obj.pattern_whitelist is not None or _spawn_profile_obj.domain_speech_only:
            filtered = _spawn_profile_obj.filter_patterns(filtered)

        if not filtered:
            # Fall back to all patterns if no domain match
            filtered = {pid: p.to_dict() for pid, p in list(self.db.patterns.items())[:500]}
        elif len(filtered) < 200:
            # Supplement with general-purpose patterns — ungated (no count cap)
            # Size-capped at 500MB serialized to prevent runaway alpha files
            for pid, p_obj in self.db.patterns.items():
                if pid in filtered:
                    continue
                p_dict = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
                p_type = str(p_dict.get('pattern_type', ''))
                # Include structural pattern types useful across domains
                if any(t in p_type for t in ('MODULE_DOMAIN', 'GAP_SIGNAL', 'PYTHON_IDIOM',
                                              'ARG_ABSORPTION', 'EXEC_CHAIN', 'THOUGHT_CHAIN',
                                              'SCRATCH_CANDIDATE', 'WEIGHT_MIX')):
                    filtered[pid] = p_dict

