    def _cmd_absorbed(self, arg=None):
        """Show all ARG_ABSORPTION patterns grouped by script."""
        self._setup_action_router()
        routes = self.action_router.get_available_routes()
        if not routes:
            print("  No absorbed argparse structures found.")
            print("  Absorb parent scripts: ingest-script <path> then re-spawn")
            return
        filt = arg.strip().lower() if arg else None
        total_cmds = sum(len(cmds) for cmds in routes.values())
        print(f"  === ABSORBED ARGPARSE ({len(routes)} scripts, {total_cmds} subcommands) ===")
        for script, cmds in sorted(routes.items()):
            if filt and filt not in script.lower():
                cmds = [c for c in cmds if filt in c['subcommand'].lower() or filt in c['help'].lower()]
                if not cmds:
                    continue
            print(f"\\n  [{script}] ({len(cmds)} subcommands)")
            for c in cmds:
                help_short = c['help'][:60] if c['help'] else '(no help)'
                print(f"    {c['subcommand']:20s} ({c['args']} args) — {help_short}")
            # Show args detail for first few if filtered
            if filt:
                for c in cmds[:3]:
                    for p in self.db.get_patterns_by_type(PatternType.ARG_ABSORPTION):
                        m = p.metadata
                        if m.get('source_script') == script and m.get('subcommand') == c['subcommand']:
                            for arg_info in m.get('arguments', [])[:8]:
                                name = arg_info.get('name', '')
                                help_a = arg_info.get('help', '')[:50]
                                typ = arg_info.get('type', 'str')
                                print(f"      {name} ({typ}) — {help_a}")
        print()

    def _cmd_chains(self, arg=None):
        """Show exec chain for a command."""
        self._setup_action_router()
        if not arg:
            # List all chains
            chains = {}
            for p in self.db.get_patterns_by_type(PatternType.EXEC_CHAIN):
                m = p.metadata
                s = m.get('source_script', '')
                chains.setdefault(s, []).append(m.get('subcommand', ''))
            if not chains:
                print("  No exec chains mapped. Chains are built at spawn time.")
                return
            print(f"  === EXEC CHAINS ({sum(len(v) for v in chains.values())} mapped) ===")
            for script, subs in sorted(chains.items()):
                print(f"  [{script}]: {', '.join(subs)}")
            print("  Usage: chains <script> <subcommand>")
            return
        parts = arg.strip().split(None, 1)
        script_key = parts[0]
        subcmd = parts[1] if len(parts) > 1 else None
        # Find matching chains
        found = []
        for p in self.db.get_patterns_by_type(PatternType.EXEC_CHAIN):
            m = p.metadata
            src = m.get('source_script', '')
            sc = m.get('subcommand', '')
            if script_key.lower() in src.lower():
                if subcmd is None or subcmd.lower() in sc.lower():
                    found.append(m)
        if not found:
            print(f"  No chains found for: {arg!r}")
            return
        for chain in found[:5]:
            print(f"  [{chain['source_script']}] {chain['subcommand']}")
            print(f"    handler:    {chain.get('handler_function', '(unknown)')}")
            print(f"    call_chain: {' → '.join(chain.get('call_chain', [])[:8])}")
            imports = chain.get('imports_required', [])
            if imports:
                print(f"    imports:    {', '.join(imports[:6])}")
            print(f"    complexity: {chain.get('estimated_complexity', 0):.2f} (depth={chain.get('chain_depth', 0)})")

    def _cmd_read(self, arg):
        """read <path> — Read a file and inject content as chat context.
        Supported formats: .py (AST class/function/import summary), .md (section list),
        .json (top-level schema), .txt (first 50 lines).
        Content is stored as a short-lived IO_OBSERVATION pattern that generate_speech()
        uses as a high-priority context candidate for the next 3 turns."""
        import ast as _ast
        if not arg:
            print("  Usage: read <file_path>")
            print("  Supported: .py .md .json .txt")
            return
        fpath = Path(arg.strip())
        if not fpath.exists():
            print(f"  File not found: {fpath}")
            return
        suffix = fpath.suffix.lower()
        try:
            if suffix == '.py':
                source = fpath.read_text(errors='replace')
                try:
                    tree = _ast.parse(source)
                    classes = [n.name for n in _ast.walk(tree) if isinstance(n, _ast.ClassDef)]
                    funcs = [n.name for n in _ast.walk(tree)
                             if isinstance(n, (_ast.FunctionDef, _ast.AsyncFunctionDef))
                             and not n.name.startswith('_')][:20]
                    imports = []
                    for n in _ast.walk(tree):
                        if isinstance(n, _ast.Import):
                            imports += [a.name.split('.')[0] for a in n.names]
                        elif isinstance(n, _ast.ImportFrom) and n.module:
                            imports.append(n.module.split('.')[0])
                    imports = list(dict.fromkeys(imports))[:15]
                    summary = (f"[Python: {fpath.name}]\\n"
                               f"Classes ({len(classes)}): {', '.join(classes[:10])}\\n"
                               f"Functions ({len(funcs)}): {', '.join(funcs[:15])}\\n"
                               f"Imports: {', '.join(imports[:12])}")
                except SyntaxError as e:
                    summary = f"[Python: {fpath.name}] SyntaxError: {e}"
            elif suffix in ('.md', '.markdown'):
                lines = fpath.read_text(errors='replace').split('\\n')
                sections = [l.strip() for l in lines if l.startswith('#')][:15]
                summary = f"[Markdown: {fpath.name}]\\nSections ({len(sections)}): " + '\\n'.join(sections[:12])
            elif suffix == '.json':
                import json as _json
                data = _json.loads(fpath.read_text(errors='replace'))
                if isinstance(data, dict):
                    keys = list(data.keys())[:20]
                    summary = f"[JSON: {fpath.name}]\\nTop-level keys ({len(keys)}): {', '.join(str(k) for k in keys)}"
                elif isinstance(data, list):
                    summary = f"[JSON: {fpath.name}]\\nList with {len(data)} items"
                else:
                    summary = f"[JSON: {fpath.name}]\\nValue: {str(data)[:100]}"
            else:
                lines = fpath.read_text(errors='replace').split('\\n')[:50]
                summary = f"[Text: {fpath.name}]\\n" + '\\n'.join(lines)
        except Exception as e:
            print(f"  Read error: {e}")
            return
        # Store as IO_OBSERVATION pattern for generate_speech() to pick up
        ctx_h = hashlib.sha256(f"read:{fpath.name}".encode()).hexdigest()[:16]
        cnt_h = hashlib.sha256(summary.encode()).hexdigest()[:16]
        pid = hashlib.sha256(f"{ctx_h}{cnt_h}READ".encode()).hexdigest()[:16]
        p = Pattern(
            pattern_id=pid, pattern_type=PatternType.IO_OBSERVATION,
            context_hash=ctx_h, content_hash=cnt_h, outcome='file_read',
            metadata={
                'text': summary[:600],
                'file': str(fpath),
                'source': 'read_command',
                'expires_after_turns': 3,
                'turn_created': len(self.chat.turn_history),
                'domain': 'general',
            }
        )
        self.db.add_or_update(p)
        print(summary[:400])
        print(f"  Context loaded from {fpath.name}. Use 'chat' to query it.")

    def _cmd_search(self, arg):
        """search <query> — Token-overlap search of pattern DB.
        Returns top-5 matching patterns with score, type, and text snippet."""
        if not arg:
            print("  Usage: search <query>")
            return
        query_toks = set(self.chat._tokenize(arg)) if hasattr(self, 'chat') else set(arg.lower().split())
        scored = []
        for pid, p_obj in self.db.patterns.items():
            p_dict = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
            meta = p_dict.get('metadata', {})
            p_type = str(p_dict.get('pattern_type', ''))
            # Build searchable text from metadata fields
            text_parts = [
                meta.get('text', ''), meta.get('term', ''), meta.get('section', ''),
                meta.get('function', ''), meta.get('name', ''), meta.get('subcommand', ''),
                meta.get('trigger', ''), meta.get('content', '')[:100],
            ]
            text = ' '.join(str(t) for t in text_parts if t)
            if not text.strip():
                continue
            tok_set = set(text.lower().split())
            overlap = len(query_toks & tok_set)
            if overlap >= 1:
                score = 0.3 + (overlap * 0.12)
                snippet = next((str(t) for t in text_parts if t), '')[:80]
                scored.append((score, pid, p_type.split('.')[-1], snippet))
        scored.sort(key=lambda x: -x[0])
        print(f"  Search: '{arg}' -> {len(scored)} matches (showing top 5)")
        for rank, (score, pid, ptype, snippet) in enumerate(scored[:5], 1):
            print(f"  [{rank}] score={score:.2f} type={ptype} | {snippet}")
        if not scored:
            print("  No patterns matched. Try broader terms.")

    def _cmd_morph(self, arg=None):
        """morph — Show current morphological intersection state.
        Displays how deterministic, probabilistic, and morphological layers
        combine to resolve domain, and how gate feedback adapts strategy weights."""
        _chat = getattr(self, 'chat', self)
        sw = getattr(_chat, '_strategy_weights',
                     {'deterministic': 0.5, 'probabilistic': 0.3, 'morphological': 0.2})
        det_w = sw.get('deterministic', 0.5)
        prob_w = sw.get('probabilistic', 0.3)
        morph_w = sw.get('morphological', 0.2)
        last_ms = getattr(_chat, '_last_morph_state', None)
        prev_metrics = getattr(_chat, '_prev_metrics', None)
        last_gate = getattr(prev_metrics, 'gate', 'none') if prev_metrics else 'none'
        turn_n = len(getattr(_chat, 'turn_history', []))
        print("  ╔══════════════════════════════════════════════════════════╗")
        print(f"  ║  Morphological Intersection State  (turn {turn_n:<4d})          ║")
        print("  ╠══════════════════════════════════════════════════════════╣")
        if last_ms:
            det_scores = last_ms.get('det_scores', {})
            prob_scores = last_ms.get('prob_scores', {})
            morph_scores = last_ms.get('morph_scores', {})
            det_top = next(iter(det_scores), '?')
            det_c = det_scores.get(det_top, 0.0)
            prob_top = next(iter(prob_scores), '?')
            prob_c = prob_scores.get(prob_top, 0.0)
            morph_top = next(iter(morph_scores), '?')
            morph_c = morph_scores.get(morph_top, 0.0)
            resolved = last_ms.get('resolved_domain', '?')
            conf = last_ms.get('confidence', 0.0)
            gap_th = last_ms.get('gap_threshold', 0.7)
            print(f"  ║  Deterministic  : {det_top:<14s} conf={det_c:.2f}  w={det_w:.2f}       ║")
            print(f"  ║  Probabilistic  : {prob_top:<14s} conf={prob_c:.2f}  w={prob_w:.2f}       ║")
            print(f"  ║  Morphological  : {morph_top:<14s} conf={morph_c:.2f}  w={morph_w:.2f}       ║")
            print("  ╠══════════════════════════════════════════════════════════╣")
            print(f"  ║  Resolved       : {resolved:<22s} conf={conf:.2f}             ║")
            print(f"  ║  Gap threshold  : {gap_th:.2f}  (domain-aware)                    ║")
        else:
            print("  ║  No morph state yet. Run a chat turn first.             ║")
        print(f"  ║  Last Gate      : {last_gate}                                          ║")
        weight_str = f"det={det_w:.2f} prob={prob_w:.2f} morph={morph_w:.2f}"
        print(f"  ║  Next weights   : {weight_str:<37s}        ║")
        print("  ╚══════════════════════════════════════════════════════════╝")

    def _cmd_sessions(self, arg=''):
        """sessions — list all session dirs with turn counts and grade averages.
        sessions load <session_name> — load prior session instance state."""
        _chat = getattr(self, 'chat', self)
        _sm = getattr(_chat, '_session_mgr', None)
        if not _sm:
            print('  No session manager active. Use --session <name> on startup.')
            return
        arg = (arg or '').strip()
        if arg.startswith('load '):
            _sess_name = arg[5:].strip()
            _prior = _sm.read_prior_session(_sess_name)
            if _prior:
                _th = _prior.get('grade_history', [])
                _dom = _prior.get('primary_domain', '?')
                _tc = _prior.get('turn_count', len(_th))
                print(f'  Session {_sess_name!r}: domain={_dom} turns={_tc} grades={_th[-5:]}')
            else:
                print(f'  Session {_sess_name!r} not found in {_sm.session_root}')
            return
        _sessions = _sm.list_sessions()
        if not _sessions:
            print(f'  No sessions in {_sm.session_root} yet.')
            return
        print(f'  Sessions in {_sm.session_root}:')
        for _name, _tc, _ga, _last in _sessions:
            _marker = ' *' if _name == _sm.session_dir.name else ''
            print(f'    {_name:<40} turns={_tc:>4}  grade_avg={_ga:.2f}  last={_last}{_marker}')
        print(f'  Active session: {_sm.session_dir.name}')

    def _cmd_correct(self, arg):
        """Repeat-After-Me: record a correction for the last response as a high-weight speech pattern.

        This is the primary human-in-the-loop training signal. When the alpha/omega says
        something wrong or suboptimal, the user provides the preferred response here.
        The correction is stored as a SPEECH_PATTERN with high initial alpha_mem weight,
        so the pattern DB biases toward it for similar inputs going forward.

        Usage: correct <how I should have responded>
        """
        if not arg:
            if self.chat.turn_history:
                last = self.chat.turn_history[-1]
                print(f"  Last response: '{last.get('response','')[:120]}'")
                print(f"  Last input:    '{last.get('user','')[:80]}'")
            print("  Usage: correct <preferred response text>")
            print("  This stores your text as a high-weight speech pattern for this context.")
            return
        if not self.chat.turn_history:
            print("  No conversation history. Chat first, then correct a response.")
            return
        last = self.chat.turn_history[-1]
        user_input = last.get('user', '')
        domain = last.get('domain', getattr(self.chat, 'active_domain', None) or getattr(self.chat.omega, 'active_domain', 'general'))
        impl_domain = last.get('impl_domain', domain)
        prior_response = last.get('response', '')

        ctx_h = hashlib.sha256(f"RAM:{domain}:{user_input[:80]}".encode()).hexdigest()[:16]
        cnt_h = hashlib.sha256(arg.encode()).hexdigest()[:16]
        pid = hashlib.sha256(f"{ctx_h}{cnt_h}CORRECT".encode()).hexdigest()[:16]
        p = Pattern(
            pattern_id=pid,
            pattern_type=PatternType.SPEECH_PATTERN,
            context_hash=ctx_h,
            content_hash=cnt_h,
            outcome='user_corrected',
            metadata={
                'text': arg[:500],
                'label': 'user_correction',
                'domain': domain,
                'impl_domain': impl_domain,
                'source': 'repeat_after_me',
                'trigger': user_input[:100],
                'correction_of': prior_response[:100],
                'priority': 'high',
                'session_turn': len(self.chat.turn_history),
            }
        )
        self.db.add_or_update(p)
        # Boost alpha_mem weight to max via 5× 'A' grading (drives EMA → 1.0)
        for _ in range(5):
            self.chat.alpha_mem.record_outcome(pid, 'A')
        # T19: Boost token weight matrix with corrected sequence
        if hasattr(self.chat, '_twm') and self.chat._twm is not None:
            correction_tokens = self.chat._twm._tokenize(arg)
            if correction_tokens:
                self.chat._twm.boost_sequence(correction_tokens, domain, n_repeats=5)
        self.db.save(_PATTERN_FILE)
        self.chat.save_session()
        print(f"  [RAM] Correction stored: pid={pid[:8]}")
        print(f"  Trigger:   '{user_input[:70]}'")
        print(f"  Corrected: '{arg[:100]}'")
        w = self.chat.alpha_mem.get_weight(pid)
        print(f"  Weight: {w:.3f} (EMA boosted — will bias responses for this context)")

    def _cmd_repeat(self, arg=None):
        """Show last response and prompt for a correction (Repeat-After-Me loop).

        Usage: repeat
               Then type:  correct <preferred response>
        """
        if not self.chat.turn_history:
            print("  No conversation history yet.")
            return
        last = self.chat.turn_history[-1]
        print(f"  === LAST EXCHANGE ===")
        print(f"  You said:    '{last.get('user','')[:100]}'")
        print(f"  I responded: '{last.get('response','')[:200]}'")
        grade = last.get('grade', '?')
        gap = last.get('gap', 0)
        domain = last.get('domain', '?')
        print(f"  Grade: {grade} | Gap: {gap:.2f} | Domain: {domain}")
        pids = last.get('activated_pids', [])
        if pids:
            print(f"  Patterns used: {', '.join(pids[:4])}")
        print()
        print("  → To correct this response, type:  correct <your preferred text>")
        print("  → The correction becomes a high-weight speech pattern immediately.")

    def _cmd_teach(self, arg):
        """Teach the brain a direct input→output pair without needing a prior chat turn.

        Usage: teach <input text> | <desired output text>
        Uses | as separator between input trigger and desired output.
        """
        if '|' not in (arg or ''):
            print("  Usage: teach <input trigger> | <desired output>")
            print("  Example: teach hello there | Hi! Good to meet you.")
            return
        parts = arg.split('|', 1)
        trigger = parts[0].strip()
        response = parts[1].strip()
        if not trigger or not response:
            print("  Both trigger and response required.")
            return
        # Determine domain from trigger tokens
        tokens = set(self.chat._tokenize(trigger))
        domain = (getattr(self.chat, 'active_domain', None) or
                  getattr(self.chat.omega, 'active_domain', 'general'))
        ctx_h = hashlib.sha256(f"TEACH:{domain}:{trigger[:80]}".encode()).hexdigest()[:16]
        cnt_h = hashlib.sha256(response.encode()).hexdigest()[:16]
        pid = hashlib.sha256(f"{ctx_h}{cnt_h}TEACH".encode()).hexdigest()[:16]
        p = Pattern(
            pattern_id=pid,
            pattern_type=PatternType.SPEECH_PATTERN,
            context_hash=ctx_h,
            content_hash=cnt_h,
            outcome='user_taught',
            metadata={
                'text': response[:500],
                'label': 'user_taught',
                'domain': domain,
                'source': 'teach_command',
                'trigger': trigger[:100],
                'priority': 'high',
            }
        )
        self.db.add_or_update(p)
        for _ in range(3):
            self.chat.alpha_mem.record_outcome(pid, 'A')
        # T19: Boost TWM with taught response tokens
        if hasattr(self.chat, '_twm') and self.chat._twm is not None:
            teach_tokens = self.chat._twm._tokenize(response)
            if teach_tokens:
                self.chat._twm.boost_sequence(teach_tokens, domain, n_repeats=3)
        self.db.save(_PATTERN_FILE)
        self.chat.save_session()
        w = self.chat.alpha_mem.get_weight(pid)
        print(f"  [TEACH] Pattern stored: pid={pid[:8]}")
        print(f"  Trigger:  '{trigger[:70]}'")
        print(f"  Response: '{response[:100]}'")
        print(f"  Weight: {w:.3f}")

    def _cmd_lineage(self, arg=None):
        """Show generation tree from spawn_log.jsonl."""
        import json as _jlin
        from pathlib import Path as _Plin
        _log = _Plin(__file__).parent / 'spawn_log.jsonl'
        ROOTS = {
            'CDALS_v2': 0, 'CDALS_v3': 0, 'orchestrator': 0,
            'Os_Toolkit': 0, 'onboarder': 0, 'Filesync': 0,
            'py_manifest_augmented': 1,
        }
        graph = {n: {'generation': g, 'parent': None, 'tier': 'ancestor' if g==0 else 'generator'}
                 for n, g in ROOTS.items()}
        if _log.exists():
            for line in _log.read_text().splitlines():
                if not line.strip(): continue
                try:
                    r = _jlin.loads(line)
                except Exception: continue
                n = r.get('name', '')
                if not n: continue
                parent = r.get('parent') or 'py_manifest_augmented'
                pg = graph.get(parent, {}).get('generation', 1)
                ev = r.get('event', '')
                tier = 'omega' if 'omega' in ev else ('alpha' if 'alpha' in ev else 'fix')
                gen = pg + (0 if ev == 'fix_spawn' else 1)
                graph[n] = {'generation': gen, 'parent': parent, 'tier': tier,
                             'domain': r.get('domain'), 'ts': r.get('ts', '')}
        by_gen = {}
        for n, info in graph.items():
            g = info['generation']
            by_gen.setdefault(g, []).append((n, info))
        total = len(graph)
        print(f"  Lineage graph ({total} nodes):")
        for g in sorted(by_gen):
            for n, info in sorted(by_gen[g]):
                tier = info.get('tier', '?')
                dom = f" domain={info['domain']}" if info.get('domain') else ''
                par = f" ← {info['parent']}" if info.get('parent') else ''
                print(f"  [gen {g}] {n} ({tier}){dom}{par}")

    def _cmd_morph_compare(self, arg=None):
        """Compare last N morph archives for a domain."""
        import json as _jmc
        import math as _mmc
        from pathlib import Path as _Pmc
        parts = (arg or '').strip().split()
        domain = parts[0] if parts else 'general'
        n = int(parts[1]) if len(parts) > 1 and parts[1].isdigit() else 3
        _dir = _Pmc(__file__).parent
        files = sorted(_dir.glob(f"morph_archive_{domain}_*.json"))[-n:]
        if not files:
            print(f"  No morph archives for domain: {domain}")
            print(f"  Available: {[f.name for f in _dir.glob('morph_archive_*.json')][:5]}")
            return
        snaps = []
        for f in files:
            try:
                snaps.append(_jmc.loads(f.read_text()))
            except Exception:
                pass
        if not snaps:
            print("  Could not load archives.")
            return
        print(f"  morph-compare [{domain}] ({len(snaps)} snapshots):")
        prev = None
        for snap in snaps:
            ts = snap.get('ts', '?')[:16]
            pc = snap.get('pattern_count', 0)
            nc = snap.get('native_count', 0)
            gc = snap.get('gap_count', 0)
            cov = snap.get('measurement_coverage_pct', 0)
            gen = snap.get('generation', '?')
            print(f"    [{ts}] gen={gen} patterns={pc} native={nc} gaps={gc} cov={cov}%")
            if prev:
                d_pat = pc - prev.get('pattern_count', 0)
                d_nat = nc - prev.get('native_count', 0)
                d_cov = round(cov - prev.get('measurement_coverage_pct', 0), 1)
                print(f"      delta: patterns={d_pat:+d} native={d_nat:+d} cov={d_cov:+.1f}%")
            prev = snap

    def _cmd_parent_gaps(self, arg=None):
        """Show assessed gaps in parent scripts."""
        gap_map = self.build_data.get('parent_gap_map', {})
        if not gap_map:
            # Try scanning PARENT_GAP patterns from DB
            scripts = {}
            for pid, p_obj in self.db.patterns.items():
                p = p_obj.to_dict() if hasattr(p_obj, 'to_dict') else p_obj
                if 'PARENT_GAP' not in str(p.get('pattern_type', '')):
                    continue
                meta = p.get('metadata', {})
                sc = meta.get('script', '?')
                ga = meta.get('gap_utility', '?')
                scripts.setdefault(sc, []).append(ga)
            if not scripts:
                print("  No PARENT_GAP patterns found. Run spawn_omega to assess parent gaps.")
                return
            gap_map = {sc: {'missing': cmds} for sc, cmds in scripts.items()}
        print(f"  Parent gaps ({len(gap_map)} scripts assessed):")
        for script, assessment in sorted(gap_map.items()):
            if isinstance(assessment, dict):
                missing = assessment.get('missing', [])
                cov = assessment.get('coverage_pct', '?')
                avail = len(assessment.get('available', []))
            else:
                missing = []
                cov = '?'
                avail = '?'
            if missing:
                print(f"  {script}: {len(missing)} gaps (coverage {cov}%) — missing: {', '.join(missing[:6])}")
            else:
                print(f"  {script}: 0 gaps (coverage {cov}%, {avail} commands absorbed)")

    def _cmd_profile(self, arg=None):
        """Profile a parent script by functional weight tiers (T24)."""
        if not arg:
            print("  Usage: profile <script_name>  (e.g. 'profile Os_Toolkit')")
            return
        import sys as _sys_prof, ast as _ast_prof, pathlib as _pl_prof
        # Resolve script path
        script_name = arg.strip()
        candidates = []
        for abs_result in self.db.patterns.values():
            p = abs_result.to_dict() if hasattr(abs_result, 'to_dict') else abs_result
            if 'ARG_ABSORPTION' not in str(p.get('pattern_type', '')):
                continue
            meta = p.get('metadata', {})
            if script_name.lower() in meta.get('source_script', '').lower():
                sp = meta.get('script_path', '')
                if sp:
                    candidates.append(sp)
                    break
        if not candidates:
            # Search filesystem
            import subprocess as _sp_prof
            result = _sp_prof.run(['find', '/home/commander/Trainer', '-name', f'{script_name}.py',
                                   '-not', '-path', '*/variants/*'], capture_output=True, text=True)
            for ln in result.stdout.splitlines():
                if ln.strip():
                    candidates.append(ln.strip())
                    break
        if not candidates:
            print(f"  Script not found: {script_name}")
            return
        script_path = _pl_prof.Path(candidates[0])
        # Inline profiler (simplified — full FunctionalWeightProfiler available at py_manifest level)
        try:
            src = open(script_path, 'r', errors='ignore').read()
            tree = _ast_prof.parse(src)
        except Exception as e:
            print(f"  Cannot parse {script_path}: {e}")
            return
        tier_counts = {
            'init': 0, 'imports': 0, 'classes': 0, 'regex_domains': 0,
            'executables': 0, 'prop_attr': 0, 'values_weights': 0,
            'math_measure': 0, 'chain_policy': 0,
        }
        for node in _ast_prof.walk(tree):
            if isinstance(node, (_ast_prof.Import, _ast_prof.ImportFrom)):
                tier_counts['imports'] += 1
            elif isinstance(node, _ast_prof.ClassDef):
                tier_counts['classes'] += 1
            elif isinstance(node, _ast_prof.FunctionDef):
                if node.name == '__init__':
                    tier_counts['init'] += 1
                else:
                    tier_counts['executables'] += 1
            elif isinstance(node, _ast_prof.Call):
                fn = getattr(node.func, 'attr', '') or getattr(node.func, 'id', '')
                if fn in ('add_parser', 'add_subparsers', 'add_argument'):
                    tier_counts['chain_policy'] += 1
                if fn == 'compile':
                    tier_counts['regex_domains'] += 1
                parent_id = getattr(getattr(node.func, 'value', None), 'id', '')
                if parent_id in ('math', 'statistics', 'np', 'numpy'):
                    tier_counts['math_measure'] += 1
            elif isinstance(node, (_ast_prof.Num, _ast_prof.Constant)):
                v = getattr(node, 'n', getattr(node, 'value', None))
                if isinstance(v, (int, float)) and v != 0:
                    tier_counts['values_weights'] += 1
        tiers_order = ['init', 'imports', 'classes', 'regex_domains', 'executables',
                       'prop_attr', 'values_weights', 'math_measure', 'chain_policy']
        print(f"  Functional profile: {script_path.name}")
        best = max(tiers_order, key=lambda t: tier_counts[t] * (1 + tiers_order.index(t) * 0.15))
        for i, tier in enumerate(tiers_order):
            c = tier_counts[tier]
            score = round(c * (1.0 + i * 0.15), 1)
            print(f"    {tier:<18} count={c:<4} score={score}")
        print(f"  dominant_tier: {best}")

    def _cmd_mutant(self, arg=None):
        """Spawn a Mutant Omega blending py_manifest + one or two parent scripts (T25).
        Usage: mutant <parent> [<secondary_parent>] [blend_ratio]
        e.g. 'mutant Os_Toolkit py_manifest_augmented'
        Every subcommand from each parent becomes a --do-* CLI arg in the mutant."""
        if not arg:
            print("  Usage: mutant <parent> [<secondary_parent>] [blend_ratio]")
            print("  e.g.   mutant Os_Toolkit py_manifest_augmented")
            print("  Every add_parser subcommand → --do-<subcommand> flag in spawned mutant.")
            return
        parts = arg.strip().split()
        parent_name = parts[0]
        secondary_name = None
        blend_ratio = 0.5
        if len(parts) > 1:
            try:
                blend_ratio = float(parts[1])
            except ValueError:
                secondary_name = parts[1]
                if len(parts) > 2:
                    try:
                        blend_ratio = float(parts[2])
                    except ValueError:
                        pass
        blend_ratio = max(0.1, min(0.9, blend_ratio))
        import sys as _sys_mut, subprocess as _sp_mut, time as _time_mut, ast as _ast_mut
        from pathlib import Path as _Path_mut

        # Find parent script — exclude backup/cache dirs to avoid stale copies
        _FIND_PRUNE = ['-not', '-path', '*/variants/*',
                       '-not', '-path', '*/backup/*',
                       '-not', '-path', '*/session_b_saves/*',
                       '-not', '-path', '*/.git/*',
                       '-not', '-path', '*/node_modules/*',
                       '-not', '-path', '*/__pycache__/*']
        find_result = _sp_mut.run(
            ['find', '/home/commander/Trainer', '-name', f'{parent_name}.py'] + _FIND_PRUNE,
            capture_output=True, text=True)
        parent_path = None
        for ln in find_result.stdout.splitlines():
            if ln.strip():
                parent_path = ln.strip()
                break
        if not parent_path:
            # Also search /home/commander/Desktop
            find_result2 = _sp_mut.run(
                ['find', '/home/commander/Desktop', '-name', f'{parent_name}.py',
                 '-not', '-path', '*/backup/*'],
                capture_output=True, text=True)
            for ln in find_result2.stdout.splitlines():
                if ln.strip():
                    parent_path = ln.strip()
                    break
        if not parent_path:
            print(f"  Parent script not found: {parent_name}")
            return
        parent_path_obj = _Path_mut(parent_path)

        # Inline functional profile computation (simplified, no FunctionalWeightProfiler class dep)
        def _quick_profile(fpath):
            tier_counts = {
                'init': 0, 'imports': 0, 'classes': 0, 'regex_domains': 0,
                'executables': 0, 'prop_attr': 0, 'values_weights': 0,
                'math_measure': 0, 'chain_policy': 0,
            }
            chain_items = []
            exec_items = []
            class_items = []
            _help_ok = False
            # Stage 1: os.popen --help → parse {cmd1,cmd2,...} from usage line.
            # Uses shell pipeline to avoid capture_output stdout-redirect issues
            # (e.g. scripts that reassign sys.stdout at import time).
            try:
                import re as _re_qp, os as _os_qp, shlex as _shlex_qp
                _cmd_str = f'{_sys_mut.executable} {_shlex_qp.quote(str(fpath))} --help 2>&1'
                _popen = _os_qp.popen(_cmd_str)
                _help_txt = _popen.read()
                _popen.close()
                _help_txt = _re_qp.sub(r'\x1b\[[0-9;]*m', '', _help_txt)
                _brace_m = _re_qp.search(r'\{([^}]+)\}', _help_txt)
                if _brace_m:
                    _parsed = [c.strip() for c in _brace_m.group(1).split(',')
                               if c.strip() and not c.strip().startswith('-')]
                    if len(_parsed) > 1:
                        chain_items = _parsed
                        _help_ok = True
                if not _help_ok:
                    print(f"    (--help stage1 miss: txt={len(_help_txt)}b "
                          f"brace={'yes' if _brace_m else 'no'} "
                          f"content={repr(_help_txt[:120])})")
            except Exception as _e_help:
                print(f"    (--help failed: {_e_help})")
            # Stage 2: AST scan for tier counts.
            # Fallback subcommand extraction uses subparsers-variable tracking
            # so only top-level add_parser calls are captured (depth-accurate).
            try:
                src = open(fpath, 'r', errors='ignore').read()
                tree = _ast_mut.parse(src)
                # Pre-pass: find name of FIRST add_subparsers() assignment = top-level var
                _subparsers_var = None
                if not _help_ok:
                    for _np in _ast_mut.walk(tree):
                        if isinstance(_np, _ast_mut.Assign):
                            for _tp in _np.targets:
                                if (isinstance(_tp, _ast_mut.Name) and
                                    isinstance(_np.value, _ast_mut.Call) and
                                    getattr(_np.value.func, 'attr', '') == 'add_subparsers'):
                                    _subparsers_var = _tp.id
                                    break
                        if _subparsers_var:
                            break
                # Main walk: tier counts + depth-accurate fallback collection
                for node in _ast_mut.walk(tree):
                    if isinstance(node, (_ast_mut.Import, _ast_mut.ImportFrom)):
                        tier_counts['imports'] += 1
                    elif isinstance(node, _ast_mut.ClassDef):
                        tier_counts['classes'] += 1
                        class_items.append(node.name)
                    elif isinstance(node, _ast_mut.FunctionDef):
                        if node.name == '__init__':
                            tier_counts['init'] += 1
                        else:
                            tier_counts['executables'] += 1
                            exec_items.append(node.name)
                    elif isinstance(node, _ast_mut.Call):
                        fn = getattr(node.func, 'attr', '') or getattr(node.func, 'id', '')
                        if fn in ('add_parser', 'add_subparsers', 'add_argument'):
                            tier_counts['chain_policy'] += 1
                            # Fallback: only collect add_parser on the top-level subparsers var
                            if not _help_ok and fn == 'add_parser' and node.args:
                                _caller_id = getattr(
                                    getattr(node.func, 'value', None), 'id', '')
                                if _subparsers_var is None or _caller_id == _subparsers_var:
                                    a0 = node.args[0]
                                    v = getattr(a0, 's', getattr(a0, 'value', None))
                                    if isinstance(v, str) and v and not v.startswith('-'):
                                        chain_items.append(v)
                        if fn == 'compile':
                            tier_counts['regex_domains'] += 1
                        pid = getattr(getattr(node.func, 'value', None), 'id', '')
                        if pid in ('math', 'statistics', 'np', 'numpy'):
                            tier_counts['math_measure'] += 1
                    elif isinstance(node, (_ast_mut.Num, _ast_mut.Constant)):
                        v = getattr(node, 'n', getattr(node, 'value', None))
                        if isinstance(v, (int, float)) and v not in (0, 1):
                            tier_counts['values_weights'] += 1
            except Exception:
                pass
            tiers_order = ['init', 'imports', 'classes', 'regex_domains', 'executables',
                           'prop_attr', 'values_weights', 'math_measure', 'chain_policy']
            total_nodes = sum(tier_counts.values())
            chain_density = tier_counts['chain_policy'] / max(1, total_nodes)
            best = max(tiers_order, key=lambda t: tier_counts[t] * (1 + tiers_order.index(t) * 0.15))
            return {
                'tier_counts': tier_counts,
                'chain_items': list(dict.fromkeys(chain_items)),  # T25: all subcommands, no cap
                'exec_items': exec_items[:30],
                'class_items': class_items[:20],
                'chain_policy_density': round(chain_density, 4),
                'dominant_tier': best,
                'total_nodes': total_nodes,
            }

        print(f"  Profiling {parent_name} (--help + AST)...")
        prof = _quick_profile(parent_path_obj)
        chain_density = prof['chain_policy_density']
        dominant_tier = prof['dominant_tier']
        print(f"  Primary: {len(prof['chain_items'])} subcommands: {', '.join(prof['chain_items'][:8])}"
              f"{'...' if len(prof['chain_items']) > 8 else ''}")

        # T25 Core: Profile secondary parent if provided
        sec_prof = None
        if secondary_name:
            _sec_find = _sp_mut.run(
                ['find', '/home/commander/Trainer', '-name', f'{secondary_name}.py']
                + _FIND_PRUNE,
                capture_output=True, text=True)
            _sec_path = None
            for _ln in _sec_find.stdout.splitlines():
                if _ln.strip():
                    _sec_path = _ln.strip()
                    break
            if not _sec_path:
                _sec_find2 = _sp_mut.run(
                    ['find', '/home/commander/Desktop', '-name', f'{secondary_name}.py',
                     '-not', '-path', '*/backup/*'],
                    capture_output=True, text=True)
                for _ln in _sec_find2.stdout.splitlines():
                    if _ln.strip():
                        _sec_path = _ln.strip()
                        break
            if _sec_path:
                print(f"  Profiling secondary: {secondary_name}...")
                sec_prof = _quick_profile(_Path_mut(_sec_path))
                print(f"  Secondary: {len(sec_prof['chain_items'])} subcommands: "
                      f"{', '.join(sec_prof['chain_items'][:8])}"
                      f"{'...' if len(sec_prof['chain_items']) > 8 else ''}")
            else:
                print(f"  Secondary parent not found: {secondary_name} (skipping)")

        # Compute predisposed ratio
        predisposition = (chain_density - 0.5) * 0.30
        predisposed_ratio = max(0.30, min(0.75, blend_ratio + predisposition))

        # Dominant domain from tier map
        TIER_DOMAIN = {
            'chain_policy': 'planning', 'executables': 'analysis', 'classes': 'data',
            'regex_domains': 'semantic_systems', 'math_measure': 'neural_network',
            'values_weights': 'training', 'imports': 'general', 'init': 'general',
        }
        SUB_UTILS = {
            'chain_policy': ['route', 'dispatch', 'intent-resolve', 'subcommand-expand'],
            'executables': ['func-trace', 'call-chain', 'signature-match'],
            'classes': ['taxonomy', 'inheritance', 'dataclass-expand'],
            'regex_domains': ['pattern-extract', 'domain-classify', 'semantic-label'],
            'math_measure': ['gradient-trace', 'loss-surface', 'weight-delta'],
            'values_weights': ['weight-tune', 'matrix-op', 'quantize'],
        }
        dominant_domain = TIER_DOMAIN.get(dominant_tier, 'general')
        sub_utilities = SUB_UTILS.get(dominant_tier, [])

        print(f"  dominant_tier: {dominant_tier} → domain: {dominant_domain}")
        print(f"  chain_policy_density: {chain_density:.3f}  "
              f"base_ratio: {blend_ratio:.2f}  →  predisposed_ratio: {predisposed_ratio:.2f}")
        print(f"  chain_policy items: {', '.join(prof['chain_items'][:8]) or '(none)'}")
        print(f"  executables: {len(prof['exec_items'])} | classes: {len(prof['class_items'])}")
        print(f"  sub_utility potentials: {', '.join(sub_utilities[:4])}")

        # Store permutation seeds into omega's DB before spawn
        seeds_stored = 0
        try:
            import hashlib as _hl_seed
            import json as _json_seed
            # Load current pattern DB
            db_path = _Path_mut(__file__).parent / 'patterns.json'
            if not db_path.exists():
                db_path = _Path_mut(__file__).parent / 'pymanifest_patterns.json'
            if db_path.exists():
                with open(db_path) as f:
                    db_data = _json_seed.load(f)
                def _mk_pat(tier, item, ptype, outcome):
                    ctx = _hl_seed.sha256(f"{parent_name}:{tier}".encode()).hexdigest()[:8]
                    cont = _hl_seed.sha256(item.encode()).hexdigest()[:8]
                    pid = ctx + cont
                    if pid not in db_data:
                        db_data[pid] = {
                            'pattern_id': pid, 'pattern_type': ptype,
                            'context_hash': ctx, 'content_hash': cont,
                            'outcome': outcome, 'occurrence_count': 1,
                            'first_seen': _time_mut.strftime('%Y-%m-%dT%H:%M:%S'),
                            'last_seen': _time_mut.strftime('%Y-%m-%dT%H:%M:%S'),
                            'metadata': {
                                'name': item, 'verb': item, 'function': item,
                                'parent_script': parent_name, 'domain': dominant_domain,
                                'action_eligible': tier != 'sub_utility',
                                'source': 'mutant_seed', 'tier': tier,
                                'sub_utilities': sub_utilities[:3],
                            }
                        }
                        return True
                    return False
                for item in prof['chain_items']:
                    if _mk_pat('chain_policy', item, 'PatternType.VERB_FUNCTION_MAP', 'action_seed'):
                        seeds_stored += 1
                for item in [i for i in prof['exec_items'] if not i.startswith('_')][:10]:
                    if _mk_pat('executable', item, 'PatternType.SCRIPT_INGEST', 'function_seed'):
                        seeds_stored += 1
                for item in prof['class_items']:
                    if _mk_pat('class', item, 'PatternType.SCRIPT_INGEST', 'class_seed'):
                        seeds_stored += 1
                for su in sub_utilities:
                    if _mk_pat('sub_utility', su, 'PatternType.VERB_FUNCTION_MAP', 'sub_utility_potential'):
                        seeds_stored += 1
                with open(db_path, 'w') as f:
                    _json_seed.dump(db_data, f)
                print(f"  Permutation seeds stored: {seeds_stored} patterns → {db_path.name}")
        except Exception as _e_seed:
            print(f"  (seed storage skipped: {_e_seed})")

        # T25 Core: Write _mutant_bias.json — subcommands become --do-* args in spawned mutant
        try:
            import json as _json_bias_w
            _bias_out = {
                'parent_name': parent_name,
                'secondary_name': secondary_name or '',
                'parent_subcommands': prof['chain_items'],
                'secondary_subcommands': (sec_prof['chain_items'] if sec_prof else []),
                'morph_regex_index': {
                    'chain_policy': prof['chain_items'],
                    'executables': prof['exec_items'],
                    'classes': prof['class_items'],
                },
            }
            _bias_write_path = _Path_mut(__file__).parent / '_mutant_bias.json'
            _bias_write_path.write_text(_json_bias_w.dumps(_bias_out, indent=2))
            _total_subcmds = len(_bias_out['parent_subcommands']) + len(_bias_out['secondary_subcommands'])
            print(f"  Bias: {len(_bias_out['parent_subcommands'])} primary + "
                  f"{len(_bias_out['secondary_subcommands'])} secondary = "
                  f"{_total_subcmds} total --do-* args → _mutant_bias.json")
        except Exception as _be_w:
            print(f"  (bias write skipped: {_be_w})")

        # Now spawn
        ts = _time_mut.strftime('%Y%m%d_%H%M%S')
        mutant_name = f"mutant_omega_{parent_name.lower()[:8]}{'_pm' if secondary_name else ''}_{ts}"
        py_manifest = _Path_mut(__file__).parent / 'py_manifest_augmented.py'
        if not py_manifest.exists():
            for p in _Path_mut(__file__).parents:
                candidate = p / 'py_manifest_augmented.py'
                if candidate.exists():
                    py_manifest = candidate
                    break
        cmd = [_sys_mut.executable, str(py_manifest), 'variant', '--omega', '--name', mutant_name]
        print(f"  Spawning {mutant_name}...")
        try:
            proc = _sp_mut.run(cmd, capture_output=True, text=True, timeout=300)
            # Extract spawned path
            for ln in proc.stdout.splitlines():
                if 'omega' in ln.lower() and ln.strip().endswith('.py'):
                    print(f"  Spawned: {ln.strip()}")
                    break
            if proc.returncode != 0:
                print(f"  Error: {proc.stderr[-200:]}")
            else:
                sec_info = f" + {secondary_name}" if secondary_name else ""
                print(f"  Done. Parents: {parent_name}{sec_info}  "
                      f"ratio: {predisposed_ratio:.2f} (base {blend_ratio:.2f})")
        except Exception as e:
            print(f"  spawn failed: {e}")

    def _cmd_backtest(self, arg=None):
        """Back-test omega variants for design capabilities (T24).
        Usage: backtest [all | <omega_name>]"""
        from pathlib import Path as _Path_bt
        variants_dir = _Path_bt(__file__).parent / 'variants'
        if not variants_dir.exists():
            # Try finding variants dir relative to omega location
            for p in _Path_bt(__file__).parents:
                candidate = p / 'Data' / 'pymanifest' / 'variants'
                if candidate.exists():
                    variants_dir = candidate
                    break
        arg_str = (arg or 'all').strip().lower()
        CAPS = [
            ('can_spawn_alpha',        '_cmd_spawn_alpha'),
            ('can_token_generate',     'TokenWeightMatrix'),
            ('has_parent_state',       'parent-state'),
            ('has_native_funcs',       'NATIVE_FUNCTION'),
            ('has_measurement_domain', 'semantic_systems'),
            ('has_thought_chains',     'THOUGHT_CHAIN'),
            ('has_lineage',            'lineage_path'),
            ('can_backtest',           'backtest'),
            ('has_scratch_pad',        'MorphScratchPad'),
            ('has_attribution',        'DomainAttributionMatrix'),
            ('has_morph_catalog',      'MorphCatalogEngine'),
        ]
        GAP_MAP = {
            'can_spawn_alpha':        'spawn template not included',
            'can_token_generate':     'TokenWeightMatrix template missing',
            'has_parent_state':       'parent-state cmd not wired (T23)',
            'has_native_funcs':       'NATIVE_FUNCTION patterns absent',
            'has_measurement_domain': 'T24 domains missing from source',
            'has_thought_chains':     'THOUGHT_CHAIN not wired (T24)',
            'has_lineage':            'LineageGraph not called (T23)',
            'can_backtest':           'backtest cmd not added (T24)',
            'has_scratch_pad':        'MorphScratchPad not added (T25)',
            'has_attribution':        'DomainAttributionMatrix not added (T25)',
            'has_morph_catalog':      'MorphCatalogEngine not added (T26)',
        }
        def _test_file(omf):
            try:
                src = open(omf, 'r', errors='ignore').read()
            except Exception:
                return None
            passed, failed = [], []
            for cid, needle in CAPS:
                if needle in src:
                    passed.append(cid)
                else:
                    failed.append(cid)
            return {'name': omf.name, 'passed': passed, 'failed': failed,
                    'score': f"{len(passed)}/{len(CAPS)}"}
        if arg_str == 'all':
            targets = sorted(variants_dir.glob('omega_*.py')) if variants_dir.exists() else []
            if not targets:
                print("  No omega variants found in variants/")
                return
            print(f"  Back-testing {len(targets)} omega variants...")
            for omf in targets:
                r = _test_file(omf)
                if r is None:
                    continue
                status = 'PASS' if not r['failed'] else f"WARN"
                print(f"  {r['name']}: {r['score']} {status}")
                for f in r['failed']:
                    print(f"    ✗ {f}: {GAP_MAP.get(f,'')}")
        else:
            matches = list(variants_dir.glob(f"*{arg_str}*.py")) if variants_dir.exists() else []
            if not matches:
                print(f"  No omega file matching '{arg_str}'")
                return
            r = _test_file(matches[0])
            if r:
                print(f"  {r['name']}: {r['score']}")
                for f in r['failed']:
                    print(f"    ✗ {f}: {GAP_MAP.get(f,'')}")

    def _cmd_scratch(self, arg=None):
        """Scratch pad surface display and management (T25).
        Usage: scratch [<domain>] | scratch commit [<domain>] | scratch pollinate <src> <dst> | scratch tick"""
        import hashlib as _h_sc
        from pathlib import Path as _P_sc
        _pad_p = _P_sc(__file__).parent / 'scratch_pad.json'
        try:
            surface = json.loads(_pad_p.read_text()) if _pad_p.exists() else {}
        except Exception:
            surface = {}
        parts = (arg or '').strip().split()
        sub = parts[0].lower() if parts else ''
        if sub == 'commit':
            dom_filter = parts[1] if len(parts) > 1 else None
            promoted = 0
            for dom, cands in surface.items():
                if dom_filter and dom != dom_filter:
                    continue
                keep = []
                for c in cands:
                    if c.get('weight', 0) >= 0.60:
                        pid = c['id']
                        p = Pattern(pattern_id=pid, pattern_type=PatternType.SCRATCH_CANDIDATE,
                                    context_hash=pid[:8], content_hash=pid[4:12], outcome='promoted',
                                    metadata={'domain': dom, 'ctype': c.get('type',''),
                                              'content': c.get('content',''), 'origin': c.get('origin',''),
                                              'weight': c.get('weight', 0)})
                        self.db.add_or_update(p)
                        promoted += 1
                    else:
                        keep.append(c)
                surface[dom] = keep
            try:
                _pad_p.write_text(json.dumps(surface, indent=2))
            except Exception:
                pass
            self.db.save(_PATTERN_FILE)
            print(f"  Scratch commit: {promoted} candidates promoted to SCRATCH_CANDIDATE")
        elif sub == 'pollinate':
            src_d = parts[1] if len(parts) > 1 else ''
            dst_d = parts[2] if len(parts) > 2 else ''
            if not src_d or not dst_d:
                print("  Usage: scratch pollinate <source_domain> <target_domain>"); return
            src_cands = sorted(surface.get(src_d, []), key=lambda x: x.get('weight', 0), reverse=True)[:5]
            count = 0
            for c in src_cands:
                if c.get('weight', 0) < 0.65:
                    continue
                cid = _h_sc.sha256(f"{dst_d}:{c.get('type','')}:{c.get('content','')}".encode()).hexdigest()[:12]
                dst_list = surface.setdefault(dst_d, [])
                if not any(x['id'] == cid for x in dst_list):
                    dst_list.append({'id': cid, 'type': c.get('type',''), 'content': c.get('content',''),
                                     'origin': f"pollinate:{src_d}", 'weight': c.get('weight',0)*0.7,
                                     'ttl': 5, 'ts': '', 'meta': {}})
                    count += 1
            try:
                _pad_p.write_text(json.dumps(surface, indent=2))
            except Exception:
                pass
            print(f"  Pollinated {count} candidates from {src_d} → {dst_d}")
        elif sub == 'tick':
            for dom in list(surface.keys()):
                remaining = []
                for c in surface[dom]:
                    if c.get('ttl', 0) > 0:
                        c['ttl'] -= 1
                    else:
                        c['weight'] = c.get('weight', 0.5) * 0.80
                    if c.get('weight', 0) >= 0.05:
                        remaining.append(c)
                surface[dom] = remaining
            try:
                _pad_p.write_text(json.dumps(surface, indent=2))
            except Exception:
                pass
            print("  Decay tick applied")
        elif sub == 'reindex':
            self._cmd_morph_reindex(None)
        else:
            dom_filter = sub or None
            if not surface:
                print("  (scratch pad empty)"); return
            doms = [dom_filter] if dom_filter and dom_filter in surface else list(surface.keys())
            for dom in doms:
                cands = sorted(surface.get(dom, []), key=lambda x: x.get('weight', 0), reverse=True)
                if not cands:
                    continue
                print(f"\\n  [{dom}] ({len(cands)} candidates)")
                for c in cands[:10]:
                    w = c.get('weight', 0)
                    bar = int(w * 10)
                    print(f"    {'█'*bar}{'░'*(10-bar)} {w:.2f} | "
                          f"{c.get('type','')[:12]:<12} | {c.get('content','')[:35]:<35} | "
                          f"ttl={c.get('ttl',0)} | {c.get('origin','')}")

    def _cmd_attribute(self, arg=None):
        """Domain attribution scoring for a token (T25).
        Usage: attribute <token>"""
        token = (arg or '').strip()
        if not token:
            print("  Usage: attribute <token>"); return
        _dkw_at = {
            'semantic_systems': ['semantic','embedding','vector','similarity','nlp','token','classify'],
            'neural_network':   ['neural','weight','gradient','layer','activation','loss'],
            'ml_pipeline':      ['train','evaluate','score','epoch','batch','dataset','fit','predict'],
            'general':          ['python','function','class','method','import','module'],
            'ancestor':         ['chain','cdals','cdal','orchestrat','lineage'],
        }
        t = token.lower()
        print(f"  Attribution for '{token}':")
        any_match = False
        for dom, kws in sorted(_dkw_at.items()):
            matches = sum(1 for kw in kws if kw in t or t in kw)
            sc = round(matches / max(1, len(kws)), 3)
            if sc > 0:
                bar = int(sc * 10)
                print(f"    {dom:<20} {'█'*bar}{'░'*(10-bar)} {sc:.3f}")
                any_match = True
        if not any_match:
            print(f"    (no domain matches for '{token}' — may be novel content)")

    def _cmd_morph_index(self, arg=None):
        """Show morphological domain pattern regex index from build data (T25).
        Usage: morph-index"""
        rx = self.build_data.get('morph_regex_index', {})
        if not rx:
            print("  (no morph_regex_index in build data — spawn new omega to populate)"); return
        print("  Morphological domain pattern index:")
        for dom in sorted(rx.keys()):
            entries = rx[dom]
            print(f"    [{dom}] ({len(entries)}): {', '.join(str(e) for e in entries[:12])}")

    def _cmd_morph_reindex(self, arg=None):
        """Re-attribute existing patterns with domain scores (T25).
        Connects prior content (dictionary, idioms) to measurement domains.
        Usage: morph-reindex [<pattern_type>]"""
        _dkw_ri = {
            'semantic_systems': ['semantic','embedding','vector','similarity','nlp','token','classify'],
            'neural_network':   ['neural','weight','gradient','layer','activation','loss'],
            'ml_pipeline':      ['train','evaluate','score','epoch','batch','dataset','fit','predict'],
            'general':          ['python','function','class','method','import','module'],
            'ancestor':         ['chain','cdals','cdal','orchestrat','lineage'],
        }
        type_filter = (arg or '').strip().upper() or None
        _reindex_types = {type_filter} if type_filter else {
            'DICTIONARY_TERM', 'PYTHON_IDIOM', 'SPEECH_PATTERN',
            'DOMAIN_PATTERN', 'KNOWLEDGE_ENTRY', 'DOMAIN_POLICY'
        }
        updated = 0
        dom_changes = {}
        for pid, p in list(self.db.patterns.items()):
            ptype = p.pattern_type.name if hasattr(p.pattern_type, 'name') else str(p.pattern_type)
            if ptype.split('.')[-1] not in _reindex_types:
                continue
            tokens = []
            for k in ('name', 'verb', 'content', 'subcommand', 'description', 'term', 'definition'):
                v = p.metadata.get(k, '')
                if v:
                    tokens.extend(str(v).lower().split())
            if not tokens:
                continue
            agg = {}
            for t in tokens[:50]:
                for dom, kws in _dkw_ri.items():
                    matches = sum(1 for kw in kws if kw in t or t in kw)
                    agg[dom] = agg.get(dom, 0.0) + matches / max(1, len(kws))
            total = max(1, len(tokens))
            av = {d: round(v / total, 4) for d, v in agg.items()}
            p.metadata['domain_scores'] = av
            top_dom = max(av, key=av.get) if av else ''
            top_score = av.get(top_dom, 0)
            current_dom = p.metadata.get('domain', '')
            if (not current_dom or current_dom == 'general') and top_score >= 0.15:
                p.metadata['domain'] = top_dom
                dom_changes[top_dom] = dom_changes.get(top_dom, 0) + 1
            self.db.add_or_update(p)
            updated += 1
        self.db.save(_PATTERN_FILE)
        print(f"  Morph reindex: {updated} patterns re-attributed")
        print(f"  Types: {', '.join(sorted(_reindex_types))}")
        if dom_changes:
            print("  Domain promotions:")
            for dom, cnt in sorted(dom_changes.items(), key=lambda x: x[1], reverse=True):
                print(f"    {dom:<20}: +{cnt}")

    def _cmd_catalog(self, arg=None):
        """T26: Query morphological catalog. Usage: catalog [<token>|domain <domain>]"""
        import json as _j_cat
        _cat_p = Path(__file__).parent.parent / 'pattern_master' / 'Morph_Training' / 'morphological_catalog.json'
        if not _cat_p.exists():
            print("  Catalog not found. Run: python3 pattern_master/train/morph_catalog_builder.py")
            return
        try:
            _cat_d = _j_cat.loads(_cat_p.read_text(encoding='utf-8'))
        except Exception as _e_cat:
            print(f"  Catalog load error: {_e_cat}")
            return
        _arg = (arg or '').strip()
        if not _arg:
            # Show meta
            meta = _cat_d.get('meta', {})
            print(f"  Morphological Catalog")
            print(f"    tokens:        {meta.get('token_count', 0):,}")
            print(f"    novel tokens:  {meta.get('novel_token_count', 0):,}")
            print(f"    domains:       {', '.join(meta.get('domains', []))}")
            print(f"    sources:       {', '.join(meta.get('sources_used', []))}")
            print(f"    built_at:      {str(meta.get('built_at', '?'))[:19]}")
            print(f"    bigrams:       {len(_cat_d.get('bigrams', {})):,}")
        elif _arg.startswith('domain '):
            dom = _arg[7:].strip()
            dc = _cat_d.get('domain_catalogs', {}).get(dom, [])
            if not dc:
                print(f"  No domain catalog for '{dom}'")
            else:
                print(f"  [{dom}] top {min(20, len(dc))} tokens:")
                for tok in dc[:20]:
                    e = _cat_d['tokens'].get(tok, {})
                    sc = e.get('domain_scores', {}).get(dom, 0)
                    print(f"    {tok:<22} {sc:.4f}")
        else:
            tok = _arg.lower()
            e = _cat_d.get('tokens', {}).get(tok, {})
            if not e:
                print(f"  '{tok}': not in catalog")
                return
            mc = e.get('morph_class', '?')
            td = e.get('top_domain', '?')
            fr = e.get('frequency', 0)
            nv = e.get('novel', True)
            print(f"  '{tok}' [{mc}] top={td} freq={fr} novel={nv}")
            ds = e.get('domain_scores', {})
            _BLK = chr(0x2588); _SHD = chr(0x2591)
            for dom, sc in sorted(ds.items(), key=lambda x: x[1], reverse=True):
                if sc > 0.001:
                    bar = int(sc * 50)
                    print(f"    {dom:<22} {_BLK*bar}{_SHD*(10-bar)} {sc:.4f}")
            cn = e.get('cooccur_next', {})
            if cn:
                print(f"    follows -> {list(cn.keys())[:5]}")
            cp = e.get('cooccur_prev', {})
            if cp:
                print(f"    precedes <- {list(cp.keys())[:5]}")
            pt = e.get('pattern_types', [])
            if pt:
                print(f"    pattern_types: {', '.join(pt)}")
            st = e.get('stems', [])
            if st:
                print(f"    stems: {', '.join(st)}")

    def _cmd_morph_train(self, arg=None):
        """T26: Omega self-training via alpha interaction.
        Usage: morph-train [domain] [turns=5]
        Spawns specialist alpha, sends domain prompts, grades responses inline,
        populates scratch pad with domain-attributed tokens."""
        import subprocess as _sp_mt, json as _j_mt, re as _re_mt
        _parts = (arg or '').strip().split()
        _domain = _parts[0] if _parts else 'general'
        _turns = int(_parts[1]) if len(_parts) > 1 and _parts[1].isdigit() else 5
        # Load catalog for inline grading
        _cat_p = Path(__file__).parent.parent / 'pattern_master' / 'Morph_Training' / 'morphological_catalog.json'
        _cat_tokens = {}
        if _cat_p.exists():
            try:
                _cat_tokens = _j_mt.loads(_cat_p.read_text(encoding='utf-8')).get('tokens', {})
            except Exception:
                pass
        # Find latest specialist alpha for domain
        _var_dir = Path(__file__).parent
        _alpha_files = sorted(_var_dir.glob(f'specialist_{_domain}_*.py'))
        if not _alpha_files:
            print(f"  No specialist alpha found for domain '{_domain}'")
            print(f"  Run: spawn-alpha {_domain}")
            return
        _alpha = _alpha_files[-1]
        print(f"  Training with: {_alpha.name} | domain={_domain} | turns={_turns}")
        # Build prompts from catalog domain tokens or fallback keywords
        _dom_tokens = [t for t, e in _cat_tokens.items()
                       if e.get('top_domain') == _domain and e.get('frequency', 0) > 2][:20]
        _FALLBACK_KW = {
            'neural_network': ['gradient', 'weight', 'activation', 'layer', 'backprop'],
            'semantic_systems': ['embedding', 'similarity', 'token', 'vector', 'domain'],
            'ml_pipeline': ['training', 'evaluation', 'dataset', 'epoch', 'accuracy'],
            'general': ['function', 'method', 'class', 'module', 'return'],
        }
        _prompt_pool = _dom_tokens or _FALLBACK_KW.get(_domain, [_domain])
        _prompts = [f"What is the role of {_prompt_pool[i % len(_prompt_pool)]} in {_domain}?"
                    for i in range(_turns)]
        # Run alpha with piped prompts
        _input_text = '\\n'.join(_prompts) + '\\nquit\\n'
        try:
            _result = _sp_mt.run(['python3', str(_alpha)], input=_input_text,
                                  capture_output=True, text=True, timeout=90)
        except Exception as _e_run:
            print(f"  Alpha run failed: {_e_run}")
            return
        # Parse responses: split by alpha prompt 'alpha[domain]> '
        _raw_out = _result.stdout
        _sections = _re_mt.split(r'\\nalpha\\[[^\\]]*\\]>\\s*', _raw_out)
        _responses = [s.strip() for s in _sections[1:_turns + 1] if s.strip()]
        # Inline grade + scratch pad update
        _GRADE_W = {'A': 1.0, 'B': 0.8, 'C': 0.6, 'D': 0.3, 'F': 0.1}
        _pad_path = _var_dir / 'scratch_pad.json'
        try:
            _pad = _j_mt.loads(_pad_path.read_text()) if _pad_path.exists() else {}
        except Exception:
            _pad = {}
        _total_added = 0
        _grade_hist = []
        for i, resp in enumerate(_responses[:_turns]):
            prompt = _prompts[i] if i < len(_prompts) else ''
            # Tokenize response
            _resp_toks = [t.lower() for t in _re_mt.findall(r'[a-zA-Z]{3,}', resp)][:30]
            # Inline grade: avg domain score of response tokens
            _dom_scores = []
            for t in _resp_toks:
                e = _cat_tokens.get(t, {})
                ds = e.get('domain_scores', {})
                if ds:
                    _dom_scores.append(ds.get(_domain, 0))
            avg_sc = sum(_dom_scores) / max(1, len(_dom_scores)) if _dom_scores else 0.0
            if avg_sc >= 0.15:   grade = 'A'
            elif avg_sc >= 0.10: grade = 'B'
            elif avg_sc >= 0.07: grade = 'C'
            elif avg_sc >= 0.04: grade = 'D'
            else:                grade = 'F'
            _grade_hist.append(grade)
            _w = _GRADE_W.get(grade, 0.3)
            # Add tokens to scratch pad
            _dom_list = _pad.setdefault(_domain, [])
            _existing_ids = {c['id'] for c in _dom_list}
            import hashlib as _h_mt
            added = 0
            for tok in _resp_toks:
                if len(tok) <= 3: continue
                cid = _h_mt.sha256(f"{_domain}:measurement:{tok}".encode()).hexdigest()[:12]
                if cid not in _existing_ids:
                    _dom_list.append({'id': cid, 'type': 'measurement', 'content': tok,
                                      'origin': f'morph_train_{grade}', 'weight': _w,
                                      'ttl': 5, 'meta': {'grade': grade, 'avg_domain_score': round(avg_sc, 4)}})
                    _existing_ids.add(cid)
                    added += 1
            # Cap domain list
            if len(_dom_list) > 200:
                _dom_list.sort(key=lambda x: x['weight'], reverse=True)
                _pad[_domain] = _dom_list[:200]
            _total_added += added
            _resp_preview = resp[:60].replace('\\n', ' ')
            print(f"  Turn {i+1}: grade={grade} ({avg_sc:.3f}) added={added} | {_resp_preview}...")
        # Save scratch pad
        try:
            _pad_path.write_text(_j_mt.dumps(_pad, indent=2))
        except Exception as _e_save:
            print(f"  Scratch pad save error: {_e_save}")
        # Summary
        from collections import Counter as _C_mt
        _gc = _C_mt(_grade_hist)
        _avg_g = sorted(_grade_hist)[len(_grade_hist)//2] if _grade_hist else '?'
        print(f"  Training complete: {len(_responses)} turns | median_grade={_avg_g} | "
              f"grades={dict(_gc)} | candidates_added={_total_added}")
        print(f"  Run 'scratch' to inspect | 'scratch commit' to promote to DB")

    def _cmd_profiles(self, arg=None):
        """T31: List available spawn profiles, or show details for one."""
        print(SpawnProfile.list_profiles())
        if arg and arg.strip():
            name = arg.strip().lower()
            cfg = SpawnProfile.PROFILES.get(name)
            if cfg:
                print(f"\\n  Profile '{name}' details:")
                wl = cfg.get('pattern_whitelist')
                print(f"    whitelist: {wl if wl else 'all pattern types'}")
                print(f"    domain_speech_only: {cfg.get('domain_speech_only', False)}")
                print(f"    compartment_default: {cfg.get('compartment_default') or 'auto-detect'}")
                print(f"    speech_score_floor: {cfg.get('speech_score_floor', 0.90)}")
                print(f"    dict_score_cap: {cfg.get('dict_score_cap', 1.0)}")
                print(f"    twm_sources: {cfg.get('twm_sources') or 'all'}")
                print(f"    mutation_targets: {cfg.get('mutation_targets', [])}")
            else:
                print(f"  Unknown profile: '{name}'. Try: language, thinking, action, code, hybrid")

    def _cmd_correction(self, arg):
        """Run bi-hemispheric collapse loop.

        Format: correction input:<text> | expected_output:<text>
        Optional: | max_seconds:<N> | max_rounds:<N>
        """
        if not arg or 'input:' not in arg or 'expected_output:' not in arg:
            print("  Usage: correction input:<text> | expected_output:<text>")
            print("  Optional: | max_seconds:300 | max_rounds:50")
            print("  Example: correction input:What is entropy? | expected_output:Entropy is a measure of disorder")
            return

        parts = [p.strip() for p in arg.split('|')]
        input_text = expected_output = None
        max_seconds = 300
        max_rounds = 50

        for part in parts:
            if part.startswith('input:'):
                input_text = part[6:].strip()
            elif part.startswith('expected_output:'):
                expected_output = part[16:].strip()
            elif part.startswith('max_seconds:'):
                try:
                    max_seconds = int(part[12:].strip())
                except ValueError:
                    pass
            elif part.startswith('max_rounds:'):
                try:
                    max_rounds = int(part[11:].strip())
                except ValueError:
                    pass

        if not input_text or not expected_output:
            print("  Error: both input:<text> and expected_output:<text> required")
            return

        # Load morph array state
        _array_state_path = Path(__file__).parent / 'variants' / 'morph_array_state.json'
        _array_state = {}
        if _array_state_path.exists():
            try:
                _array_state = json.loads(_array_state_path.read_text())
            except Exception:
                pass

        # Initialize scratch pad if not already loaded
        if not hasattr(self, '_scratch_pad') or self._scratch_pad is None:
            self._scratch_pad = MorphScratchPad(Path(__file__).parent / 'variants')

        engine = BiHemisphericEngine(
            db=self.db,
            scratchpad=self._scratch_pad,
            thought_matrix=ThoughtMatrixStore(self.db),
            morph_array_state=_array_state
        )

        result = engine.run_collapse_loop(
            input_text, expected_output,
            max_seconds=max_seconds,
            max_rounds=max_rounds,
            chat_instance=getattr(self, 'chat', None)
        )

        self._print_collapse_report(result)

        # Save DB after collapse
        self.db.save(_PATTERN_FILE)

    def _print_collapse_report(self, result):
        """Display collapse loop results."""
        print(f"\\n  ══ COLLAPSE REPORT ══")
        print(f"  Status     : {'★ COLLAPSED' if result.get('collapsed') else '⏱ TIMEOUT'}")
        print(f"  Rounds     : {result.get('rounds_run', 0)}")
        print(f"  Time       : {result.get('total_time_s', 0):.1f}s")
        print(f"  Patterns   : {result.get('total_patterns_created', 0)} created")
        be = result.get('best_ever', {{}})
        print(f"  Best       : [{be.get('grade', '?')}] {be.get('domain', '?')}")
        print(f"    Factual  : {be.get('factual_accuracy', 0):.2%}")
        print(f"    Semantic : {be.get('semantic_accuracy', 0):.2%}")
        print(f"    Overall  : {be.get('overall_score', 0):.2%}")
        ac = result.get('audit_chain', {{}})
        print(f"  Audit chain:")
        print(f"    GGUF SHA : {ac.get('gguf_sha', '?')}")
        print(f"    Target   : {result.get('target_sha', '?')}")
        print(f"    DB size  : {ac.get('pattern_db_size', 0):,} patterns")
        print(f"    Domains  : {', '.join(ac.get('scratchpad_domains', []))}")
        _rpath = Path(__file__).parent / 'variants' / 'collapse_report.json'
        print(f"  Report     : {_rpath}")
        print()

